'use client';
import { useState, useEffect } from 'react';
import api from '../../../services/api';
import Link from 'next/link';
import { ArrowLeft, Plus, User, Edit, Save, X } from 'lucide-react';
import AddAgentModal from '../../../components/admin/AddAgentModal';
import AgentBalanceModal from '../../../components/admin/AgentBalanceModal';
import toast from 'react-hot-toast';

export default function AgentsPage() {
    const [agents, setAgents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);

    // Imports removed from body
    // State removed from here

    // Edit Mode
    const [editingAgent, setEditingAgent] = useState(null);
    const [editCommission, setEditCommission] = useState('');

    const fetchAgents = async () => {
        try {
            const res = await api.get('/admin/agents');
            setAgents(res.data);
            setLoading(false);
            setAgents(res.data);
            setLoading(false);
        } catch (err) {
            if (err.response?.status !== 401) {
                console.error(err);
                const msg = err.response?.data?.message || err.message || 'Failed to fetch agents';
                toast.error(`Error loading agents: ${msg}`);
            }
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchAgents();
    }, []);

    const handleCreate = async (agentData) => {
        try {
            await api.post('/admin/agent', agentData);
            setShowModal(false);
            fetchAgents();
            toast.success('Agent created successfully!');
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed to create agent');
        }
    };

    const handleUpdateCommission = async (agentId) => {
        try {
            await api.put('/admin/agent/commission', { agentId, commissionRate: editCommission });
            setEditingAgent(null);
            fetchAgents();
        } catch (err) {
            toast.error('Failed to update commission');
        }
    };

    const [showBalanceModal, setShowBalanceModal] = useState(false);
    const [balanceForm, setBalanceForm] = useState({ agentId: null });

    const openBalanceModal = (agent) => {
        setBalanceForm({ agentId: agent.id }); // Only need ID, form state is largely internal to modal now
        setShowBalanceModal(true);
    };

    const handleAdjustBalance = async (balanceData) => {
        // [TODO] Modal
        try {
            await api.post('/admin/agent/balance', balanceData);
            setShowBalanceModal(false);
            fetchAgents();
            toast.success('Balance adjusted successfully');
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed to adjust balance');
        }
    };

    return (
        <div className="flex flex-col h-full bg-slate-50 min-h-screen">
            {/* PWA Header - Admin Edition */}
            <div className="bg-slate-900 text-white p-6 rounded-b-[2rem] shadow-lg mb-6 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-40 h-40 bg-pink-500 rounded-full mix-blend-screen filter blur-3xl opacity-20 -mr-20 -mt-20"></div>
                <div className="absolute bottom-0 left-0 w-40 h-40 bg-purple-500 rounded-full mix-blend-screen filter blur-3xl opacity-20 -ml-20 -mb-20"></div>

                <div className="relative z-10">
                    <div className="flex justify-between items-center mb-6">
                        <Link href="/admin/dashboard" className="p-2 bg-white/10 backdrop-blur-md rounded-xl hover:bg-white/20 transition">
                            <ArrowLeft className="w-5 h-5 text-white" />
                        </Link>
                        <button onClick={() => setShowModal(true)} className="flex items-center gap-2 bg-pink-500 text-white px-4 py-2 rounded-xl backdrop-blur-sm border border-pink-400 font-bold text-sm shadow-lg shadow-pink-500/20 active:scale-95 transition">
                            <Plus className="w-4 h-4" /> Add New
                        </button>
                    </div>

                    <h1 className="text-3xl font-bold mb-1">Agents</h1>
                    <p className="text-slate-400 text-sm">Manage your sales force</p>
                </div>
            </div>

            <div className="p-6 overflow-y-auto pb-32">
                <div className="space-y-4">
                    {loading ? (
                        <div className="text-center py-10 text-slate-400">Loading agents...</div>
                    ) : agents.map(agent => (
                        <div key={agent.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex flex-col gap-4">
                            {/* Header: Icon + Name + Phone */}
                            <div className="flex items-start gap-4">
                                <div className="w-12 h-12 bg-slate-100 text-slate-600 rounded-xl flex items-center justify-center shrink-0">
                                    <User className="w-6 h-6" />
                                </div>
                                <div className="min-w-0 flex-1">
                                    <h3 className="font-bold text-slate-800 text-lg truncate">{agent.fullName}</h3>
                                    <p className="text-sm text-slate-500 font-mono">{agent.phone}</p>
                                </div>
                                <div className={`px-2 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wider ${agent.kycStatus === 'approved' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
                                    {agent.kycStatus || 'Pending'}
                                </div>
                            </div>

                            {/* Balance & Stats Section */}
                            <div className="flex flex-col gap-3">
                                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 relative">
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Current Stock</p>
                                    <p className="text-3xl font-black text-slate-800 tracking-tight">${agent.Wallet?.balance || 0}</p>
                                    <button
                                        onClick={() => openBalanceModal(agent)}
                                        className="absolute top-4 right-4 text-[10px] bg-indigo-50 text-indigo-600 hover:bg-indigo-100 px-3 py-1.5 rounded-full font-bold transition border border-indigo-100"
                                    >
                                        Manage
                                    </button>
                                </div>

                                <div className="grid grid-cols-3 gap-2">
                                    <div className="bg-emerald-50/50 p-2 rounded-lg border border-emerald-100 text-center">
                                        <p className="text-[9px] font-bold text-emerald-400 uppercase">Profit</p>
                                        <p className="font-bold text-emerald-700 text-sm">${Number(agent.totalEarnings || 0).toLocaleString()}</p>
                                    </div>
                                    <div className="bg-blue-50/50 p-2 rounded-lg border border-blue-100 text-center">
                                        <p className="text-[9px] font-bold text-blue-400 uppercase">Cash In</p>
                                        <p className="font-bold text-blue-700 text-sm">${Number(agent.totalDeposits || 0).toLocaleString()}</p>
                                    </div>
                                    <div className="bg-rose-50/50 p-2 rounded-lg border border-rose-100 text-center">
                                        <p className="text-[9px] font-bold text-rose-400 uppercase">Cash Out</p>
                                        <p className="font-bold text-rose-700 text-sm">${Number(agent.totalWithdraws || 0).toLocaleString()}</p>
                                    </div>
                                </div>

                                <Link href={`/admin/history?user=${agent.id}`} className="w-full text-center py-2 text-xs font-bold text-slate-400 hover:text-slate-600 transition border-t border-slate-100 block">
                                    View Transaction History
                                </Link>
                            </div>

                            {/* Commission Section */}
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100/50 flex items-center justify-between">
                                <div className="flex flex-col">
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Commission Rate</span>
                                    {editingAgent === agent.id ? (
                                        <div className="flex items-center gap-2 mt-1">
                                            <input
                                                type="number"
                                                value={editCommission}
                                                onChange={(e) => setEditCommission(e.target.value)}
                                                className="w-20 p-1 border rounded text-sm font-bold bg-white"
                                                autoFocus
                                            />
                                            <button onClick={() => handleUpdateCommission(agent.id)} className="bg-green-500 text-white p-1 rounded hover:bg-green-600"><Save className="w-4 h-4" /></button>
                                            <button onClick={() => setEditingAgent(null)} className="bg-red-100 text-red-500 p-1 rounded hover:bg-red-200"><X className="w-4 h-4" /></button>
                                        </div>
                                    ) : (
                                        <div className="flex items-center gap-2 mt-0.5">
                                            <span className="text-xl font-bold text-slate-700">{agent.commissionRate}%</span>
                                            <button onClick={() => { setEditingAgent(agent.id); setEditCommission(agent.commissionRate); }} className="text-slate-400 hover:text-emerald-600 transition">
                                                <Edit className="w-4 h-4" />
                                            </button>
                                        </div>
                                    )}
                                </div>
                                <div className="text-right">
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block">Username</span>
                                    <span className="text-xs font-medium text-slate-600">{agent.username}</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Modal - Create Agent */}
            <AddAgentModal
                isOpen={showModal}
                onClose={() => setShowModal(false)}
                onSubmit={handleCreate}
            />

            {/* Modal - Manage Balance */}
            <AgentBalanceModal
                isOpen={showBalanceModal}
                onClose={() => setShowBalanceModal(false)}
                onSubmit={handleAdjustBalance}
                initialAgentId={balanceForm.agentId}
            />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../../../services/api';
import { Check, X, RefreshCw, DollarSign } from 'lucide-react';
import toast from 'react-hot-toast';

export default function AdminSettlementsPage() {
    const [settlements, setSettlements] = useState([]);
    const [loading, setLoading] = useState(true);
    const [processing, setProcessing] = useState(null);

    useEffect(() => {
        fetchSettlements();
    }, []);

    const fetchSettlements = async () => {
        try {
            // Re-use pending transactions endpoint but filter by type?
            // Or use dedicated endpoint. Let's use getPendingTransactions with type filter if supported
            // Backend supports ?type=admin_settlement
            const res = await api.get('/transactions/pending?type=admin_settlement');
            setSettlements(res.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleAction = async (id, status) => {
        setProcessing(id);
        try {
            await api.post('/transaction/complete', {
                transactionId: id,
                status: status, // completed or rejected
                comment: `Admin ${status} settlement`
            });
            await fetchSettlements();
            toast.success(`Settlement ${status}`);
        } catch (err) {
            toast.error('Action failed');
        } finally {
            setProcessing(null);
        }
    };

    return (
        <div className="p-6">
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-2xl font-bold text-slate-800">Agent Settlements pending</h1>
                <button onClick={fetchSettlements} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200">
                    <RefreshCw className="w-5 h-5 text-slate-600" />
                </button>
            </div>

            {loading ? <div className="text-center py-10">Loading Requests...</div> : (
                <div className="space-y-4">
                    {settlements.length === 0 ? <p className="text-center text-slate-400">No pending settlements</p> : (
                        settlements.map(trx => (
                            <div key={trx.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
                                <div>
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className="font-bold text-slate-800">{trx.User?.fullName}</span>
                                        <span className="text-xs px-2 py-0.5 bg-blue-100 text-blue-700 rounded-full font-bold">Agent</span>
                                    </div>
                                    <p className="text-sm text-slate-500">{trx.User?.phone}</p>
                                    <div className="mt-2 bg-slate-50 p-2 rounded-lg text-xs text-slate-600">
                                        {trx.recipientDetails}
                                    </div>
                                    <p className="text-[10px] text-slate-400 mt-1">{new Date(trx.createdAt).toLocaleString()}</p>
                                </div>

                                <div className="flex flex-col items-end gap-2">
                                    <span className="text-2xl font-black text-slate-800">${Math.abs(parseFloat(trx.amount))}</span>
                                    <div className="flex gap-2">
                                        <button
                                            onClick={() => handleAction(trx.id, 'rejected')}
                                            disabled={processing === trx.id}
                                            className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 transition disabled:opacity-50"
                                        >
                                            <X className="w-5 h-5" />
                                        </button>
                                        <button
                                            onClick={() => handleAction(trx.id, 'completed')}
                                            disabled={processing === trx.id}
                                            className="px-4 py-2 bg-green-600 text-white rounded-lg font-bold hover:bg-green-700 transition flex items-center gap-2 disabled:opacity-50"
                                        >
                                            <Check className="w-4 h-4" /> Approve
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            )}
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import api from '../../../services/api';
import { ArrowLeft, Users, FileText, Settings, Shield, ShieldCheck, Wallet, Briefcase, MessageSquare, Ticket, Lock, Zap, Activity, Gem, ClipboardList, TrendingUp, AlertTriangle } from 'lucide-react';
import DashboardCard from '../../../components/admin/DashboardCard';
import ConfirmationModal from '../../../components/ui/ConfirmationModal';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
    const router = useRouter();
    const [stats, setStats] = useState({
        overview: {
            today_deposits: 0,
            today_withdraws: 0,
            total_created: 0,
            total_withdraws: 0,
            pending_deposits: 0,
            pending_withdraws: 0
        },
        actual: {
            user_main_balances: 0,
            user_game_balances: 0
        }
    });
    const [loading, setLoading] = useState(true);
    const [maintenance, setMaintenance] = useState(false);
    const [updatingMaint, setUpdatingMaint] = useState(false);
    const [modal, setModal] = useState({ isOpen: false, title: '', message: '', onConfirm: null });

    useEffect(() => {
        const loadData = async () => {
            try {
                // 1. Financials
                const finRes = await api.get('/admin/audit/financial');
                const overview = finRes.data.overview || {};
                const actual = finRes.data.actual || {};
                const eco = finRes.data.economics || {};

                setStats({
                    ...eco, // spreads totalUsers, totalDeposits, totalServerRevenue, etc.
                    currentLiabilities: overview.current_liabilities || 0,
                    pendingActions: (overview.pending_deposits || 0) + (overview.pending_withdraws || 0)
                });

                // 2. Maintenance Status
                const sysRes = await api.get('/admin/settings/public');
                if (sysRes.data.maintenance?.isActive) setMaintenance(true);

            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };
        loadData();
    }, []);

    const toggleMaintenance = async () => {
        setModal({
            isOpen: true,
            title: 'Toggle Maintenance Mode?',
            message: `Are you sure you want to ${maintenance ? 'DISABLE' : 'ENABLE'} Maintenance Mode?`,
            confirmText: maintenance ? 'Disable' : 'Enable',
            onConfirm: async () => {
                setUpdatingMaint(true);
                try {
                    const newState = !maintenance;
                    await api.post('/settings/system', {
                        settings: {
                            maintenance: {
                                isActive: newState,
                                message: newState ? 'System Under Maintenance' : ''
                            }
                        }
                    });
                    setMaintenance(newState);
                    toast.success(`Maintenance Mode ${newState ? 'ENABLED' : 'DISABLED'}`);
                } catch (e) {
                    toast.error('Failed to update maintenance');
                } finally {
                    setUpdatingMaint(false);
                }
            }
        });
    };

    return (
        <div className="min-h-screen bg-[#050505] font-sans pb-20 text-white">
            {/* BACKGROUND VFX */}
            <div className="fixed inset-0 pointer-events-none opacity-20 bg-[url('https://grainy-gradients.vercel.app/noise.svg')]"></div>

            {/* Header Section */}
            <header className="bg-[#0D0D0D] border-b border-[#D4AF37]/20 sticky top-0 z-50 backdrop-blur-md bg-opacity-80">
                <div className="w-full px-6 lg:px-10 py-4 flex justify-between items-center">
                    <div className="flex items-center gap-4">
                        <button onClick={() => router.push('/')} className="p-2 rounded-full hover:bg-white/10 transition">
                            <ArrowLeft className="w-5 h-5 text-slate-400" />
                        </button>
                        <h1 className="text-xl font-black uppercase tracking-widest text-[#D4AF37] flex items-center gap-2">
                            <ShieldCheck className="w-6 h-6" /> Admin Console
                        </h1>
                    </div>

                    {/* Maintenance Toggle */}
                    <button
                        onClick={toggleMaintenance}
                        disabled={updatingMaint}
                        className={`flex items-center gap-2 px-4 py-2 rounded-full font-bold text-xs uppercase transition-all shadow-lg ${maintenance
                            ? 'bg-red-500 text-white shadow-red-500/20 animate-pulse'
                            : 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 hover:bg-emerald-500/20'
                            }`}
                    >
                        {updatingMaint ? (
                            <Activity className="w-3 h-3 animate-spin" />
                        ) : (
                            maintenance ? <Lock className="w-3 h-3" /> : <Zap className="w-3 h-3" />
                        )}
                        {maintenance ? 'System Locked' : 'System Live'}
                    </button>
                </div>
            </header>

            {/* MAIN CONTENT */}
            <main className="w-full px-6 lg:px-10 py-8 relative z-10">
                {/* SIMPLE STATS GRID */}
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-8">
                    {/* 1. Total Users */}
                    <div className="bg-[#0f0f0f] border border-white/5 p-5 rounded-xl text-center">
                        <Users className="w-8 h-8 text-blue-500 mx-auto mb-2" />
                        <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-1">Total Users</h3>
                        <div className="text-2xl font-black text-white">{Number(stats.totalUsers || 0).toLocaleString()}</div>
                    </div>

                    {/* 2. User Wallets */}
                    <div className="bg-[#0f0f0f] border border-white/5 p-5 rounded-xl text-center">
                        <Wallet className="w-8 h-8 text-yellow-500 mx-auto mb-2" />
                        <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-1">User Wallets</h3>
                        <div className="text-2xl font-black text-white">{Number(stats.currentLiabilities || 0).toLocaleString()} NXS</div>
                    </div>

                    {/* 3. Total Deposits */}
                    <div className="bg-[#0f0f0f] border border-white/5 p-5 rounded-xl text-center">
                        <TrendingUp className="w-8 h-8 text-emerald-500 mx-auto mb-2" />
                        <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-1">Total Deposits</h3>
                        <div className="text-2xl font-black text-white">{Number(stats.totalDeposits || 0).toLocaleString()} NXS</div>
                    </div>

                    {/* 4. Total Withdrawals */}
                    <div className="bg-[#0f0f0f] border border-white/5 p-5 rounded-xl text-center">
                        <ArrowLeft className="w-8 h-8 text-rose-500 mx-auto mb-2 -rotate-[135deg]" />
                        <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-1">Total Withdrawals</h3>
                        <div className="text-2xl font-black text-white">{Number(stats.totalWithdraws || 0).toLocaleString()} NXS</div>
                    </div>

                    {/* 5. Server Sales */}
                    <div className="bg-[#0f0f0f] border border-white/5 p-5 rounded-xl text-center">
                        <ShieldCheck className="w-8 h-8 text-indigo-500 mx-auto mb-2" />
                        <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-1">Server Sales</h3>
                        <div className="text-2xl font-black text-white">{Number(stats.totalServerRevenue || 0).toLocaleString()} NXS</div>
                    </div>

                    {/* 6. Task Earnings */}
                    <div className="bg-[#0f0f0f] border border-white/5 p-5 rounded-xl text-center">
                        <Activity className="w-8 h-8 text-cyan-500 mx-auto mb-2" />
                        <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-1">Task Earnings</h3>
                        <div className="text-2xl font-black text-white">{Number(stats.totalTaskIncome || 0).toLocaleString()} NXS</div>
                    </div>
                </div>

                {/* DASHBOARD GRID (2-Column Strict) */}
                <div className="grid grid-cols-2 gap-4">
                    <DashboardCard href="/admin/transactions" title="Transactions" description="Deposits & Payouts" icon={FileText} colorClass="blue" badge={stats.pendingActions > 0 ? `${stats.pendingActions}` : ''} />
                    <DashboardCard href="/admin/users" title="Manage Users" description="Edit, Ban, Verify" icon={Users} colorClass="indigo" />
                    <DashboardCard href="/admin/agents" title="Agent Network" description="Commission & Trees" icon={Briefcase} colorClass="green" />
                    <DashboardCard href="/admin/plans" title="Plan Manager" description="Create/Edit Tiers" icon={Gem} colorClass="amber" />
                    <DashboardCard href="/admin/tasks" title="Manage 20 Tasks" description="Edit Video Ads" icon={ClipboardList} colorClass="cyan" />
                    <DashboardCard href="/admin/settings" title="System Settings" description="Global Config" icon={Settings} colorClass="gray" />
                    <DashboardCard href="/admin/audit" title="Financial Audit" description="Profit/Loss Reports" icon={Shield} colorClass="red" />

                    <DashboardCard href="/admin/lottery" title="Lottery Control" description="Draws & Tickets" icon={Ticket} colorClass="pink" />
                    <DashboardCard href="/admin/support" title="User Support" description="Help & Tickets" icon={MessageSquare} colorClass="cyan" />

                </div>

            </main>
            {/* Confirmation Modal */}
            <ConfirmationModal
                isOpen={modal.isOpen}
                onClose={() => setModal({ ...modal, isOpen: false })}
                onConfirm={modal.onConfirm}
                title={modal.title}
                message={modal.message}
                confirmText={modal.confirmText || 'Confirm'}
            />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../../services/api';
import { Save, Plus, Trash2, ArrowLeft, Smartphone } from 'lucide-react';
import Link from 'next/link';
import toast from 'react-hot-toast';
import ConfirmationModal from '../../../components/ui/ConfirmationModal';

export default function DepositSettingsPage() {
    const [agents, setAgents] = useState([]);
    const [depositNumbers, setDepositNumbers] = useState([]); // [{ number: '...', agentId: 1, agentName: '...' }]
    const [loading, setLoading] = useState(true);

    // Form State
    const [newNumber, setNewNumber] = useState('');
    const [selectedAgentId, setSelectedAgentId] = useState('');
    const [editIndex, setEditIndex] = useState(null);
    const [confirmModal, setConfirmModal] = useState({ isOpen: false });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [agentsRes, settingsRes] = await Promise.all([
                api.get('/admin/agents'),
                api.get('/admin/deposit-settings')
            ]);
            setAgents(agentsRes.data);
            setDepositNumbers(settingsRes.data.deposit_agents || []);
        } catch (err) {
            console.error(err);
            toast.error('Failed to load data');
        } finally {
            setLoading(false);
        }
    };

    const handleAddNumber = () => {
        if (!newNumber || !selectedAgentId) return toast.error('Please enter number and select agent');

        const agent = agents.find(a => a.id === parseInt(selectedAgentId));
        if (!agent) return;

        if (editIndex !== null) {
            // Update Existing
            const updated = [...depositNumbers];
            updated[editIndex] = {
                number: newNumber,
                agentId: agent.id,
                agentName: agent.fullName
            };
            setDepositNumbers(updated);
            setEditIndex(null);
        } else {
            // Add New
            const updated = [...depositNumbers, {
                number: newNumber,
                agentId: agent.id,
                agentName: agent.fullName
            }];
            setDepositNumbers(updated);
        }

        setNewNumber('');
        setSelectedAgentId('');
    };

    const handleEdit = (index) => {
        const item = depositNumbers[index];
        setNewNumber(item.number);
        setSelectedAgentId(item.agentId);
        setEditIndex(index);
    };

    const handleRemoveNumber = (index) => {
        setConfirmModal({
            isOpen: true,
            title: 'Remove Number',
            message: 'Are you sure you want to remove this number?',
            confirmText: 'Remove',
            onConfirm: () => {
                const updated = depositNumbers.filter((_, i) => i !== index);
                setDepositNumbers(updated);
                if (editIndex === index) {
                    setEditIndex(null);
                    setNewNumber('');
                    setSelectedAgentId('');
                }
                setConfirmModal({ isOpen: false });
                toast.success('Number removed');
            }
        });
    };

    const handleSave = async () => {
        try {
            await api.post('/admin/deposit-settings', { deposit_agents: depositNumbers });
            toast.success('Settings Saved Successfully!');
        } catch (err) {
            console.error(err);
            toast.error('Failed to save settings');
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 p-6 pb-20">
            {/* Header */}
            <div className="flex items-center gap-4 mb-8">
                <Link href="/admin/dashboard" className="p-3 bg-white hover:bg-slate-100 rounded-xl shadow-sm border border-slate-200 transition">
                    <ArrowLeft className="w-5 h-5 text-slate-600" />
                </Link>
                <div>
                    <h1 className="text-2xl font-bold text-slate-800">Deposit Numbers</h1>
                    <p className="text-slate-500 text-sm">Link deposit phone numbers to Agents for auto-accounting.</p>
                </div>
            </div>

            <div className="max-w-2xl mx-auto space-y-6">
                <div className="max-w-md mx-auto space-y-4 md:max-w-2xl">
                    {/* Main Configuration Card */}
                    <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100">
                        <h3 className="font-bold text-lg mb-4 text-slate-700">Active Numbers</h3>

                        {/* Add New Form - Responsive Stack */}
                        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-200 mb-6">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">Add New Number</label>
                            <div className="flex flex-col gap-3">
                                <input
                                    type="text"
                                    placeholder="Wallet Number (017...)"
                                    value={newNumber}
                                    onChange={(e) => setNewNumber(e.target.value)}
                                    className="w-full p-4 rounded-xl border border-slate-300 focus:outline-none focus:border-indigo-500 font-mono font-medium text-lg bg-white"
                                />
                                <select
                                    value={selectedAgentId}
                                    onChange={(e) => setSelectedAgentId(e.target.value)}
                                    className="w-full p-4 rounded-xl border border-slate-300 focus:outline-none focus:border-indigo-500 font-sans font-medium text-slate-800 bg-white"
                                    style={{ fontFamily: 'sans-serif, system-ui, -apple-system' }}
                                >
                                    <option value="">Select Agent...</option>
                                    {agents.map(a => (
                                        <option key={a.id} value={a.id}>{a.fullName} ({a.phone})</option>
                                    ))}
                                </select>
                                <div className="flex gap-2">
                                    <button
                                        onClick={handleAddNumber}
                                        disabled={!newNumber || !selectedAgentId}
                                        className={`flex-1 py-4 text-white font-bold rounded-xl shadow-lg transition flex items-center justify-center gap-2 ${editIndex !== null ? 'bg-orange-500 hover:bg-orange-600 shadow-orange-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'
                                            } disabled:opacity-50 disabled:shadow-none`}
                                    >
                                        {editIndex !== null ? (
                                            <><Plus className="w-5 h-5 rotate-45" /> Update Number</>
                                        ) : (
                                            <><Plus className="w-6 h-6" /> Add Number</>
                                        )}
                                    </button>

                                    {editIndex !== null && (
                                        <button
                                            onClick={() => {
                                                setEditIndex(null);
                                                setNewNumber('');
                                                setSelectedAgentId('');
                                            }}
                                            className="px-4 py-4 bg-slate-200 text-slate-500 font-bold rounded-xl hover:bg-slate-300 transition"
                                        >
                                            Cancel
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>

                        {/* List */}
                        <div className="space-y-3">
                            {depositNumbers.length === 0 ? (
                                <div className="text-center py-10 opacity-50">
                                    <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-3">
                                        <Smartphone className="w-8 h-8 text-slate-400" />
                                    </div>
                                    <p className="text-slate-500 font-medium">No numbers added yet.</p>
                                </div>
                            ) : depositNumbers.map((item, idx) => (
                                <div key={idx} className="flex justify-between items-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm hover:border-indigo-100 transition group">
                                    <div className="flex items-center gap-4">
                                        <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600 font-bold shrink-0">
                                            #{(idx + 1).toString().padStart(2, '0')}
                                        </div>
                                        <div className="overflow-hidden">
                                            <p className="font-mono font-bold text-slate-800 text-lg truncate">{item.number}</p>
                                            <p className="text-xs text-slate-500 truncate">Agent: <span className="font-bold text-indigo-600">{item.agentName}</span></p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <button
                                            onClick={() => handleEdit(idx)}
                                            className="p-3 text-orange-400 hover:text-orange-500 hover:bg-orange-50 rounded-xl transition shrink-0"
                                        >
                                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>
                                        </button>
                                        <button
                                            onClick={() => handleRemoveNumber(idx)}
                                            className="p-3 text-red-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition shrink-0"
                                        >
                                            <Trash2 className="w-5 h-5" />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Floating Save Button Area */}
                    <div className="sticky bottom-4 mx-4">
                        <button
                            onClick={handleSave}
                            className="w-full py-4 bg-slate-900 text-white font-bold rounded-2xl shadow-xl hover:scale-[1.02] active:scale-[0.98] transition flex items-center justify-center gap-3 backdrop-blur-md"
                        >
                            <Save className="w-5 h-5" /> Save Changes
                        </button>
                    </div>
                </div>
            </div>
            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                onConfirm={confirmModal.onConfirm}
                title={confirmModal.title}
                message={confirmModal.message}
                confirmText={confirmModal.confirmText}
            />
        </div>
    );
}

'use client';
import { useEffect, useState, Suspense } from 'react';
import api from '../../../services/api';
import { ArrowLeft, Search, Filter, Smartphone, Wallet, Send, Gamepad2, Gift, Ban, CheckCircle, Clock } from 'lucide-react';
import Link from 'next/link';
import { useSearchParams } from 'next/navigation';


function HistoryContent() {
    const [transactions, setTransactions] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState('all'); // all, add_money, mobile_recharge, send_money
    const [search, setSearch] = useState('');

    // Get searchParams
    const searchParams = useSearchParams();
    const userId = searchParams.get('user');

    useEffect(() => {
        fetchHistory();
    }, [userId]);

    const fetchHistory = async () => {
        try {
            // Include userId in query if present
            const endpoint = userId ? `/transactions/all?userId=${userId}` : '/transactions/all';
            const res = await api.get(endpoint);
            setTransactions(res.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const getMeta = (type) => {
        switch (type) {
            case 'add_money': return { icon: Wallet, color: 'text-emerald-600', bg: 'bg-emerald-50', label: 'Add Money' };
            case 'mobile_recharge': return { icon: Smartphone, color: 'text-violet-600', bg: 'bg-violet-50', label: 'Mobile Recharge' };
            case 'send_money': return { icon: Send, color: 'text-pink-600', bg: 'bg-pink-50', label: 'Send Money' };
            case 'game_win': return { icon: Gamepad2, color: 'text-orange-600', bg: 'bg-orange-50', label: 'Game Win' };
            case 'commission': return { icon: Gift, color: 'text-blue-600', bg: 'bg-blue-50', label: 'Commission' };
            case 'wallet_transfer': return { icon: Wallet, color: 'text-indigo-600', bg: 'bg-indigo-50', label: 'Wallet Transfer' };
            case 'referral_bonus': return { icon: Gift, color: 'text-purple-600', bg: 'bg-purple-50', label: 'Referral Bonus' };
            case 'task_reward': return { icon: CheckCircle, color: 'text-yellow-600', bg: 'bg-yellow-50', label: 'Task Reward' };
            default: return { icon: Clock, color: 'text-slate-500', bg: 'bg-slate-100', label: type.replace('_', ' ') };
        }
    };

    const filteredTransactions = transactions.filter(tx => {
        const matchesFilter = filter === 'all' || tx.type === filter;

        // Safe Search with Lowercase checks
        const searchLower = search.toLowerCase();
        const matchesSearch = search === '' ||
            tx.id?.toString().includes(search) ||
            tx.User?.phone?.includes(search) || // Optional chaining handles missing User or Phone
            (tx.User?.fullName && tx.User.fullName.toLowerCase().includes(searchLower)) || // Check existence before toLowerCase
            (tx.recipientDetails && tx.recipientDetails.toLowerCase().includes(searchLower)); // Added search by details too

        return matchesFilter && matchesSearch;
    });

    return (
        <div className="min-h-screen bg-slate-50 font-sans pb-20">
            {/* Header */}
            <div className="bg-white sticky top-0 z-20 shadow-sm border-b border-slate-100 px-4 py-4 md:px-8">
                <div className="max-w-5xl mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Link href="/admin/dashboard" className="p-2.5 hover:bg-slate-100 rounded-xl transition border border-slate-200 text-slate-600">
                            <ArrowLeft className="w-5 h-5" />
                        </Link>
                        <div>
                            <h1 className="text-xl font-bold text-slate-800">History</h1>
                            <p className="text-xs text-slate-500 font-medium">All User Transactions</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="max-w-5xl mx-auto p-4 md:p-8 space-y-6">

                {/* Search & Filter Bar */}
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4">
                    <div className="relative flex-1">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                        <input
                            type="text"
                            placeholder="Search by Phone, Name or TrxID..."
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            className="w-full pl-12 pr-4 py-3 rounded-xl bg-slate-50 border-none focus:ring-2 focus:ring-indigo-500/20 font-medium text-slate-700 outline-none"
                        />
                    </div>
                    <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
                        {['all', 'add_money', 'mobile_recharge', 'send_money'].map(f => (
                            <button
                                key={f}
                                onClick={() => setFilter(f)}
                                className={`px-4 py-2.5 rounded-xl text-xs font-bold whitespace-nowrap transition capitalize ${filter === f
                                    ? 'bg-slate-800 text-white shadow-lg shadow-slate-200'
                                    : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                                    }`}
                            >
                                {f.replace('_', ' ')}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Content */}
                {loading ? (
                    <div className="space-y-4">
                        {[1, 2, 3, 4, 5].map((i) => (
                            <div key={i} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm animate-pulse flex flex-col gap-4">
                                <div className="flex justify-between items-start">
                                    <div className="flex items-center gap-3">
                                        <div className="w-12 h-12 bg-slate-200 rounded-xl"></div>
                                        <div>
                                            <div className="h-4 w-24 bg-slate-200 rounded mb-2"></div>
                                            <div className="h-3 w-16 bg-slate-200 rounded"></div>
                                        </div>
                                    </div>
                                    <div className="h-5 w-20 bg-slate-200 rounded-full"></div>
                                </div>
                                <div className="space-y-2 pt-2 border-t border-slate-50">
                                    <div className="h-3 w-full bg-slate-200 rounded"></div>
                                    <div className="h-3 w-2/3 bg-slate-200 rounded"></div>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : filteredTransactions.length === 0 ? (
                    <div className="text-center py-20 opacity-50 bg-white rounded-2xl border border-dashed border-slate-200">
                        <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Search className="w-8 h-8 text-slate-400" />
                        </div>
                        <h3 className="font-bold text-slate-600 text-lg">No Transactions Found</h3>
                        <p className="text-slate-400">Try adjusting your filters</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {filteredTransactions.map((trx) => {
                            const meta = getMeta(trx.type);
                            const Icon = meta.icon;
                            const isCredit = parseFloat(trx.amount) > 0;

                            return (
                                <div key={trx.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md hover:border-indigo-100 transition group relative overflow-hidden flex flex-col justify-between">

                                    {/* Top Row: Icon, Title, Status */}
                                    <div className="flex justify-between items-start mb-4">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${meta.bg} ${meta.color} shrink-0`}>
                                                <Icon className="w-6 h-6" />
                                            </div>
                                            <div>
                                                <p className="font-bold text-slate-700 capitalize">{meta.label}</p>
                                                <p className="text-xs text-slate-400 font-mono">{new Date(trx.createdAt).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' })}</p>
                                            </div>
                                        </div>
                                        <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${trx.status === 'completed' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                                            trx.status === 'rejected' ? 'bg-rose-50 text-rose-600 border-rose-100' :
                                                'bg-amber-50 text-amber-600 border-amber-100'
                                            }`}>
                                            {trx.status}
                                        </span>
                                    </div>

                                    {/* Middle: Details & Amount */}
                                    <div className="space-y-3 flex-1">
                                        <div className="flex justify-between items-center p-3 bg-slate-50/80 rounded-xl border border-slate-100">
                                            <span className="text-xs text-slate-500 font-medium">Amount</span>
                                            <span className={`font-mono font-bold text-base ${isCredit ? 'text-emerald-600' : 'text-slate-700'}`}>
                                                {isCredit ? '+' : ''}{parseFloat(trx.amount).toFixed(2)} $
                                            </span>
                                        </div>

                                        <div className="space-y-1 px-1">
                                            <div className="flex justify-between text-xs">
                                                <span className="text-slate-400">User:</span>
                                                <span className="font-medium text-slate-700">{trx.User?.fullName} <span className="text-slate-400">({trx.User?.phone})</span></span>
                                            </div>
                                            {trx.recipientDetails && (
                                                <div className="flex justify-between text-xs">
                                                    <span className="text-slate-400">Details:</span>
                                                    <span className="font-medium text-slate-600 max-w-[200px] truncate" title={trx.recipientDetails}>{trx.recipientDetails}</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    {/* Bottom: ID & Decor */}
                                    <div className="mt-4 pt-3 border-t border-slate-50 flex justify-between items-center">
                                        <span className="text-[10px] font-mono text-slate-300">ID: {trx.id}</span>
                                        {trx.adminComment && (
                                            <span className="text-[10px] text-indigo-500 font-medium bg-indigo-50 px-2 py-0.5 rounded">Note Added</span>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
}

export default function TransactionHistoryPage() {
    return (
        <Suspense fallback={
            <div className="min-h-screen flex items-center justify-center">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-500 border-t-transparent"></div>
            </div>
        }>
            <HistoryContent />
        </Suspense>
    );
}

