'use client';
import { useState, useEffect } from 'react';
import api from '../../../services/api';
import Link from 'next/link';
// import Image from 'next/image'; // Assuming we might verify images later, check usage
import { ArrowLeft, Check, X, Clock } from 'lucide-react';
import toast from 'react-hot-toast';
import ConfirmationModal from '../../../components/ui/ConfirmationModal';

export default function AdminRequestsPage() {
    const [requests, setRequests] = useState([]);
    const [loading, setLoading] = useState(true);
    const [confirmModal, setConfirmModal] = useState({ isOpen: false });
    const [securityModal, setSecurityModal] = useState({ isOpen: false, requestId: null, action: null });
    const [secKeys, setSecKeys] = useState(['', '', '']);

    const fetchRequests = async () => {
        try {
            const res = await api.get('/admin/recharges');
            setRequests(res.data);
            setLoading(false);
        } catch (err) {
            console.error(err);
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchRequests();
    }, []);

    const handleAction = (id, action) => {
        if (action === 'approve') {
            // Trigger 3-Layer Security Modal for Approvals
            setSecKeys(['', '', '']);
            setSecurityModal({ isOpen: true, requestId: id, action: 'approve' });
        } else {
            // Standard Confirmation for Rejections
            setConfirmModal({
                isOpen: true,
                title: 'Reject Request',
                message: `Are you sure you want to reject this request?`,
                confirmText: 'Reject',
                onConfirm: async () => {
                    try {
                        await api.post('/admin/deposit-request', { requestId: id, action: 'reject' });
                        fetchRequests();
                        toast.success(`Request rejected`);
                        setConfirmModal({ isOpen: false });
                    } catch (err) {
                        toast.error(err.response?.data?.message || 'Action failed');
                    }
                }
            });
        }
    };

    const submitSecureAction = async () => {
        try {
            await api.post('/admin/deposit-request', {
                requestId: securityModal.requestId,
                action: securityModal.action,
                secKey1: secKeys[0],
                secKey2: secKeys[1],
                secKey3: secKeys[2]
            });
            fetchRequests();
            toast.success(`Request Approved Securely!`);
            setSecurityModal({ isOpen: false, requestId: null, action: null });
        } catch (err) {
            toast.error(err.response?.data?.message || 'Security Verification Failed');
        }
    };

    return (
        <div className="flex flex-col h-full bg-gray-50">
            <div className="bg-white p-4 flex items-center gap-4 shadow-sm z-10 border-b border-gray-100">
                <Link href="/admin/dashboard" className="p-2 hover:bg-gray-100 rounded-full"><ArrowLeft className="w-6 h-6 text-gray-700" /></Link>
                <h1 className="text-lg font-bold text-gray-800">Recharge Requests</h1>
            </div>

            <div className="flex-1 p-4 overflow-y-auto">
                {loading ? (
                    <p className="text-center text-gray-500 mt-10">Loading...</p>
                ) : requests.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                        <Clock className="w-12 h-12 mb-2 opacity-20" />
                        <p>No pending requests</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {requests.map(req => (
                            <div key={req.id} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
                                <div className="flex justify-between items-start mb-4">
                                    <div>
                                        <p className="font-bold text-gray-800">{req.User?.fullName || 'Unknown User'}</p>
                                        <p className="text-xs text-gray-500">{req.User?.phone}</p>
                                    </div>
                                    <span className="bg-orange-100 text-orange-600 text-xs font-bold px-2 py-1 rounded-md uppercase">Pending</span>
                                </div>

                                <div className="bg-gray-50 p-3 rounded-xl mb-4 flex justify-between items-center">
                                    <span className="text-gray-500 text-sm">Amount Requested</span>
                                    <span className="font-bold text-lg text-pink-600">$ {req.amount}</span>
                                </div>

                                {req.proofImage && (
                                    <div className="mb-4">
                                        <p className="text-xs text-gray-500 mb-1">Proof:</p>
                                        <a href={`https://usaaffiliatemarketing.com/api/${req.proofImage}`} target="_blank" rel="noopener noreferrer" className="text-blue-500 text-xs hover:underline truncate block">
                                            View Proof Image
                                        </a>
                                    </div>
                                )}

                                {/* TrxID Section (Priority) */}
                                {req.transactionId && (
                                    <div className="bg-slate-100 p-3 rounded-lg mb-4 border border-slate-200">
                                        <p className="text-[10px] text-slate-500 font-bold uppercase mb-1">Transaction ID</p>
                                        <div className="flex justify-between items-center">
                                            <code className="text-sm font-black text-slate-700 select-all">{req.transactionId}</code>
                                            <button
                                                onClick={() => {
                                                    navigator.clipboard.writeText(req.transactionId);
                                                    toast.success('TrxID Copied!');
                                                }}
                                                className="bg-white p-1.5 rounded-md shadow-sm border border-gray-200 text-xs font-bold text-blue-600 hover:bg-blue-50 active:scale-95 transition-all"
                                            >
                                                COPY
                                            </button>
                                        </div>
                                    </div>
                                )}

                                <div className="grid grid-cols-2 gap-3">
                                    <button onClick={() => handleAction(req.id, 'reject')} className="py-3 rounded-xl border border-red-100 text-red-600 font-bold text-sm hover:bg-red-50 transition flex justify-center items-center gap-2">
                                        <X className="w-4 h-4" /> Reject
                                    </button>
                                    <button onClick={() => handleAction(req.id, 'approve')} className="py-3 rounded-xl bg-green-500 text-white font-bold text-sm hover:bg-green-600 transition flex justify-center items-center gap-2 shadow-lg shadow-green-500/20">
                                        <Check className="w-4 h-4" /> Approve
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                onConfirm={confirmModal.onConfirm}
                title={confirmModal.title}
                message={confirmModal.message}
                confirmText={confirmModal.confirmText}
            />

            {/* 3-Layer Security Modal */}
            {securityModal.isOpen && (
                <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => setSecurityModal({ isOpen: false })}></div>
                    <div className="relative bg-[#0a0f1e] border-2 border-red-500/50 rounded-2xl p-6 w-full max-w-sm shadow-[0_0_50px_-12px_rgba(239,68,68,0.5)]">
                        <div className="text-center mb-6">
                            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-3 border border-red-500/30 shadow-[0_0_15px_rgba(239,68,68,0.3)]">
                                <span className="text-2xl text-red-500 font-black">!</span>
                            </div>
                            <h2 className="text-red-500 font-black text-xl uppercase tracking-widest">Security Check</h2>
                            <p className="text-xs text-slate-400 mt-2">Enter your 3 Secret Keys to authorize this balance creation.</p>
                        </div>

                        <div className="space-y-3 mb-6">
                            {[0, 1, 2].map((i) => (
                                <input
                                    key={i}
                                    type="password"
                                    placeholder={`Secret Key ${i + 1}`}
                                    value={secKeys[i]}
                                    onChange={(e) => {
                                        const newKeys = [...secKeys];
                                        newKeys[i] = e.target.value;
                                        setSecKeys(newKeys);
                                    }}
                                    className="w-full bg-slate-900 border border-slate-700/50 rounded-xl px-4 py-3 text-white text-center tracking-[0.5em] focus:outline-none focus:border-red-500 transition-colors"
                                />
                            ))}
                        </div>

                        <div className="flex gap-3">
                            <button onClick={() => setSecurityModal({ isOpen: false })} className="flex-1 py-3 rounded-xl bg-slate-800 text-slate-300 font-bold text-sm hover:bg-slate-700 transition">
                                CANCEL
                            </button>
                            <button
                                onClick={submitSecureAction}
                                disabled={secKeys.some(k => !k)}
                                className="flex-1 py-3 rounded-xl bg-gradient-to-r from-red-600 to-red-500 text-white font-black text-sm hover:shadow-[0_0_20px_rgba(239,68,68,0.4)] transition disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-wider"
                            >
                                AUTHORIZE
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../../services/api';
import Link from 'next/link';
import { Save, Settings, DollarSign, Activity, ArrowLeft, TrendingUp, Plus, Trash2 } from 'lucide-react';

export default function GlobalSettingsPage() {
    const [settings, setSettings] = useState({
        task_base_reward: '',
        daily_task_limit: '',
        min_withdraw_amount: '',
        referral_bonus_amount: '',
        referral_reward_currency: 'income',
        cash_out_commission_percent: '',
        p2p_market_min: '',
        p2p_market_max: '',
        referral_tiers: []
    });
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchSettings();
    }, []);

    const fetchSettings = async () => {
        try {
            const res = await api.get('/admin/settings/global');
            const data = res.data;
            if (typeof data.referral_tiers === 'string') {
                try {
                    data.referral_tiers = JSON.parse(data.referral_tiers);
                } catch (e) {
                    data.referral_tiers = [];
                }
            }
            setSettings(data);
            setLoading(false);
        } catch (err) {
            console.error(err);
            setLoading(false);
        }
    };

    const handleSave = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            await api.post('/admin/settings/global', settings);
            setMessage('Settings Saved Successfully!');
        } catch (err) {
            console.error(err);
            setMessage('Failed to save settings.');
        } finally {
            setSaving(false);
            setTimeout(() => setMessage(''), 3000);
        }
    };

    const handleAddTier = () => {
        setSettings(prev => ({
            ...prev,
            referral_tiers: [...(prev.referral_tiers || []), { level: (prev.referral_tiers?.length || 0) + 1, name: '', targetReferrals: 0, bonusAmount: 0 }]
        }));
    };

    const handleUpdateTier = (index, field, value) => {
        const newTiers = [...settings.referral_tiers];
        newTiers[index][field] = value;
        setSettings({ ...settings, referral_tiers: newTiers });
    };

    const handleRemoveTier = (index) => {
        const newTiers = settings.referral_tiers.filter((_, i) => i !== index);
        // re-index levels to maintain order
        newTiers.forEach((t, i) => t.level = i + 1);
        setSettings({ ...settings, referral_tiers: newTiers });
    };

    return (
        <div className="p-6">
            <div className="mb-6 flex items-center gap-4">
                <Link href="/admin/dashboard" className="p-2 bg-slate-200 rounded-full hover:bg-slate-300 transition">
                    <ArrowLeft className="w-5 h-5 text-slate-700" />
                </Link>
                <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                    <Settings className="w-8 h-8 text-indigo-600" />
                    System Control & Settings
                </h1>
            </div>

            {message && (
                <div className={`p-4 rounded-xl mb-6 font-bold ${message.includes('Success') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {message}
                </div>
            )}

            {loading ? (
                <div className="text-center text-slate-400 py-10">Loading Settings...</div>
            ) : (
                <form onSubmit={handleSave} className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100 max-w-4xl">

                    {/* Task Settings Section Removed - Controlled by Packages/Tiers */}


                    {/* Financial Settings Section */}
                    <div className="mb-8">
                        <h2 className="text-lg font-bold text-slate-700 border-b pb-2 mb-4 flex items-center gap-2">
                            <DollarSign className="w-5 h-5" /> Financial Controls
                        </h2>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-2">Min Withdraw Amount (NXS)</label>
                                <input
                                    type="number"
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500"
                                    value={settings.min_withdraw_amount}
                                    onChange={e => setSettings({ ...settings, min_withdraw_amount: e.target.value })}
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-2">Referral Bonus (NXS)</label>
                                <input
                                    type="number"
                                    step="0.01"
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500"
                                    value={settings.referral_bonus_amount}
                                    onChange={e => setSettings({ ...settings, referral_bonus_amount: e.target.value })}
                                    required
                                />
                                <p className="text-xs text-slate-400 mt-1">Bonus given to referrer per invite.</p>
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-2 font-sans">Referral Bonus Destination</label>
                                <select
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 font-sans"
                                    value={settings.referral_reward_currency || 'income'}
                                    onChange={e => setSettings({ ...settings, referral_reward_currency: e.target.value })}
                                >
                                    <option value="income">Income Wallet (Withdrawable)</option>
                                    <option value="purchase">Purchase Wallet (Shopping Only)</option>
                                </select>
                                <p className="text-xs text-gray-500 mt-1 font-sans">Select which wallet receives the referral bonus.</p>
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-2">Agent Cash Out Commission (%)</label>
                                <input
                                    type="number"
                                    step="0.01"
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500"
                                    value={settings.cash_out_commission_percent}
                                    onChange={e => setSettings({ ...settings, cash_out_commission_percent: e.target.value })}
                                    required
                                />
                                <p className="text-xs text-slate-400 mt-1">Extra profit % given to Agent when they process a Cash Out.</p>
                            </div>
                        </div>
                    </div>

                    {/* P2P Market Controls Section */}
                    <div className="mb-8">
                        <h2 className="text-lg font-bold text-slate-700 border-b pb-2 mb-4 flex items-center gap-2">
                            <TrendingUp className="w-5 h-5" /> P2P Market Controls
                        </h2>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-2">P2P Chart Minimum Price (NXS)</label>
                                <input
                                    type="number"
                                    step="0.01"
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500"
                                    value={settings.p2p_market_min}
                                    onChange={e => setSettings({ ...settings, p2p_market_min: e.target.value })}
                                />
                                <p className="text-xs text-slate-400 mt-1">The lowest simulated value for the P2P random chart.</p>
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-2">P2P Chart Maximum Price (NXS)</label>
                                <input
                                    type="number"
                                    step="0.01"
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500"
                                    value={settings.p2p_market_max}
                                    onChange={e => setSettings({ ...settings, p2p_market_max: e.target.value })}
                                />
                                <p className="text-xs text-slate-400 mt-1">The highest simulated value for the P2P random chart.</p>
                            </div>
                        </div>
                    </div>


                    {/* Tier & Auto-Promotion Section */}
                    <div className="mb-8">
                        <div className="flex items-center justify-between border-b pb-2 mb-4">
                            <h2 className="text-lg font-bold text-slate-700 flex items-center gap-2">
                                <Activity className="w-5 h-5" /> Referral Promotional Tiers
                            </h2>
                            <button
                                type="button"
                                onClick={handleAddTier}
                                className="flex items-center gap-1 bg-indigo-100 text-indigo-700 px-3 py-1.5 rounded-lg text-sm font-bold hover:bg-indigo-200 transition shadow-sm"
                            >
                                <Plus className="w-4 h-4" /> Add Tier
                            </button>
                        </div>

                        <div className="space-y-4">
                            {(settings.referral_tiers || []).map((tier, index) => (
                                <div key={index} className="flex flex-col md:flex-row gap-4 bg-slate-50 p-4 rounded-xl border border-slate-200 items-start md:items-center relative group shadow-sm transition-all hover:border-indigo-300">
                                    <div className="w-full md:w-1/3">
                                        <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1 ml-1">Tier Name</label>
                                        <input
                                            type="text"
                                            className="w-full p-2.5 bg-white rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-slate-800"
                                            placeholder="e.g. Gold"
                                            value={tier.name}
                                            onChange={e => handleUpdateTier(index, 'name', e.target.value)}
                                            required
                                        />
                                    </div>
                                    <div className="w-full md:w-1/3">
                                        <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1 ml-1">Target Referrals</label>
                                        <input
                                            type="number"
                                            className="w-full p-2.5 bg-white rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 font-mono text-slate-800"
                                            value={tier.targetReferrals}
                                            onChange={e => handleUpdateTier(index, 'targetReferrals', parseInt(e.target.value) || 0)}
                                            required
                                        />
                                    </div>
                                    <div className="w-full md:w-1/3">
                                        <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1 ml-1">Bonus Reward (NXS)</label>
                                        <input
                                            type="number"
                                            step="0.01"
                                            className="w-full p-2.5 bg-white rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 font-mono text-emerald-600 font-black"
                                            value={tier.bonusAmount}
                                            onChange={e => handleUpdateTier(index, 'bonusAmount', parseFloat(e.target.value) || 0)}
                                            required
                                        />
                                    </div>
                                    <button
                                        type="button"
                                        onClick={() => handleRemoveTier(index)}
                                        className="absolute -top-3 -right-3 md:top-auto md:right-0 md:relative p-2 bg-white text-red-500 border border-red-200 rounded-full hover:bg-red-500 hover:text-white hover:border-red-500 transition shadow-sm md:ml-2"
                                        title="Remove Tier"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            ))}
                            {(!settings.referral_tiers || settings.referral_tiers.length === 0) && (
                                <div className="text-center p-8 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl">
                                    <Activity className="w-8 h-8 text-slate-300 mx-auto mb-2" />
                                    <p className="text-slate-500 font-medium">No promotional tiers created.</p>
                                    <p className="text-sm text-slate-400">Click "Add Tier" to start rewarding your top inviters.</p>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="flex justify-end pt-4">
                        <button
                            type="submit"
                            disabled={saving}
                            className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg disabled:opacity-50 flex items-center gap-2"
                        >
                            <Save className="w-5 h-5" />
                            {saving ? 'Saving...' : 'Update Settings'}
                        </button>
                    </div>
                </form>
            )}
        </div>
    );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import api from '../../../services/api';
import Link from 'next/link';
import { ArrowLeft, MessageSquare, Reply, CheckCircle, Search, RefreshCw, Send, CheckCircle2, Ticket, LifeBuoy } from 'lucide-react';
import toast from 'react-hot-toast';

export default function AdminSupportPage() {
    const [tickets, setTickets] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTicket, setActiveTicket] = useState(null);
    const [replyMessage, setReplyMessage] = useState('');
    const [sending, setSending] = useState(false);
    const [filter, setFilter] = useState('all'); // all, open, answered, closed

    const chatEndRef = useRef(null);

    useEffect(() => {
        fetchTickets();

        // Auto-refresh interval for live tickets 
        const interval = setInterval(() => {
            fetchTickets(false);
        }, 15000); // 15s polling

        return () => clearInterval(interval);
    }, []);

    useEffect(() => {
        if (activeTicket) {
            chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
    }, [activeTicket?.messages]);

    const fetchTickets = async (showLoad = true) => {
        if (showLoad) setLoading(true);
        try {
            const res = await api.get('/support/all');
            setTickets(res.data);

            // Sync active ticket
            if (activeTicket) {
                const updated = res.data.find(t => t._id === activeTicket._id);
                if (updated) setActiveTicket(updated);
            }
        } catch (err) {
            console.error(err);
        } finally {
            if (showLoad) setLoading(false);
        }
    };

    const handleReply = async (e) => {
        e.preventDefault();
        if (!activeTicket || !replyMessage.trim()) return;

        setSending(true);
        try {
            const res = await api.post('/support/reply', {
                messageId: activeTicket._id,
                reply: replyMessage
            });

            // Optimistically update
            setActiveTicket(res.data.support);
            setReplyMessage('');
            fetchTickets(false);
        } catch (err) {
            toast.error('Failed to send reply');
        } finally {
            setSending(false);
        }
    };

    const filteredTickets = tickets.filter(t => {
        if (filter === 'all') return true;
        return t.status === filter;
    });

    return (
        <div className="min-h-screen bg-slate-50 font-sans pb-20">
            {/* Header */}
            <div className="bg-white sticky top-0 z-20 shadow-sm border-b border-slate-100 px-4 py-4 md:px-8">
                <div className="max-w-5xl mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Link href="/admin/dashboard" className="p-2.5 hover:bg-slate-100 rounded-xl transition border border-slate-200 text-slate-600">
                            <ArrowLeft className="w-5 h-5" />
                        </Link>
                        <div>
                            <h1 className="text-xl font-bold text-slate-800">Support Tickets</h1>
                            <p className="text-xs text-slate-500 font-medium">Manage User Queries</p>
                        </div>
                    </div>
                    <button
                        onClick={fetchTickets}
                        className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100 transition active:scale-95 flex items-center gap-2 font-bold text-xs"
                    >
                        <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                        <span className="hidden md:inline">Reload</span>
                    </button>
                </div>
            </div>

            <div className="max-w-7xl mx-auto p-4 md:p-8 flex flex-col md:flex-row gap-6 h-[calc(100vh-100px)]">

                {/* Left Side: Tickets List */}
                <div className={`w-full ${activeTicket ? 'hidden md:flex md:w-1/3' : 'md:w-1/3'} flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden relative`}>

                    {/* Filters */}
                    <div className="p-4 border-b border-slate-100 bg-slate-50 flex gap-2 overflow-x-auto scrollbar-hide shrink-0">
                        {['all', 'open', 'answered', 'closed'].map(f => (
                            <button
                                key={f}
                                onClick={() => setFilter(f)}
                                className={`px-4 py-2 rounded-xl text-[10px] font-bold uppercase transition flex-shrink-0 ${filter === f
                                    ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200'
                                    : 'bg-white text-slate-500 border border-slate-200 hover:bg-slate-50'
                                    }`}
                            >
                                {f}
                            </button>
                        ))}
                    </div>

                    {/* List */}
                    <div className="flex-1 overflow-y-auto p-2 scrollbar-hide">
                        {loading && tickets.length === 0 ? (
                            <div className="space-y-2 p-2">
                                {[1, 2, 3].map(i => <div key={i} className="h-20 bg-slate-50 rounded-xl animate-pulse"></div>)}
                            </div>
                        ) : filteredTickets.length === 0 ? (
                            <div className="text-center py-20">
                                <MessageSquare className="w-8 h-8 text-slate-300 mx-auto mb-3" />
                                <p className="text-slate-400 font-bold text-sm">No tickets found</p>
                            </div>
                        ) : (
                            <div className="space-y-1">
                                {filteredTickets.map(ticket => (
                                    <div
                                        key={ticket._id}
                                        onClick={() => setActiveTicket(ticket)}
                                        className={`p-4 rounded-xl cursor-pointer transition border-l-4 ${activeTicket?._id === ticket._id ? 'bg-indigo-50 border-indigo-600' : 'bg-white border-transparent hover:bg-slate-50 border-b border-b-slate-100'}`}
                                    >
                                        <div className="flex justify-between items-start mb-1">
                                            <div className="flex items-center gap-2">
                                                <span className={`w-2 h-2 rounded-full ${ticket.status === 'open' ? 'bg-amber-500 animate-pulse' : ticket.status === 'answered' ? 'bg-green-500' : 'bg-slate-300'}`}></span>
                                                <span className="text-[10px] font-bold text-slate-700">{ticket.userId?.fullName || 'User'}</span>
                                            </div>
                                            <span className="text-[9px] text-slate-400 font-medium">{new Date(ticket.createdAt).toLocaleDateString()}</span>
                                        </div>
                                        <h3 className="font-bold text-slate-800 text-xs mb-1 line-clamp-1">{ticket.subject}</h3>
                                        <p className="text-[10px] text-slate-500 line-clamp-1">
                                            {ticket.messages && ticket.messages.length > 0 ? ticket.messages[ticket.messages.length - 1].text : ticket.message}
                                        </p>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {/* Right Side: Active Chat Window */}
                <div className={`w-full ${!activeTicket ? 'hidden md:flex md:items-center md:justify-center md:w-2/3 md:bg-white md:rounded-2xl md:border md:border-slate-200' : 'flex flex-col md:w-2/3 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden'}`}>

                    {!activeTicket ? (
                        <div className="text-center">
                            <Ticket className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                            <h2 className="text-lg font-bold text-slate-400">Select a Ticket to Reply</h2>
                        </div>
                    ) : (
                        <>
                            {/* Chat Header */}
                            <div className="p-4 border-b border-slate-100 bg-white flex items-center gap-4 shrink-0">
                                <button className="md:hidden p-2 bg-slate-50 rounded-full" onClick={() => setActiveTicket(null)}>
                                    <ArrowLeft className="w-5 h-5 text-slate-700" />
                                </button>
                                <div>
                                    <h2 className="font-bold text-slate-800 text-sm">{activeTicket.subject}</h2>
                                    <p className="text-xs text-slate-500 flex items-center gap-2">
                                        {activeTicket.userId?.fullName} <span className="text-slate-300">•</span> {activeTicket.userId?.phone}
                                    </p>
                                </div>
                                <div className="ml-auto">
                                    <span className={`px-3 py-1 bg-slate-100 rounded-full text-[10px] font-bold uppercase ${activeTicket.status === 'open' ? 'text-amber-600' : 'text-green-600'}`}>
                                        {activeTicket.status}
                                    </span>
                                </div>
                            </div>

                            {/* Messages Container */}
                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/50">
                                {activeTicket.messages?.map((msg, idx) => {
                                    const isAdmin = msg.senderRole === 'admin';
                                    return (
                                        <div key={idx} className={`flex ${isAdmin ? 'justify-end' : 'justify-start'}`}>
                                            {!isAdmin && (
                                                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center mr-2 flex-shrink-0 mt-auto mb-1">
                                                    <span className="text-xs font-bold text-slate-600">U</span>
                                                </div>
                                            )}
                                            <div className={`max-w-[75%] rounded-2xl px-4 py-3 ${isAdmin ? 'bg-indigo-600 text-white rounded-br-none shadow-md shadow-indigo-200' : 'bg-white text-slate-800 rounded-bl-none border border-slate-200 shadow-sm'}`}>
                                                <p className="text-sm whitespace-pre-wrap leading-relaxed">{msg.text}</p>
                                                <div className={`text-[9px] mt-1.5 font-medium flex items-center justify-end gap-1 ${isAdmin ? 'text-indigo-200' : 'text-slate-400'}`}>
                                                    {new Date(msg.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                                    {isAdmin && <CheckCircle2 className="w-3 h-3" />}
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                                {/* Legacy String Fallbacks */}
                                {(activeTicket.message && !activeTicket.messages?.length) && (
                                    <div className="flex justify-start">
                                        <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center mr-2 flex-shrink-0 mt-auto mb-1">
                                            <span className="text-xs font-bold text-slate-600">U</span>
                                        </div>
                                        <div className="max-w-[75%] rounded-2xl px-4 py-3 bg-white text-slate-800 rounded-bl-none border border-slate-200 shadow-sm">
                                            <p className="text-sm">{activeTicket.message}</p>
                                        </div>
                                    </div>
                                )}
                                {(activeTicket.adminReply && !activeTicket.messages?.length) && (
                                    <div className="flex justify-end">
                                        <div className="max-w-[75%] rounded-2xl px-4 py-3 bg-indigo-600 text-white rounded-br-none shadow-md shadow-indigo-200">
                                            <p className="text-sm">{activeTicket.adminReply}</p>
                                        </div>
                                    </div>
                                )}
                                <div ref={chatEndRef} />
                            </div>

                            {/* Chat Input */}
                            <div className="p-4 border-t border-slate-100 bg-white shrink-0">
                                <form onSubmit={handleReply} className="flex gap-2 relative">
                                    <textarea
                                        value={replyMessage}
                                        onChange={(e) => setReplyMessage(e.target.value)}
                                        placeholder="Type an official response..."
                                        className="w-full pl-5 pr-14 py-4 bg-slate-50 border border-slate-200 rounded-2xl h-14 resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500/20 font-medium text-sm text-slate-800"
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter' && !e.shiftKey) {
                                                e.preventDefault();
                                                handleReply(e);
                                            }
                                        }}
                                    ></textarea>
                                    <button
                                        type="submit"
                                        disabled={!replyMessage.trim() || sending}
                                        className="absolute right-2 top-2 bottom-2 aspect-square bg-indigo-600 text-white rounded-xl flex items-center justify-center transition hover:bg-indigo-700 active:scale-95 disabled:bg-slate-300"
                                    >
                                        {sending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Send className="w-4 h-4 ml-0.5" />}
                                    </button>
                                </form>
                                <p className="text-[9px] text-slate-400 mt-2 text-center font-medium">Press Enter to send, Shift+Enter for new line.</p>
                            </div>
                        </>
                    )}
                </div>

            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import api from '../../../services/api';
import { Plus, Trash2, ExternalLink, Image as ImageIcon, ArrowLeft, Pencil, X } from 'lucide-react';
import toast from 'react-hot-toast';
import ConfirmationModal from '../../../components/ui/ConfirmationModal';

export default function AdminTasksPage() {
    const [ads, setAds] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showForm, setShowForm] = useState(false);
    const [editId, setEditId] = useState(null); // [NEW] Track Edit Mode
    const [plans, setPlans] = useState([]); // [NEW] Plan List for Dropdown
    const [confirmModal, setConfirmModal] = useState({ isOpen: false });

    // Form State
    const [formData, setFormData] = useState({
        title: '',
        imageUrl: '',
        url: '',
        duration: 15,
        type: 'ad_view'
    });
    const [submitting, setSubmitting] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchAds();
    }, []);

    const fetchAds = async () => {
        try {
            const res = await api.get('/admin/task-ad');
            setAds(res.data);
            setLoading(false);
        } catch (err) {
            console.error(err);
            setLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            const payload = { ...formData };

            if (editId) {
                await api.put(`/admin/task-ad/${editId}`, payload);
                setMessage('Task Ad Updated Successfully!');
            } else {
                await api.post('/admin/task-ad', payload);
                setMessage('Task Ad Created Successfully!');
            }

            setFormData({ title: '', imageUrl: '', url: '', duration: 15, type: 'ad_view' });
            setEditId(null); // Reset
            setShowForm(false);
            fetchAds();
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            console.error(err);
            setMessage('Failed to save ad.');
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = (id) => {
        setConfirmModal({
            isOpen: true,
            title: 'Delete Ad',
            message: 'Are you sure you want to delete this ad?',
            confirmText: 'Delete',
            onConfirm: async () => {
                try {
                    await api.delete(`/admin/task-ad/${id}`);
                    setAds(ads.filter(ad => (ad._id || ad.id) !== id));
                    toast.success('Ad deleted');
                    setConfirmModal({ isOpen: false });
                } catch (err) {
                    console.error(err);
                    toast.error('Failed to delete ad');
                }
            }
        });
    };

    return (
        <div className="bg-slate-50 min-h-screen p-8">
            <div className="flex justify-between items-center mb-8">
                <div className="flex items-center gap-4">
                    <Link href="/admin/dashboard" className="p-2 bg-white rounded-xl shadow-sm hover:shadow-md transition text-slate-600">
                        <ArrowLeft size={20} />
                    </Link>
                    <div>
                        <h1 className="text-2xl font-black text-slate-800">Task Management</h1>
                        <p className="text-slate-500 text-sm">Create and manage task advertisements</p>
                    </div>
                </div>
                <button
                    onClick={() => { setShowForm(!showForm); setEditId(null); setFormData({ title: '', imageUrl: '', url: '', duration: 15, type: 'ad_view' }); }}
                    className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-200"
                >
                    {showForm ? <X size={20} /> : <Plus size={20} />}
                    {showForm ? 'Close' : 'Add New Task'}
                </button>
            </div>

            {message && (
                <div className="bg-emerald-100 text-emerald-700 p-4 rounded-xl mb-6 border border-emerald-200 font-medium animate-in fade-in slide-in-from-top-2">
                    {message}
                </div>
            )}

            {/* Add/Edit Form */}
            {showForm && (
                <div className="bg-white p-6 rounded-2xl shadow-lg border border-slate-100 mb-8 animate-in slide-in-from-top-4">
                    <h2 className="text-lg font-bold mb-4">{editId ? 'Edit Task Ad' : 'Create New Task Ad'}</h2>
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Task Title</label>
                                <input
                                    type="text"
                                    value={formData.title}
                                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                    className="w-full text-slate-900 bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:border-indigo-500 placeholder-slate-400"
                                    placeholder="e.g. Visit Partner Site"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Target URL</label>
                                <input
                                    type="url"
                                    value={formData.url}
                                    onChange={(e) => setFormData({ ...formData, url: e.target.value })}
                                    className="w-full text-slate-900 bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:border-indigo-500 placeholder-slate-400"
                                    placeholder="https://example.com"
                                    required
                                />
                            </div>
                        </div>

                        {/* Image URL */}
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Image URL (Optional)</label>
                            <div className="flex gap-2">
                                <div className="p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-400">
                                    <ImageIcon size={20} />
                                </div>
                                <input
                                    type="url"
                                    value={formData.imageUrl}
                                    onChange={(e) => setFormData({ ...formData, imageUrl: e.target.value })}
                                    className="w-full text-slate-900 bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:border-indigo-500 placeholder-slate-400"
                                    placeholder="https://example.com/image.jpg"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Duration (Sec)</label>
                                <input
                                    type="number"
                                    value={formData.duration}
                                    onChange={(e) => setFormData({ ...formData, duration: e.target.value })}
                                    className="w-full text-slate-900 bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:border-indigo-500 placeholder-slate-400"
                                    min="5"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Type</label>
                                <select
                                    value={formData.type}
                                    onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                                    className="w-full text-slate-900 bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:border-indigo-500"
                                >
                                    <option value="ad_view">Ad Visit</option>
                                    <option value="video">Video Stream</option>
                                    <option value="review">Product Review</option>
                                </select>
                            </div>
                        </div>

                        <div className="flex justify-end gap-3 pt-4 border-t border-slate-100">
                            <button
                                type="button"
                                onClick={() => { setShowForm(false); setEditId(null); }}
                                className="px-6 py-2 rounded-xl font-bold text-slate-500 hover:bg-slate-100 transition"
                            >
                                Cancel
                            </button>
                            <button
                                type="submit"
                                disabled={submitting}
                                className="bg-indigo-600 text-white px-8 py-2 rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg disabled:opacity-50"
                            >
                                {submitting ? 'Saving...' : (editId ? 'Update Ad' : 'Create Ad')}
                            </button>
                        </div>
                    </form>
                </div>
            )}

            {/* List */}
            {loading ? (
                <div className="text-center py-10 text-slate-400">Loading Ads...</div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {ads.map(ad => (
                        <div key={ad._id || ad.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden group hover:shadow-lg transition">
                            <div className="h-48 overflow-hidden relative">
                                <img
                                    src={ad.imageUrl || "https://images.unsplash.com/photo-1617704548623-340376564e68?auto=format&fit=crop&q=80&w=800"}
                                    alt={ad.title}
                                    className="w-full h-full object-cover group-hover:scale-105 transition duration-500"
                                />
                            </div>
                            <div className="p-4">
                                <h3 className="font-bold text-lg text-slate-800 mb-1 truncate">{ad.title}</h3>
                                <div className="flex gap-2 mb-3">
                                    <span className="bg-slate-100 text-slate-600 px-2 py-0.5 rounded text-xs font-mono">{ad.duration}s</span>
                                    <span className="bg-blue-100 text-blue-600 px-2 py-0.5 rounded text-xs uppercase">{ad.type}</span>
                                </div>
                            </div>
                            <div className="flex justify-between items-center border-t border-slate-50 pt-3">
                                <a
                                    href={ad.url}
                                    target="_blank"
                                    className="text-indigo-500 text-sm font-bold flex items-center gap-1 hover:underline"
                                >
                                    <ExternalLink className="w-4 h-4" /> Link
                                </a>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => {
                                            setFormData({
                                                title: ad.title,
                                                imageUrl: ad.imageUrl || '',
                                                url: ad.url,
                                                duration: ad.duration,
                                                type: ad.type,
                                                priority: ad.priority,
                                                valid_plan_id: (ad.valid_plans && ad.valid_plans.length > 0) ? ad.valid_plans[0] : ''
                                            });
                                            setEditId(ad._id || ad.id);
                                            setShowForm(true);
                                            window.scrollTo({ top: 0, behavior: 'smooth' });
                                        }}
                                        className="text-amber-400 hover:text-amber-600 p-2 hover:bg-amber-50 rounded-lg transition"
                                    >
                                        <Pencil className="w-5 h-5" />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(ad._id || ad.id)}
                                        className="text-red-400 hover:text-red-600 p-2 hover:bg-red-50 rounded-lg transition"
                                    >
                                        <Trash2 className="w-5 h-5" />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}

                    {ads.length === 0 && (
                        <div className="col-span-full py-12 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-300">
                            <ImageIcon className="w-12 h-12 text-slate-300 mx-auto mb-2" />
                            <p className="text-slate-500 font-medium">No Ads Found</p>
                            <p className="text-sm text-slate-400">Click "Add New Ad" to create one.</p>
                        </div>
                    )}
                </div>
            )}

            {/* Confirmation Modal */}
            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                onConfirm={confirmModal.onConfirm}
                title={confirmModal.title}
                message={confirmModal.message}
                confirmText={confirmModal.confirmText}
            />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { ArrowLeft, Search, RefreshCw, ShieldAlert, Monitor, Globe, CheckCircle, Ban, Filter, Copy } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import api from '../../../services/api';

export default function DeviceTrackingPage() {
    const router = useRouter();
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [filter, setFilter] = useState('all'); // all, duplicate, whitelisted, blocked

    useEffect(() => {
        fetchUsers();
    }, []);

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const res = await api.get('/admin/users'); // Ensure backend returns deviceId, lastIp
            setUsers(res.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    // --- Logic to Find Duplicates ---
    const getDuplicateDeviceIds = () => {
        const counts = {};
        users.forEach(u => {
            if (u.deviceId) {
                counts[u.deviceId] = (counts[u.deviceId] || 0) + 1;
            }
        });
        return Object.keys(counts).filter(id => counts[id] > 1);
    };

    const duplicateIds = getDuplicateDeviceIds();

    // --- Filter Logic ---
    const filteredUsers = users.filter(user => {
        const matchesSearch =
            user.fullName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            user.phone?.includes(searchTerm) ||
            user.deviceId?.includes(searchTerm) ||
            user.lastIp?.includes(searchTerm);

        if (!matchesSearch) return false;

        if (filter === 'duplicate') return duplicateIds.includes(user.deviceId);
        if (filter === 'whitelisted') return user.isDeviceWhitelisted;
        if (filter === 'blocked') return user.status === 'blocked';

        return true;
    });

    const copyToClipboard = (text) => {
        navigator.clipboard.writeText(text);
        // Toast could be added here
    };

    return (
        <div className="min-h-screen bg-slate-50 font-sans pb-20">
            {/* Header */}
            <div className="bg-[#0f172a] text-white p-5 pt-8 md:p-6 md:pb-12 rounded-b-[2rem] shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-full opacity-20 bg-[url('https://grainy-gradients.vercel.app/noise.svg')]"></div>

                <div className="relative z-10 max-w-7xl mx-auto mb-6 flex items-center justify-between">
                    <button onClick={() => router.push('/admin/dashboard')} className="w-10 h-10 bg-white/10 rounded-full flex items-center justify-center backdrop-blur-md hover:bg-white/20 transition">
                        <ArrowLeft className="w-5 h-5 text-white" />
                    </button>
                    <h1 className="text-xl font-bold">Device Tracking</h1>
                    <button onClick={fetchUsers} className="w-10 h-10 bg-white/10 rounded-full flex items-center justify-center backdrop-blur-md hover:bg-white/20 transition">
                        <RefreshCw className={`w-5 h-5 text-white ${loading ? 'animate-spin' : ''}`} />
                    </button>
                </div>

                {/* Search & Filter Bar */}
                <div className="relative z-10 max-w-7xl mx-auto flex flex-col md:flex-row gap-3">
                    <div className="flex-1 relative">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                        <input
                            type="text"
                            placeholder="Search Name, Phone, IP, Device ID..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-white/10 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-sm text-white placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-rose-500/50"
                        />
                    </div>

                    <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 hide-scrollbar">
                        {['all', 'duplicate', 'whitelisted', 'blocked'].map(f => (
                            <button
                                key={f}
                                onClick={() => setFilter(f)}
                                className={`px-4 py-2 rounded-xl text-xs font-bold capitalize whitespace-nowrap transition-all border ${filter === f
                                    ? 'bg-rose-500 text-white border-rose-400 shadow-lg shadow-rose-500/20'
                                    : 'bg-white/5 text-slate-300 border-white/10 hover:bg-white/10'
                                    }`}
                            >
                                {f}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* List */}
            <div className="max-w-7xl mx-auto px-5 -mt-6 relative z-20">
                <div className="flex flex-col gap-3">
                    {loading ? (
                        <div className="text-center py-20 text-slate-400">Loading tracking data...</div>
                    ) : filteredUsers.length === 0 ? (
                        <div className="text-center py-20 bg-white rounded-3xl border border-slate-200 shadow-sm">
                            <Monitor className="w-12 h-12 text-slate-200 mx-auto mb-3" />
                            <p className="text-slate-500 font-medium">No devices found matching criteria.</p>
                        </div>
                    ) : (
                        filteredUsers.map(user => {
                            const isDuplicate = duplicateIds.includes(user.deviceId);

                            return (
                                <div key={user.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-4 group hover:shadow-md transition-all">

                                    {/* User Info */}
                                    <div className="flex items-center gap-4">
                                        <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-lg font-bold shrink-0 ${isDuplicate ? 'bg-rose-100 text-rose-600' : 'bg-slate-100 text-slate-500'
                                            }`}>
                                            {user.fullName?.[0] || 'U'}
                                        </div>
                                        <div>
                                            <div className="flex items-center gap-2">
                                                <h3 className="font-bold text-slate-800">{user.fullName || 'Unknown User'}</h3>
                                                {user.isDeviceWhitelisted && (
                                                    <span className="bg-emerald-100 text-emerald-600 text-[9px] font-bold px-1.5 py-0.5 rounded uppercase border border-emerald-200">Whitelisted</span>
                                                )}
                                                {user.status === 'blocked' && (
                                                    <span className="bg-red-100 text-red-600 text-[9px] font-bold px-1.5 py-0.5 rounded uppercase border border-red-200">Blocked</span>
                                                )}
                                            </div>
                                            <p className="text-xs text-slate-500 font-mono">{user.phone}</p>
                                        </div>
                                    </div>

                                    {/* Device & IP Details */}
                                    <div className="flex flex-col md:flex-row gap-4 md:gap-8 text-sm">

                                        {/* Device ID */}
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-1">
                                                <Monitor className="w-3 h-3" /> Device ID
                                            </span>
                                            <div className="flex items-center gap-2 group/copy cursor-pointer" onClick={() => copyToClipboard(user.deviceId)}>
                                                <span className={`font-mono font-medium ${isDuplicate ? 'text-rose-500 font-bold' : 'text-slate-700'}`}>
                                                    {user.deviceId ? `${user.deviceId.substring(0, 16)}...` : 'N/A'}
                                                </span>
                                                {user.deviceId && <Copy className="w-3 h-3 text-slate-300 group-hover/copy:text-blue-500" />}
                                            </div>
                                            {isDuplicate && <span className="text-[10px] text-rose-500 font-bold flex items-center gap-1"><ShieldAlert className="w-3 h-3" /> Multi-Account Detected</span>}
                                        </div>

                                        {/* IP Address */}
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-1">
                                                <Globe className="w-3 h-3" /> IP Address
                                            </span>
                                            <span className="font-mono text-slate-700 font-medium">
                                                {user.lastIp || 'Unknown'}
                                            </span>
                                        </div>

                                    </div>

                                    {/* Action Link */}
                                    <div className="flex justify-end">
                                        <Link
                                            href={`/admin/users/detail?id=${user.id}`}
                                            className="px-4 py-2 rounded-lg bg-slate-50 text-slate-600 text-xs font-bold hover:bg-slate-100 transition border border-slate-200"
                                        >
                                            View Details
                                        </Link>
                                    </div>

                                </div>
                            );
                        })
                    )}
                </div>
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect, Suspense } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import api from '../../../../services/api';
import { ArrowLeft, CheckCircle, XCircle, DollarSign, ShieldAlert, Monitor, Globe } from 'lucide-react';
import Link from 'next/link';
import toast from 'react-hot-toast';

function UserDetailContent() {
    const searchParams = useSearchParams();
    const id = searchParams.get('id');
    const router = useRouter();
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    // Actions State
    const [balanceModal, setBalanceModal] = useState(false);
    const [amount, setAmount] = useState('');
    const [type, setType] = useState('credit');
    const [comment, setComment] = useState('');
    const [secKeys, setSecKeys] = useState(['', '', '']); // 3-Layer Security Keys
    const [actionLoading, setActionLoading] = useState(false);

    useEffect(() => {
        if (id) {
            fetchUser();
        } else {
            // If no ID, redirect back
            // router.push('/admin/users');
        }
    }, [id]);

    const fetchUser = async () => {
        try {
            const res = await api.get(`/admin/user/${id}`);
            setUser(res.data);
            setLoading(false);
        } catch (err) {
            console.error(err);
            // toast.error("Failed to load user");
            // router.push('/admin/users');
        }
    };

    const handleStatusChange = async (newStatus) => {
        try {
            await api.patch(`/admin/user/${id}/status`, { status: newStatus });
            fetchUser();
        } catch (err) {
            toast.error("Failed to update status");
        }
    };

    const toggleWhitelist = async () => {
        try {
            await api.patch(`/admin/user/${id}/whitelist`);
            fetchUser();
        } catch (err) {
            toast.error("Failed to toggle whitelist");
        }
    };

    const handleBalanceUpdate = async () => {
        if (!amount) return;

        // Require security keys for credit
        if (type === 'credit' && secKeys.some(k => !k)) {
            return toast.error("All 3 Security Keys are required to add balance.");
        }

        setActionLoading(true);
        try {
            await api.post(`/admin/user/${id}/balance`, {
                amount,
                type,
                comment,
                secKey1: secKeys[0],
                secKey2: secKeys[1],
                secKey3: secKeys[2]
            });
            setBalanceModal(false);
            setAmount('');
            setComment('');
            setSecKeys(['', '', '']);
            fetchUser();
            toast.success("Balance updated successfully");
        } catch (err) {
            toast.error(err.response?.data?.message || "Failed to update balance");
        } finally {
            setActionLoading(false);
        }
    };

    if (!id) return <div className="p-10 text-center">Invalid User ID</div>;
    if (loading) return <div className="p-10 text-center">Loading...</div>;
    if (!user) return <div className="p-10 text-center">User not found</div>;

    return (
        <div className="bg-slate-50 min-h-screen pb-20 font-sans">
            {/* Header */}
            <div className="bg-slate-900 text-white p-6 rounded-b-[2rem] shadow-lg mb-6">
                <div className="flex items-center gap-4 mb-4">
                    <Link href="/admin/users" className="p-2 bg-white/10 rounded-full hover:bg-white/20">
                        <ArrowLeft className="w-5 h-5" />
                    </Link>
                    <h1 className="text-2xl font-bold">{user.fullName}</h1>
                </div>
                <div className="flex gap-4 text-sm text-slate-400 font-mono">
                    <span>{user.phone}</span>
                    <span>|</span>
                    <span>{user.username}</span>
                </div>
            </div>

            <div className="px-4 space-y-6 max-w-4xl mx-auto">

                {/* 1. Status & Whitelist Card */}
                <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
                    <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <ShieldAlert className="w-5 h-5 text-indigo-500" /> Account Security
                    </h2>

                    <div className="flex flex-col md:flex-row gap-6">
                        {/* Status */}
                        <div className="flex-1">
                            <label className="text-xs font-bold text-slate-400 uppercase">Account Status</label>
                            <div className="flex items-center gap-2 mt-2">
                                <select
                                    value={user.status}
                                    onChange={(e) => handleStatusChange(e.target.value)}
                                    className={`w-full p-3 rounded-xl border-2 font-bold outline-none
                                        ${user.status === 'active' ? 'border-green-200 bg-green-50 text-green-700' : ''}
                                        ${user.status === 'restricted' ? 'border-orange-200 bg-orange-50 text-orange-700' : ''}
                                        ${user.status === 'blocked' ? 'border-red-200 bg-red-50 text-red-700' : ''}
                                    `}
                                >
                                    <option value="active">Active</option>
                                    <option value="restricted">Restricted</option>
                                    <option value="blocked">Blocked</option>
                                </select>
                            </div>
                        </div>

                        {/* Whitelist */}
                        <div className="flex-1">
                            <label className="text-xs font-bold text-slate-400 uppercase">Multi-Account Check</label>
                            <div className="flex items-center justify-between p-3 rounded-xl border-2 border-slate-100 mt-2">
                                <span className="text-sm font-semibold text-slate-600">
                                    {user.isDeviceWhitelisted ? 'Whitelisted (Bypassed)' : 'Protected (Standard)'}
                                </span>
                                <button
                                    onClick={toggleWhitelist}
                                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${user.isDeviceWhitelisted ? 'bg-green-500' : 'bg-slate-300'}`}
                                >
                                    <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${user.isDeviceWhitelisted ? 'translate-x-6' : 'translate-x-1'}`} />
                                </button>
                            </div>
                            <p className="text-[10px] text-slate-400 mt-1">If enabled, this device can create unlimited accounts.</p>
                        </div>
                    </div>
                </div>

                {/* 2. Device Fingerprint */}
                <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
                    <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <Monitor className="w-5 h-5 text-blue-500" /> Device Intelligence
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="p-4 bg-slate-50 rounded-2xl">
                            <div className="text-xs text-slate-400 uppercase font-bold mb-1">Device ID (Fingerprint)</div>
                            <div className="font-mono text-sm text-slate-700 break-all">{user.deviceId || 'Not Captured'}</div>
                        </div>
                        <div className="p-4 bg-slate-50 rounded-2xl">
                            <div className="text-xs text-slate-400 uppercase font-bold mb-1 flex items-center gap-1">
                                <Globe className="w-3 h-3" /> Last Known IP
                            </div>
                            <div className="font-mono text-sm text-slate-700">{user.lastIp || 'Unknown'}</div>
                        </div>
                    </div>
                </div>

                {/* 3. Financials */}
                <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
                    <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <DollarSign className="w-5 h-5 text-emerald-500" /> Financial Control
                    </h2>

                    <div className="flex items-center justify-between p-4 bg-emerald-50 rounded-2xl border border-emerald-100 mb-4">
                        <div>
                            <div className="text-xs text-emerald-600 font-bold uppercase">Main Balance</div>
                            <div className="text-2xl font-black text-emerald-800">${user.wallet?.main?.toFixed(2) || '0.00'}</div>
                        </div>
                        <button
                            onClick={() => setBalanceModal(true)}
                            className="px-4 py-2 bg-emerald-600 text-white text-sm font-bold rounded-lg hover:bg-emerald-700 transition shadow-lg shadow-emerald-200"
                        >
                            Adjust Balance
                        </button>
                    </div>

                    <div className="grid grid-cols-3 gap-2 text-center">
                        <div className="p-2 bg-slate-50 rounded-xl">
                            <div className="text-[10px] text-slate-400">Income</div>
                            <div className="font-bold">${user.wallet?.income?.toFixed(2)}</div>
                        </div>
                        <div className="p-2 bg-slate-50 rounded-xl">
                            <div className="text-[10px] text-slate-400">Game</div>
                            <div className="font-bold">${user.wallet?.game?.toFixed(2)}</div>
                        </div>
                        <div className="p-2 bg-slate-50 rounded-xl">
                            <div className="text-[10px] text-slate-400">Purchase</div>
                            <div className="font-bold">${user.wallet?.purchase?.toFixed(2)}</div>
                        </div>
                    </div>
                </div>

            </div>

            {/* Balance Modal */}
            {balanceModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
                    <div className="bg-white w-full max-w-sm rounded-[2rem] p-6 shadow-2xl animate-in zoom-in-95">
                        <h3 className="text-xl font-bold text-slate-800 mb-4">Adjust Balance</h3>

                        <div className="flex gap-2 mb-4 p-1 bg-slate-100 rounded-xl">
                            <button
                                onClick={() => setType('credit')}
                                className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${type === 'credit' ? 'bg-white shadow text-green-600' : 'text-slate-500'}`}
                            >
                                Credit (+)
                            </button>
                            <button
                                onClick={() => setType('debit')}
                                className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${type === 'debit' ? 'bg-white shadow text-red-600' : 'text-slate-500'}`}
                            >
                                Debit (-)
                            </button>
                        </div>

                        <input
                            type="number"
                            placeholder="Amount"
                            value={amount}
                            onChange={e => setAmount(e.target.value)}
                            className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-bold mb-3 text-lg outline-none focus:ring-2 focus:ring-indigo-500"
                        />

                        <textarea
                            placeholder="Admin Comment (Reason)"
                            value={comment}
                            onChange={e => setComment(e.target.value)}
                            className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500 resize-none h-24"
                        />

                        {/* 3-Layer Security (Only required for Credit) */}
                        {type === 'credit' && (
                            <div className="bg-red-50 border border-red-200 p-4 rounded-xl mb-6">
                                <h4 className="text-red-600 font-bold text-xs uppercase tracking-wider mb-3 flex items-center gap-2">
                                    <ShieldAlert className="w-4 h-4" /> Security Authorization
                                </h4>
                                <div className="space-y-2">
                                    {[0, 1, 2].map((i) => (
                                        <input
                                            key={i}
                                            type="password"
                                            placeholder={`Secret Key ${i + 1}`}
                                            value={secKeys[i]}
                                            onChange={(e) => {
                                                const newKeys = [...secKeys];
                                                newKeys[i] = e.target.value;
                                                setSecKeys(newKeys);
                                            }}
                                            className="w-full bg-white border border-red-200 rounded-lg px-3 py-2 text-center tracking-[0.3em] font-bold text-red-700 outline-none focus:ring-2 focus:ring-red-400"
                                        />
                                    ))}
                                </div>
                            </div>
                        )}

                        <div className="flex gap-3">
                            <button onClick={() => setBalanceModal(false)} className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-100 rounded-xl">Cancel</button>
                            <button
                                onClick={handleBalanceUpdate}
                                disabled={actionLoading || (type === 'credit' && secKeys.some(k => !k))}
                                className="flex-1 py-3 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {actionLoading ? 'Processing...' : 'Confirm'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

export default function UserDetailPage() {
    return (
        <Suspense fallback={<div className="p-10 text-center">Loading...</div>}>
            <UserDetailContent />
        </Suspense>
    );
}

"use client";
import AdminLayout from '../layout';
import UserManagement from '../../../components/UserManagement';

export default function AdminUsersPage() {
    return (
        <div className="min-h-screen bg-black text-white p-4 pb-24">
            <h1 className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-500 mb-6">
                User Database
            </h1>
            <UserManagement />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../../services/api';
import { Check, X, Clock, Wallet, User } from 'lucide-react';
import toast from 'react-hot-toast';
import ConfirmationModal from '../../../components/ui/ConfirmationModal';

export default function AdminWithdrawals() {
    const [requests, setRequests] = useState([]);
    const [agents, setAgents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState(null);
    const [selectedAgents, setSelectedAgents] = useState({}); // { [reqId]: agentId }
    const [confirmModal, setConfirmModal] = useState({ isOpen: false });

    useEffect(() => {
        fetchRequests();
        fetchAgents();
    }, []);

    const fetchRequests = async () => {
        try {
            const res = await api.get('/withdrawal/list?status=pending');
            setRequests(res.data);
            setLoading(false);
        } catch (err) {
            console.error(err);
            setLoading(false);
        }
    };

    const fetchAgents = async () => {
        try {
            const res = await api.get('/admin/agents'); // Using admin route to get full list
            setAgents(res.data || []);
        } catch (err) {
            console.error("Failed to fetch agents", err);
        }
    };

    const handleAction = (id, status) => {
        const agentId = selectedAgents[id];

        let message = `Are you sure you want to ${status} this request?`;
        if (status === 'completed' && !agentId) {
            message = "No Agent Selected! Are you sure you want to approve without assigning an Agent? (System funds will be used directly)";
        }

        setConfirmModal({
            isOpen: true,
            title: status === 'completed' ? 'Approve Withdrawal' : 'Reject Withdrawal',
            message: message,
            confirmText: status === 'completed' ? 'Approve' : 'Reject',
            onConfirm: async () => {
                setActionLoading(id);
                try {
                    await api.post('/withdrawal/process', {
                        transactionId: id,
                        status: status,
                        adminComment: status === 'completed' ? 'Approved by Admin' : 'Rejected by Admin',
                        agentId: status === 'completed' ? agentId : null
                    });
                    setRequests(requests.filter(r => r.id !== id));
                    toast.success(`Request ${status} successfully`);
                    setConfirmModal({ isOpen: false });
                } catch (err) {
                    toast.error(err.response?.data?.message || 'Action failed');
                } finally {
                    setActionLoading(null);
                }
            }
        });
    };

    const handleAgentSelect = (reqId, agentId) => {
        setSelectedAgents(prev => ({
            ...prev,
            [reqId]: agentId
        }));
    };

    if (loading) return <div className="p-10 text-center">Loading Requests...</div>;

    return (
        <div className="p-6 pb-24 font-sans text-gray-800">
            <h1 className="text-2xl font-bold mb-6 text-slate-800">Withdrawal Requests</h1>

            {requests.length === 0 ? (
                <div className="text-center py-10 text-gray-400 bg-white rounded-2xl border border-dashed border-gray-200">
                    <p>No pending requests.</p>
                </div>
            ) : (
                <div className="space-y-4">
                    {requests.map((req) => (
                        <div key={req.id} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex flex-col gap-3 relative overflow-hidden">
                            {/* Status Indicator */}
                            <div className="absolute top-0 left-0 w-1 h-full bg-orange-400"></div>

                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-bold text-lg text-slate-800">$ {Math.abs(req.amount).toLocaleString()}</h3>
                                    <p className="text-sm text-gray-500 flex items-center gap-1">
                                        <Wallet className="w-3 h-3" /> {req.description}
                                    </p>
                                    {/* [NEW] Delay & Net Payout */}
                                    <div className="mt-1 flex gap-2">
                                        <span className="text-[10px] bg-slate-100 px-1.5 py-0.5 rounded text-slate-600 font-bold border border-slate-200">
                                            {req.metadata?.deliveryTime || '24h'}
                                        </span>
                                        <span className="text-[10px] bg-emerald-50 px-1.5 py-0.5 rounded text-emerald-700 font-bold border border-emerald-200">
                                            Net: $ {(Math.abs(req.amount) - (req.fee || 0)).toLocaleString()}
                                        </span>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <span className="text-xs font-bold text-orange-500 bg-orange-50 px-2 py-1 rounded-lg">PENDING</span>
                                    <p className="text-[10px] text-gray-400 mt-1">
                                        {new Date(req.createdAt).toLocaleDateString()}
                                    </p>
                                </div>
                            </div>

                            <div className="bg-gray-50 p-3 rounded-xl text-sm text-gray-600 font-mono">
                                {req.recipientDetails}
                            </div>

                            <div className="flex items-center gap-2 mt-2">
                                <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-xs font-bold text-gray-600">
                                    {req.User?.username?.[0]?.toUpperCase()}
                                </div>
                                <div className="flex-1">
                                    <p className="text-sm font-bold text-slate-700">{req.User?.fullName}</p>
                                    <p className="text-xs text-gray-500">{req.User?.phone}</p>
                                </div>
                            </div>

                            {/* Agent Selection Dropdown */}
                            <div className="mt-2">
                                <label className="text-xs font-bold text-gray-500 mb-1 block">Assign Agent (for Payout)</label>
                                <div className="relative">
                                    <select
                                        className="w-full p-2 text-sm border border-gray-200 rounded-lg appearance-none bg-white"
                                        value={selectedAgents[req.id] || ''}
                                        onChange={(e) => handleAgentSelect(req.id, e.target.value)}
                                    >
                                        <option value="">-- Select Agent --</option>
                                        {agents.map(agent => (
                                            <option key={agent.id} value={agent.id}>
                                                {agent.username} ({agent.phone}) - Bal: {agent.Wallet?.balance || 0}
                                            </option>
                                        ))}
                                    </select>
                                    <User className="w-4 h-4 text-gray-400 absolute right-3 top-2.5 pointer-events-none" />
                                </div>
                            </div>

                            <div className="flex gap-3 mt-2 border-t border-gray-100 pt-3">
                                <button
                                    onClick={() => handleAction(req.id, 'completed')}
                                    disabled={actionLoading === req.id}
                                    className="flex-1 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl font-bold text-sm flex items-center justify-center gap-2 active:scale-95 transition disabled:opacity-50"
                                >
                                    <Check className="w-4 h-4" /> Approve
                                </button>
                                <button
                                    onClick={() => handleAction(req.id, 'rejected')}
                                    disabled={actionLoading === req.id}
                                    className="flex-1 py-3 bg-red-500 hover:bg-red-600 text-white rounded-xl font-bold text-sm flex items-center justify-center gap-2 active:scale-95 transition disabled:opacity-50"
                                >
                                    <X className="w-4 h-4" /> Reject
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
            {/* Confirmation Modal */}
            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                onConfirm={confirmModal.onConfirm}
                title={confirmModal.title}
                message={confirmModal.message}
                confirmText={confirmModal.confirmText}
            />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import api from '../../../services/api';
import { Wallet, ArrowUpRight, ArrowDownLeft, History, RefreshCcw, Bell, LogOut, ChevronRight, Check, X, Copy } from 'lucide-react';
import AdminBottomNav from '../../../components/AdminBottomNav';
import ImageSlider from '../../../components/ImageSlider';
import { motion, AnimatePresence } from 'framer-motion';
import { useRouter } from 'next/navigation';
import toast from 'react-hot-toast';

export default function AgentDashboard() {
    const router = useRouter();
    const [stats, setStats] = useState({
        currentBalance: 0,
        totalEarnings: 0
    });
    const [transactions, setTransactions] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(null); // 'topup' | 'withdraw'
    const [amount, setAmount] = useState('');
    const [method, setMethod] = useState('Bkash');
    const [details, setDetails] = useState('');

    const fetchData = async () => {
        try {
            const statsRes = await api.get('/agent/stats');
            setStats(statsRes.data);

            const trxRes = await api.get('/transactions/assigned'); // Assigned Trx
            setTransactions(trxRes.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleAction = async (id, status) => {
        try {
            await api.post('/transaction/complete', {
                transactionId: id,
                status: status
            });
            fetchData();
            toast.success('Success!');
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed');
        }
    };

    const submitRequest = async (e) => {
        e.preventDefault();
        try {
            const endpoint = showModal === 'topup' ? '/agent/topup' : '/agent/withdraw';
            await api.post(endpoint, {
                amount,
                method,
                transactionId: showModal === 'topup' ? details : undefined,
                accountDetails: showModal === 'withdraw' ? details : undefined,
                note: details
            });
            toast.success('Request Submitted');
            setShowModal(null);
            setAmount('');
            setDetails('');
            fetchData();
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed');
        }
    };

    if (loading) return (
        <div className="min-h-screen bg-[#1A1F2B] flex items-center justify-center">
            <div className="w-8 h-8 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
    );

    return (
        <div className="min-h-screen bg-[#1A1F2B] font-sans pb-24 text-slate-200">
            {/* Ultra-Slim Header */}
            <header className="px-6 pt-6 pb-2 mb-2 flex justify-between items-center sticky top-0 z-40 bg-[#1A1F2B]/90 backdrop-blur-md">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-emerald-500 to-teal-600 flex items-center justify-center text-white font-bold text-lg shadow-lg shadow-emerald-500/20">
                        A
                    </div>
                    <div>
                        <h1 className="text-white font-bold text-lg leading-tight">Agent Panel</h1>
                        <div className="flex items-center gap-1.5">
                            <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                            <span className="text-xs text-emerald-400 font-medium tracking-wide">LIVE</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <button className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-slate-400 hover:text-white transition">
                        <Bell className="w-5 h-5" />
                    </button>
                </div>
            </header>

            <main className="px-5 space-y-6">

                {/* Agent Specific Slider */}
                <div className="w-full h-32 md:h-40 relative rounded-2xl overflow-hidden shadow-lg border border-white/5">
                    <ImageSlider images={[
                        'https://via.placeholder.com/800x300/064e3b/ffffff?text=Boost+Your+Earnings',
                        'https://via.placeholder.com/800x300/0f172a/ffffff?text=Agent+Exclusive+Offer',
                        'https://via.placeholder.com/800x300/4c1d95/ffffff?text=High+Commission+Rates'
                    ]} />
                </div>

                {/* Premium Balance Card */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="relative overflow-hidden rounded-[2rem] bg-gradient-to-br from-emerald-600 to-teal-800 p-6 shadow-2xl shadow-emerald-900/40"
                >
                    {/* Background Texture */}
                    <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full blur-3xl -mr-32 -mt-32 pointer-events-none"></div>
                    <div className="absolute bottom-0 left-0 w-48 h-48 bg-black/20 rounded-full blur-3xl -ml-24 -mb-24 pointer-events-none"></div>

                    <div className="relative z-10 flex flex-col items-center text-center">
                        <p className="text-emerald-100 text-sm font-medium mb-1 tracking-wide">Available Stock</p>
                        <h2 className="text-4xl font-black text-white mb-4 tracking-tight drop-shadow-lg">
                            ${Number(stats.currentBalance || 0).toLocaleString()}
                        </h2>

                        <div className="flex items-center gap-2 bg-white/10 backdrop-blur-md border border-white/10 px-4 py-1.5 rounded-full">
                            <Wallet className="w-3.5 h-3.5 text-emerald-300" />
                            <span className="text-xs font-bold text-white/90">Ready for Transfer</span>
                        </div>
                    </div>
                </motion.div>

                {/* Quick Actions Grid */}
                <div className="grid grid-cols-3 gap-3">
                    <motion.button
                        whileTap={{ scale: 0.95 }}
                        onClick={() => setShowModal('topup')}
                        className="flex flex-col items-center gap-2 p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 transition group"
                    >
                        <div className="w-12 h-12 rounded-full bg-emerald-500/20 flex items-center justify-center group-hover:bg-emerald-500/30 transition">
                            <ArrowUpRight className="w-6 h-6 text-emerald-400" />
                        </div>
                        <span className="text-xs font-bold text-slate-300">Load Stock</span>
                    </motion.button>

                    <motion.button
                        whileTap={{ scale: 0.95 }}
                        onClick={() => setShowModal('withdraw')}
                        className="flex flex-col items-center gap-2 p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 transition group"
                    >
                        <div className="w-12 h-12 rounded-full bg-rose-500/20 flex items-center justify-center group-hover:bg-rose-500/30 transition">
                            <ArrowDownLeft className="w-6 h-6 text-rose-400" />
                        </div>
                        <span className="text-xs font-bold text-slate-300">Withdraw</span>
                    </motion.button>

                    <motion.button
                        whileTap={{ scale: 0.95 }}
                        onClick={() => router.push('/agent/history')}
                        className="flex flex-col items-center gap-2 p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 transition group"
                    >
                        <div className="w-12 h-12 rounded-full bg-indigo-500/20 flex items-center justify-center group-hover:bg-indigo-500/30 transition">
                            <History className="w-6 h-6 text-indigo-400" />
                        </div>
                        <span className="text-xs font-bold text-slate-300">History</span>
                    </motion.button>
                </div>

                {/* Requests Queue */}
                <div className="pt-2">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-lg font-bold text-white flex items-center gap-2">
                            Available Requests
                            <span className="px-2 py-0.5 rounded-full bg-emerald-500/20 text-emerald-400 text-xs">{transactions.length}</span>
                        </h3>
                    </div>

                    {transactions.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-12 text-slate-500 space-y-3 bg-white/5 rounded-3xl border border-white/5 border-dashed">
                            <RefreshCcw className="w-10 h-10 opacity-50" />
                            <p className="text-sm font-medium">No pending requests</p>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            <AnimatePresence>
                                {transactions.map((trx, i) => (
                                    <motion.div
                                        key={trx.id}
                                        initial={{ opacity: 0, y: 10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, x: -20 }}
                                        transition={{ delay: i * 0.05 }}
                                        className="bg-white/5 backdrop-blur-sm p-4 rounded-2xl border border-white/5 relative overflow-hidden"
                                    >
                                        <div className="flex justify-between items-start mb-3">
                                            <div className="flex items-start gap-3">
                                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${trx.type === 'withdraw' ? 'bg-rose-500/20 text-rose-400' : 'bg-blue-500/20 text-blue-400'
                                                    }`}>
                                                    {trx.type === 'withdraw' ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-slate-200 text-sm mb-0.5">{trx.User?.fullName || 'Unknown User'}</h4>
                                                    <div className="flex items-center gap-2">
                                                        <p className="text-xs text-slate-400 font-mono tracking-wide">{trx.User?.phone}</p>
                                                        <button
                                                            onClick={() => navigator.clipboard.writeText(trx.User?.phone)}
                                                            className="text-slate-600 hover:text-slate-400"
                                                        >
                                                            <Copy className="w-3 h-3" />
                                                        </button>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="text-right">
                                                <p className={`text-lg font-black ${trx.type === 'withdraw' ? 'text-rose-400' : 'text-blue-400'}`}>
                                                    ${Math.abs(trx.amount)}
                                                </p>
                                                <span className={`inline-block text-[10px] font-bold px-2 py-0.5 rounded uppercase mt-1 ${trx.type === 'withdraw' ? 'bg-rose-500/10 text-rose-400' : 'bg-blue-500/10 text-blue-400'
                                                    }`}>
                                                    {trx.type.replace('_', ' ')}
                                                </span>
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-2 gap-3 mt-4 pt-3 border-t border-white/5">
                                            <button
                                                onClick={() => handleAction(trx.id, 'rejected')}
                                                className="py-2.5 rounded-xl bg-white/5 border border-white/5 text-slate-400 text-xs font-bold hover:bg-white/10 hover:text-white transition flex items-center justify-center gap-2"
                                            >
                                                <X className="w-3.5 h-3.5" /> Reject
                                            </button>
                                            <button
                                                onClick={() => handleAction(trx.id, 'completed')}
                                                className="py-2.5 rounded-xl bg-emerald-600 text-white text-xs font-bold shadow-lg shadow-emerald-900/40 hover:bg-emerald-500 active:scale-95 transition flex items-center justify-center gap-2"
                                            >
                                                <Check className="w-3.5 h-3.5" /> Approve
                                            </button>
                                        </div>
                                    </motion.div>
                                ))}
                            </AnimatePresence>
                        </div>
                    )}
                </div>
            </main>

            {/* Modal */}
            <AnimatePresence>
                {showModal && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm"
                    >
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.9, opacity: 0 }}
                            className="bg-[#1F2937] border border-white/10 rounded-3xl p-6 w-full max-w-sm shadow-2xl"
                        >
                            <h3 className="text-xl font-bold text-white mb-6 capitalize text-center">
                                {showModal === 'topup' ? 'Load Stock' : 'Withdraw Stock'}
                            </h3>
                            <form onSubmit={submitRequest} className="space-y-4">
                                <div>
                                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Amount</label>
                                    <input
                                        type="number"
                                        required
                                        className="w-full bg-[#111827] border border-white/10 rounded-xl px-4 py-3 font-bold text-white focus:outline-none focus:border-emerald-500 transition"
                                        value={amount}
                                        onChange={e => setAmount(e.target.value)}
                                        placeholder="0.00"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">
                                        {showModal === 'topup' ? 'Payment Method' : 'Receive Method'}
                                    </label>
                                    <select
                                        className="w-full bg-[#111827] border border-white/10 rounded-xl px-4 py-3 font-bold text-white focus:outline-none focus:border-emerald-500 transition"
                                        value={method}
                                        onChange={e => setMethod(e.target.value)}
                                    >
                                        <option>Bkash</option>
                                        <option>Nagad</option>
                                        <option>Rocket</option>
                                        <option>Bank Transfer</option>
                                        <option>Hand Cash</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">
                                        {showModal === 'topup' ? 'Transaction ID / Note' : 'Account Details'}
                                    </label>
                                    <textarea
                                        required
                                        className="w-full bg-[#111827] border border-white/10 rounded-xl px-4 py-3 font-bold text-white focus:outline-none focus:border-emerald-500 transition"
                                        value={details}
                                        onChange={e => setDetails(e.target.value)}
                                        placeholder={showModal === 'topup' ? 'Enter TrxID after sending cash to Admin' : 'Enter your wallet number'}
                                        rows={2}
                                    />
                                </div>
                                <div className="flex gap-3 pt-4">
                                    <button
                                        type="button"
                                        onClick={() => setShowModal(null)}
                                        className="flex-1 py-3.5 rounded-xl font-bold text-slate-400 bg-white/5 hover:bg-white/10 transition"
                                    >
                                        Cancel
                                    </button>
                                    <button
                                        type="submit"
                                        className="flex-1 py-3.5 rounded-xl font-bold text-white bg-emerald-600 hover:bg-emerald-500 shadow-lg shadow-emerald-900/40 transition"
                                    >
                                        Submit
                                    </button>
                                </div>
                            </form>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

            <AdminBottomNav />
        </div >
    );
}

