                        </button>

                        <button
                            onClick={handleShare}
                            className="flex items-center justify-center gap-2 py-3 px-4 rounded-xl font-bold bg-indigo-600 text-white shadow-lg shadow-indigo-200 active:scale-95 transition hover:bg-indigo-700"
                        >
