    { name: 'Zambia', code: '+260', flagCode: 'zm' },
    { name: 'Zimbabwe', code: '+263', flagCode: 'zw' }
];

function RegisterForm() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const refCodeFromUrl = searchParams.get('ref');
    const { playNotification, playSuccess, playError } = useGameSound();

    // CLEAN STATE: No defaults that look like auto-fill
    const [formData, setFormData] = useState({
        fullName: '',
        phone: '',
        countryCode: '+880',
        password: '',
        referralCode: refCodeFromUrl || '',
        deviceId: '',
        otp: ''
    });

    const [verificationStep, setVerificationStep] = useState('initial');
    const [generatedOtp, setGeneratedOtp] = useState(null);
    const [userOtp, setUserOtp] = useState('');
    const [showCountryList, setShowCountryList] = useState(false);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const [notification, setNotification] = useState(null);
    const [isOtpLoading, setIsOtpLoading] = useState(false);

    useEffect(() => {
        if (refCodeFromUrl) setFormData(prev => ({ ...prev, referralCode: refCodeFromUrl }));
        const loadFingerprint = async () => {
            try {
                const fp = await FingerprintJS.load();
                const result = await fp.get();
                setFormData(prev => ({ ...prev, deviceId: result.visitorId }));
            } catch (error) { console.error(error); }
        };
        loadFingerprint();
    }, [refCodeFromUrl]);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSendOtp = () => {
        if (!formData.fullName || !formData.phone) {
            setError('Please enter your Name and Phone Number first.');
            return;
        }

        // [NEW] Strict Phone Validation
        const phoneCheck = validatePhone(formData.countryCode, formData.phone);
        if (!phoneCheck.isValid) {
            setError(phoneCheck.error || 'Invalid Phone Number Format.');
            return;
        }

        setIsOtpLoading(true);
        setTimeout(() => {
            const code = Math.floor(1000 + Math.random() * 9000).toString();
            setGeneratedOtp(code);
            setVerificationStep('verifying');
            setIsOtpLoading(false);

            // Wait 800ms before auto-filling it to simulate actual SMS reading
            setTimeout(() => {
                setUserOtp(code);
            }, 800);

            setNotification({ type: 'info', message: `Auto-Detecting SMS: ${code}` });
            setTimeout(() => setNotification(null), 10000);
        }, 1500);
    };

    useEffect(() => {
        if (verificationStep === 'verifying' && userOtp.length === 4) {
            if (userOtp === generatedOtp) {
                // Wait 1 second before hiding the populated input so the user admires the auto-fill!
                setTimeout(() => {
                    setVerificationStep('verified');
                    setNotification({ type: 'success', message: 'Verified Successfully!' });
                    setTimeout(() => setNotification(null), 3000);
                }, 1000);
            } else {
                setError('Incorrect Code.');
                setUserOtp('');
            }
        }
    }, [userOtp, generatedOtp, verificationStep]);

    const handleRegister = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        const payload = {
            ...formData,
            // [REFACTOR] Use primary_phone for API
            primary_phone: `${formData.countryCode}${formData.phone.replace(/^0+/, '')}`,
            country: countries.find(c => c.code === formData.countryCode)?.name || 'Global'
        };

        try {
            const res = await api.post('/auth/register', payload);
            if (res.data.token) {
                localStorage.setItem('token', res.data.token);
                localStorage.setItem('user', JSON.stringify(res.data.user));
                // playSuccess();
                router.push(res.data.user.role === 'admin' ? '/admin/dashboard' : '/dashboard');
            } else { router.push('/'); }
        } catch (err) {
            // [MOBILE DEBUGGING] - FORCE ALERT TO SEE RAW ERROR


            setError(err.response?.data?.message || 'Registration failed');
            // playError();
            setLoading(false);
        }
    };
    return (
        <div className="flex flex-col h-full min-h-screen bg-[#070b14] relative font-sans text-slate-100 overflow-y-auto custom-scrollbar">
            {/* Premium Background Effects */}
            <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
                <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-emerald-600/10 rounded-full blur-[120px] animate-pulse"></div>
                <div className="absolute bottom-[-20%] right-[-10%] w-[60%] h-[60%] bg-blue-600/10 rounded-full blur-[120px] animate-pulse" style={{ animationDelay: '2s' }}></div>
            </div>

            {/* Notification Toast */}
            {notification && (
                <div className={`fixed top-5 left-1/2 -translate-x-1/2 z-50 px-6 py-3 rounded-full shadow-2xl animate-in slide-in-from-top duration-500 flex items-center gap-4 ${notification.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-[#131c31] border border-white/10 text-white'}`}>
                    <Smartphone className="w-5 h-5" />
                    <span className="font-mono text-xl font-black tracking-widest">{notification.message}</span>
                </div>
            )}

            <div className="relative z-10 flex-1 flex flex-col justify-center items-center px-4 py-8 w-full">
                <Link href="/" className="absolute top-8 left-8 text-slate-400 hover:text-white flex items-center gap-2 text-sm font-medium transition-colors"><ArrowLeft className="w-4 h-4" /> Back to Home</Link>

                <div className="w-full max-w-lg bg-[#0b1221]/80 backdrop-blur-2xl border border-white/5 rounded-[2.5rem] shadow-2xl shadow-black/50 p-8 relative overflow-hidden">
                    {/* Top Accent Line */}
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-emerald-500 to-blue-500"></div>

                    <div className="text-center mb-10 mt-2">
                        <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-gradient-to-tr from-emerald-500 to-blue-500 shadow-2xl mb-4 shadow-emerald-500/20">
                            <User className="w-7 h-7 text-white" />
                        </div>
                        <h1 className="text-3xl font-black text-white drop-shadow-md tracking-tight">
                            Create Account
                        </h1>
                        <p className="text-slate-400 text-xs font-semibold tracking-widest mt-2 uppercase">USA Affiliate Network</p>

                        {/* [NEW] Direct App Download for Referred Users */}
                        {formData.referralCode && (
                            <div className="mt-6 p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-center justify-between gap-4 animate-in fade-in slide-in-from-bottom-2 duration-700">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-xl bg-emerald-500/20 flex items-center justify-center">
                                        <Smartphone className="w-5 h-5 text-emerald-400" />
                                    </div>
                                    <div className="text-left">
                                        <p className="text-[10px] font-bold text-emerald-400 uppercase tracking-wider">Official App</p>
                                        <p className="text-xs font-bold text-white">Faster & Secure Access</p>
                                    </div>
                                </div>
                                <a
                                    href="https://usaaffiliatemarketing.com/app.apk"
                                    className="bg-emerald-500 hover:bg-emerald-400 text-black px-4 py-2 rounded-xl text-[10px] font-black tracking-widest transition-all active:scale-95"
                                >
                                    GET APK
                                </a>
                            </div>
                        )}
                    </div>


                    {error && <div className="mb-6 p-3 bg-red-500/20 border border-red-500/50 text-red-200 rounded-xl text-sm font-bold text-center anim-shake">{error}</div>}

                    <form onSubmit={handleRegister} className="space-y-5" autoComplete="off">
                        {/* AutoComplete Off Hack */}
                        <input type="text" style={{ display: 'none' }} />
                        <input type="password" style={{ display: 'none' }} />

                        <AuthInput
                            icon={User}
                            label="Identity Name"
                            name="fullName"
                            placeholder="Enter full name"
                            value={formData.fullName}
                            onChange={handleChange}
                            required
                            autoComplete="off"
                        />

                        {/* Phone with CDN Flag */}
                        <div className="space-y-2">
                            <label className="block text-[11px] font-bold text-slate-400 uppercase tracking-widest ml-4">Authorized Phone</label>
                            <div className="flex gap-2">
                                <div className="relative w-[38%]">
                                    <button type="button" onClick={() => setShowCountryList(!showCountryList)} className="w-full h-full bg-[#131c31] border border-white/5 rounded-2xl rounded-r-none pl-4 pr-3 flex items-center justify-between gap-2 hover:bg-white/5 cursor-pointer transition-colors focus:ring-2 focus:ring-emerald-500/30 outline-none">
                                        <div className="flex items-center gap-2">
                                            <img
                                                src={`https://flagcdn.com/w40/${countries.find(c => c.code === formData.countryCode)?.flagCode || 'bd'}.png`}
                                                alt="flag"
                                                className="w-5 h-3.5 rounded-sm object-cover shadow-sm"
                                            />
                                            <span className="text-sm font-bold text-slate-200">{formData.countryCode}</span>
                                        </div>
                                        <svg className={`w-4 h-4 text-slate-500 transition-transform ${showCountryList ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                                    </button>

                                    {showCountryList && (
                                        <div className="absolute z-50 top-full left-0 mt-2 w-72 bg-[#131c31] border border-white/10 rounded-2xl shadow-2xl shadow-black max-h-64 overflow-y-auto custom-scrollbar animate-in fade-in zoom-in-95 backdrop-blur-xl">
                                            <div className="p-2 sticky top-0 bg-[#131c31]/90 backdrop-blur-sm border-b border-white/5 z-10">
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-2">Select Country</p>
                                            </div>
                                            {countries.map(c => (
                                                <div key={c.name} onClick={() => { setFormData({ ...formData, countryCode: c.code }); setShowCountryList(false); }} className="p-3 mx-1 my-1 rounded-xl hover:bg-white/10 cursor-pointer flex items-center justify-between gap-3 transition-colors">
                                                    <div className="flex items-center gap-3">
                                                        <img src={`https://flagcdn.com/w40/${c.flagCode}.png`} alt={c.name} className="w-6 h-4 rounded-sm shadow-sm" />
                                                        <p className="text-sm font-bold text-white leading-none">{c.name}</p>
                                                    </div>
                                                    <p className="text-xs font-mono text-emerald-400">{c.code}</p>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                                <div className="flex-1">
                                    <AuthInput
                                        icon={Phone}
                                        name="phone"
                                        placeholder="Mobile Number"
                                        value={formData.phone}
                                        onChange={handleChange}
                                        required
                                        autoComplete="new-password"
                                        className="rounded-l-none"
                                    />
                                </div>
                            </div>
                        </div>

                        <AuthInput icon={Lock} label="Secure Password" type="password" name="password" placeholder="••••••••" value={formData.password} onChange={handleChange} required autoComplete="new-password" />

                        <AuthInput icon={Hash} label="Referral Code (Optional)" name="referralCode" placeholder="Ref Code" value={formData.referralCode} onChange={handleChange} />

                        {/* OTP Box */}
                        <div className="bg-[#131c31] rounded-2xl p-5 border border-white/5 mt-4 shadow-inner">
                            {verificationStep === 'initial' && (
                                <div className="flex items-center justify-between">
                                    <span className="text-sm text-slate-400 font-bold uppercase tracking-wider text-[11px]">Human Verification</span>
                                    <button type="button" onClick={handleSendOtp} disabled={isOtpLoading} className="px-5 py-2.5 bg-gradient-to-r from-emerald-500 to-blue-500 text-white text-xs font-black tracking-widest rounded-xl hover:brightness-110 transition-all shadow-lg active:scale-95 disabled:opacity-50 flex items-center gap-2">
                                        {isOtpLoading ? <span className="animate-spin h-4 w-4 border-2 border-white/20 border-t-white rounded-full"></span> : 'GET CODE'}
                                    </button>
                                </div>
                            )}

                            {verificationStep === 'verifying' && (
                                <div className="space-y-3 animate-in fade-in slide-in-from-top-2">
                                    <div className="flex justify-between items-center text-[11px] font-bold text-slate-400 uppercase tracking-widest">
                                        <span>Auto-Verifying Code</span>
                                        <span className="text-emerald-400 animate-pulse">Waiting for input...</span>
                                    </div>
                                    <div className="flex gap-2">
                                        <input
                                            type="text"
                                            maxLength={4}
                                            value={userOtp}
                                            onChange={(e) => setUserOtp(e.target.value.replace(/\D/g, ''))}
                                            placeholder="••••"
                                            className="w-full bg-[#0a1120] border border-white/10 rounded-xl px-4 py-3 text-center text-white font-mono text-2xl tracking-[1em] outline-none focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 transition-all shadow-inner"
                                            autoFocus
                                        />
                                    </div>
                                </div>
                            )}

                            {verificationStep === 'verified' && (
                                <div className="flex items-center justify-center gap-2 text-emerald-400 font-bold py-2 animate-in zoom-in-95">
                                    <CheckCircle className="w-6 h-6" /> IDENTITY SECURED
                                </div>
                            )}
                        </div>

                        <button
                            type="submit"
                            disabled={loading || verificationStep !== 'verified'}
                            className={`w-full mt-6 py-4 rounded-2xl font-black tracking-wide text-sm shadow-xl transition-all flex justify-center items-center gap-2 ${verificationStep === 'verified' ? 'bg-gradient-to-r from-emerald-500 to-blue-600 text-white hover:scale-[1.02] hover:shadow-emerald-500/20 cursor-pointer' : 'bg-[#131c31] text-slate-500 border border-white/5 cursor-not-allowed'}`}
                        >
                            {loading ? <span className="animate-spin h-5 w-5 border-2 border-white/20 border-t-white rounded-full"></span> : 'FINALIZE REGISTRATION'}
                        </button>

                        {/* [NEW] Persistent Install Action */}
                        <button
                            type="button"
                            onClick={() => window.triggerPWAInstall && window.triggerPWAInstall()}
                            className="w-full py-3 mt-2 bg-emerald-500/10 border border-emerald-500/20 rounded-xl text-emerald-400 text-[11px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-emerald-500/20 transition-all active:scale-95 group"
                        >
                            <svg className="w-4 h-4 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                            Download Official App
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
}

export default function RegisterPage() {
    return <Suspense fallback={<div className="min-h-screen bg-[#0A2540] flex items-center justify-center text-white">Loading...</div>}><RegisterForm /></Suspense>;
}

'use client';
import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Server, Shield, Globe, Power, CheckCircle, Wifi, Lock, Smartphone, X, ArrowLeft } from 'lucide-react';
import api from '../../services/api';
import toast from 'react-hot-toast';
import { useRouter } from 'next/navigation';
import VerificationModal from '../../components/VerificationModal';
import ConnectionFlow from '../../components/ConnectionFlow';

export default function ServerDashboard() {
    const [servers, setServers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [connecting, setConnecting] = useState(null); // planId being connected
    const [activeServerId, setActiveServerId] = useState(null);
    const [verificationModal, setVerificationModal] = useState(null); // { plan } or null
    const router = useRouter();

    useEffect(() => {
        fetchServers();
        const stored = localStorage.getItem('active_server_id');
        if (stored) setActiveServerId(stored);
    }, []);

    const fetchServers = async () => {
        try {
            const { data } = await api.get('/plan/my-plans');
            // [FIX] Handle array or nested object
            setServers(Array.isArray(data) ? data : data.plans || []);
        } catch (e) {
            console.error(e);
            toast.error("Failed to load servers.");
        } finally {
            setLoading(false);
        }
    };

    const initiateConnect = (plan) => {
        if (!plan.syntheticPhone || plan.syntheticPhone === 'Generating...') {
            toast.error("Server is provisioning. Please wait.");
            return;
        }
        setVerificationModal(plan);
    };

    const [vpsModal, setVpsModal] = useState(null); // { plan }

    // Called by Verification Modal on success
    const handleVerifySuccess = (plan) => {
        setVerificationModal(null);
        setVpsModal(plan);
        // Logic continues in handleVPSComplete
    };

    const handleVPSComplete = async () => {
        const plan = vpsModal;
        if (!plan) return;

        // Backend Handshake (Silent now, animation handled checks visual)
        try {
            await api.post('/task/verify-connection', {
                planId: plan._id,
                syntheticPhone: plan.syntheticPhone
            });

            localStorage.setItem('active_server_id', plan._id);
            localStorage.setItem('active_server_name', plan.planName);
            localStorage.setItem('active_server_phone', plan.syntheticPhone);

            setActiveServerId(plan._id);
            router.push('/tasks');

        } catch (err) {
            console.error(err);
            toast.error("Handshake Failed. Re-verifying...");
            setVpsModal(null);
        }
    };

    const handleDeploy = () => {
        router.push('/marketplace');
    };
    const handleDisconnect = () => {
        toast((t) => (
            <div className="flex flex-col gap-2">
                <span className="text-xs font-bold">Disconnect from secure server?</span>
                <div className="flex gap-2">
                    <button
                        onClick={() => {
                            localStorage.removeItem('active_server_id');
                            localStorage.removeItem('active_server_name');
                            localStorage.removeItem('active_server_phone'); // [NEW] Clear Key
                            setActiveServerId(null);
                            toast.dismiss(t.id);
                            toast.success("Disconnected successfully.");
                        }}
                        className="bg-red-500 text-white px-3 py-1 rounded text-[10px] font-bold"
                    >
                        Confirm
                    </button>
                    <button
                        onClick={() => toast.dismiss(t.id)}
                        className="bg-slate-700 text-white px-3 py-1 rounded text-[10px] font-bold"
                    >
                        Cancel
                    </button>
                </div>
            </div>
        ), {
            duration: 5000,
            style: {
                background: '#0f172a',
                border: '1px solid #dc2626',
                color: '#fff',
            }
        });
    };

    if (loading) return (
        <div className="min-h-screen bg-[#050505] flex items-center justify-center p-6">
            <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                <p className="text-slate-400 font-mono text-xs animate-pulse">LOCATING ASSETS...</p>
            </div>
        </div>
    );

    return (
        <div className="min-h-screen bg-[#050505] text-white pb-24 relative overflow-hidden">
            <AnimatePresence>
                {verificationModal && (
                    <VerificationModal
                        plan={verificationModal}
                        onClose={() => setVerificationModal(null)}
                        onSuccess={handleVerifySuccess}
                    />
                )}
            </AnimatePresence>

            {/* Background Effects */}
            <div className="absolute top-0 left-0 w-full h-[300px] bg-gradient-to-b from-indigo-900/20 to-transparent pointer-events-none"></div>

            <div className="p-6 pt-10 relative z-10">
                <div className="flex items-center justify-between mb-8">
                    <div>
                        <div className="flex items-center gap-4 mb-2">
                            <div
                                onClick={() => router.push('/dashboard')}
                                className="p-2 bg-white/10 rounded-full hover:bg-white/20 transition cursor-pointer"
                            >
                                <ArrowLeft size={20} className="text-white" />
                            </div>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight text-white flex items-center gap-2">
                            <Shield className="fill-indigo-500 text-indigo-500" size={24} />
                            SERVER FLEET
                        </h1>
                        <p className="text-slate-400 text-xs font-mono mt-1">USA SECURE GATEWAY</p>
                    </div>
                </div>

                {servers.length === 0 ? (
                    <div className="text-center py-20 bg-slate-900/30 rounded-2xl border border-white/5">
                        <Server size={48} className="text-slate-700 mx-auto mb-4" />
                        <h3 className="text-slate-300 font-bold">No Active Servers</h3>
                        <p className="text-slate-500 text-sm mt-2 mb-6">Purchase a plan to deploy your personal task server.</p>
                        <button onClick={() => router.push('/marketplace')} className="bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-3 rounded-xl font-bold text-sm tracking-wide transition-all shadow-[0_0_15px_rgba(79,70,229,0.3)]">
                            DEPLOY SERVER
                        </button>
                    </div>
                ) : (
                    <div className="grid gap-6">
                        {servers.map((server) => (
                            <ServerCard
                                key={server._id}
                                server={server}
                                onConnect={initiateConnect}
                                onDisconnect={handleDisconnect}
                                isConnecting={connecting === server._id}
                                isActive={activeServerId === server._id}
                                hasActive={!!activeServerId}
                            />
                        ))}
                    </div>
                )}
            </div>
            {/* Verification Modal */}
            <AnimatePresence>
                {verificationModal && (
                    <VerificationModal
                        plan={verificationModal}
                        onClose={() => setVerificationModal(null)}
                        onSuccess={handleVerifySuccess}
                    />
                )}
            </AnimatePresence>

            {/* VPS Animation Overlay */}
            <AnimatePresence>
                {vpsModal && (
                    <ConnectionFlow
                        plan={vpsModal}
                        onComplete={handleVPSComplete}
                    />
                )}
            </AnimatePresence>
        </div> // End of ServerDashboard Container
    );
}

function ServerCard({ server, onConnect, onDisconnect, isConnecting, isActive, hasActive }) {
    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-slate-900/60 backdrop-blur-md rounded-2xl border border-white/10 overflow-hidden relative group"
        >
            {/* Glowing Border effect on hover */}
            <div className="absolute inset-0 border-2 border-transparent group-hover:border-indigo-500/30 rounded-2xl transition-all duration-500 pointer-events-none"></div>

            <div className="p-5">
                {/* Header */}
                <div className="flex justify-between items-start mb-6">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-lg bg-indigo-500/10 flex items-center justify-center border border-indigo-500/20">
                            <Server className="text-indigo-400" size={20} />
                        </div>
                        <div>
                            <h3 className="font-bold text-white text-lg">{server.planName}</h3>
                            <div className="text-[10px] text-emerald-400 font-bold bg-emerald-500/10 px-2 py-0.5 rounded-full inline-block mt-1 flex items-center gap-1 w-fit">
                                <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></div>
                                ONLINE
                            </div>
                        </div>
                    </div>
                    <Globe className="text-slate-600" size={40} strokeWidth={1} />
                </div>

                {/* Specs */}
                <div className="space-y-3 mb-6">
                    <div className="flex justify-between items-center text-sm border-b border-white/5 pb-2">
                        <span className="text-slate-500">IP Address</span>
                        <span className="font-mono text-slate-300 tracking-wider">{server.serverIp || '104.28.XX.XX'}</span>
                    </div>
                    <div className="flex justify-between items-center text-sm border-b border-white/5 pb-2">
                        <span className="text-slate-500">Location</span>
                        <span className="font-medium text-white flex items-center gap-1.5">
                            <img src="https://flagcdn.com/us.svg" alt="USA" className="w-4 h-3 object-cover rounded-[1px]" />
                            {server.serverLocation || 'Virginia, USA'}
                        </span>
                    </div>
                    <div className="flex justify-between items-center text-sm pt-1">
                        <span className="text-slate-500">Virtual Number</span>
                        <span className="font-mono text-indigo-300">{server.syntheticPhone || '+1 (703) XXX-XXXX'}</span>
                    </div>
                </div>

                {/* Action */}
                {isActive ? (
                    <button
                        onClick={onDisconnect}
                        className="w-full py-4 rounded-xl font-black text-sm tracking-widest uppercase transition-all flex items-center justify-center gap-3 bg-red-500/10 hover:bg-red-500/20 text-red-500 border border-red-500/20 shadow-[0_4px_20px_rgba(220,38,38,0.1)]"
                    >
                        <Power size={18} />
                        DISCONNECT SYSTEM
                    </button>
                ) : (
                    // [MODIFIED] Allow switching servers easily
                    <button
                        onClick={() => onConnect(server)}
                        disabled={isConnecting}
                        className={`w-full py-4 rounded-xl font-black text-sm tracking-widest uppercase transition-all flex items-center justify-center gap-3 ${isConnecting
                            ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
                            : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-[0_0_20px_rgba(79,70,229,0.4)]'
                            }`}
                    >
                        {isConnecting ? (
                            <>
                                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                                CONNECTING...
                            </>
                        ) : (
                            <>
                                <Wifi size={18} />
                                CONNECT SERVER
                            </>
                        )}
                    </button>
                )}
            </div>
        </motion.div>
    );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import api from '../../services/api';
import BottomNav from '../../components/BottomNav';
import { ArrowLeft, Send, MessageCircle, Phone, LifeBuoy, CheckCircle2, Ticket } from 'lucide-react';
import Link from 'next/link';
import toast from 'react-hot-toast';

export default function SupportPage() {
    const [subject, setSubject] = useState('');
    const [message, setMessage] = useState('');
    const [loading, setLoading] = useState(false);

    // Ticket States
    const [myTickets, setMyTickets] = useState([]);
    const [activeTicket, setActiveTicket] = useState(null);
    const [replyText, setReplyText] = useState('');
    const [replying, setReplying] = useState(false);

    const messagesEndRef = useRef(null);

    useEffect(() => {
        fetchTickets();
    }, []);

    // Auto-scroll when chatting
    useEffect(() => {
        if (activeTicket) {
            messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
    }, [activeTicket?.messages]);

    const fetchTickets = async () => {
        try {
            const res = await api.get('/support/my-messages');
            setMyTickets(res.data);

            // Auto update active ticket if open
            if (activeTicket) {
                const updated = res.data.find(t => t._id === activeTicket._id);
                if (updated) setActiveTicket(updated);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleCreateTicket = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const res = await api.post('/support/send', { subject, message });
            toast.success('Ticket created successfully!');
            setSubject('');
            setMessage('');
            fetchTickets();
            // Jump right into the new ticket
            if (res.data.support) setActiveTicket(res.data.support);
        } catch (err) {
            toast.error('Failed to create ticket');
        } finally {
            setLoading(false);
        }
    };

    const handleSendReply = async (e) => {
        e.preventDefault();
        if (!replyText.trim() || !activeTicket) return;

        setReplying(true);
        try {
            const res = await api.post('/support/reply', {
                messageId: activeTicket._id,
                reply: replyText
            });
            setReplyText('');
            // Preemptively append for speed or wait for fetch
            setActiveTicket(res.data.support);
            fetchTickets();
        } catch (err) {
            toast.error('Failed to send message');
        } finally {
            setReplying(false);
        }
    };

    // ===== ACTIVE CHAT VIEW =====
    if (activeTicket) {
        return (
            <div className="flex flex-col h-screen bg-slate-50 font-sans">
                {/* Header */}
                <div className="bg-white px-4 py-4 flex items-center justify-between shadow-sm z-10 sticky top-0 border-b border-slate-100">
                    <div className="flex items-center gap-3">
                        <button onClick={() => setActiveTicket(null)} className="p-2 hover:bg-slate-100 rounded-full transition">
                            <ArrowLeft className="w-5 h-5 text-slate-700" />
                        </button>
                        <div>
                            <h1 className="text-base font-bold text-slate-800 line-clamp-1">{activeTicket.subject}</h1>
                            <span className={`text-[10px] uppercase font-bold tracking-wider ${activeTicket.status === 'answered' ? 'text-green-600' : 'text-blue-500'}`}>
                                STATUS: {activeTicket.status}
                            </span>
                        </div>
                    </div>
                </div>

                {/* Chat Messages */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {activeTicket.messages?.map((msg, idx) => {
                        const isMe = msg.senderRole === 'user';
                        return (
                            <div key={idx} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                                {!isMe && (
                                    <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center mr-2 flex-shrink-0 mt-auto mb-1 border border-indigo-200">
                                        <LifeBuoy className="w-4 h-4 text-indigo-600" />
                                    </div>
                                )}
                                <div className={`max-w-[80%] rounded-2xl px-4 py-3 ${isMe ? 'bg-slate-800 text-white rounded-br-none shadow-md' : 'bg-white text-slate-800 rounded-bl-none border border-slate-100 shadow-sm'}`}>
                                    <p className="text-sm whitespace-pre-wrap leading-relaxed">{msg.text}</p>
                                    <div className={`text-[9px] mt-1.5 font-medium flex items-center justify-end gap-1 ${isMe ? 'text-slate-400' : 'text-slate-400'}`}>
                                        {new Date(msg.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        {isMe && <CheckCircle2 className="w-3 h-3 text-slate-400" />}
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                    {/* Fallback for legacy DB schema displaying top level message string */}
                    {(activeTicket.message && !activeTicket.messages?.length) && (
                        <div className="flex justify-end">
                            <div className="max-w-[80%] rounded-2xl px-4 py-3 bg-slate-800 text-white rounded-br-none shadow-md">
                                <p className="text-sm">{activeTicket.message}</p>
                            </div>
                        </div>
                    )}
                    {(activeTicket.adminReply && !activeTicket.messages?.length) && (
                        <div className="flex justify-start">
                            <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center mr-2 flex-shrink-0 mt-auto mb-1 border border-indigo-200">
                                <LifeBuoy className="w-4 h-4 text-indigo-600" />
                            </div>
                            <div className="max-w-[80%] rounded-2xl px-4 py-3 bg-white text-slate-800 rounded-bl-none border border-slate-100 shadow-sm">
                                <p className="text-sm">{activeTicket.adminReply}</p>
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <div className="bg-white p-3 border-t border-slate-100">
                    <form onSubmit={handleSendReply} className="flex gap-2">
                        <input
                            type="text"
                            placeholder="Type a message..."
                            value={replyText}
                            onChange={(e) => setReplyText(e.target.value)}
                            className="flex-1 bg-slate-50 border border-slate-200 rounded-full px-5 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-slate-800/20 font-medium"
                        />
                        <button
                            type="submit"
                            disabled={!replyText.trim() || replying}
                            className="w-12 h-12 bg-slate-800 text-white rounded-full flex items-center justify-center flex-shrink-0 transition active:scale-95 disabled:bg-slate-300"
                        >
                            {replying ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Send className="w-5 h-5 ml-1" />}
                        </button>
                    </form>
                </div>
            </div>
        )
    }

    // ===== MASTER LIST INBOX VIEW =====
    return (
        <div className="flex flex-col h-screen bg-slate-50 font-sans">
            {/* Header */}
            <div className="bg-white px-6 py-4 flex items-center gap-4 shadow-sm z-10 sticky top-0">
                <Link href="/dashboard" className="p-2 hover:bg-slate-100 rounded-full transition"><ArrowLeft className="w-6 h-6 text-slate-700" /></Link>
                <h1 className="text-xl font-bold text-slate-800">Help & Support</h1>
            </div>

            <div className="flex-1 overflow-y-auto px-4 py-6 pb-24 scrollbar-hide">



                {/* Send Message Form */}
                <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 mb-8">
                    <h2 className="text-lg font-bold text-slate-800 mb-1">Create Support Ticket</h2>
                    <p className="text-xs font-medium text-slate-400 mb-4">Want to become a Depositor or having issues? Let us know!</p>

                    <form onSubmit={handleCreateTicket} className="space-y-4">
                        <input
                            type="text"
                            placeholder="Subject (e.g. Depositor Access)"
                            value={subject}
                            onChange={(e) => setSubject(e.target.value)}
                            className="w-full p-4 bg-slate-50 rounded-xl border-none focus:ring-2 focus:ring-slate-800/20 font-bold text-sm text-slate-800"
                            required
                        />
                        <textarea
                            placeholder="Explain your problem clearly..."
                            value={message}
                            onChange={(e) => setMessage(e.target.value)}
                            className="w-full p-4 h-32 bg-slate-50 rounded-xl border-none focus:ring-2 focus:ring-slate-800/20 font-medium text-sm text-slate-700 resize-none"
                            required
                        ></textarea>
                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-4 rounded-xl shadow-lg shadow-slate-200 active:scale-95 transition flex items-center justify-center gap-2"
                        >
                            {loading ? 'Submitting...' : <><Ticket className="w-5 h-5" /> Open Ticket</>}
                        </button>
                    </form>
                </div>

                {/* Message History */}
                <div>
                    <h3 className="font-bold text-slate-400 text-xs uppercase tracking-wider mb-4 ml-2">My Support Tickets</h3>
                    {myTickets.length === 0 ? (
                        <div className="text-center py-10 bg-white rounded-[2rem] border border-dashed border-slate-200">
                            <LifeBuoy className="w-10 h-10 text-slate-300 mx-auto mb-3" />
                            <p className="font-bold text-slate-400">No active tickets.</p>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {myTickets.map(ticket => (
                                <div
                                    key={ticket._id}
                                    onClick={() => setActiveTicket(ticket)}
                                    className="bg-white p-4 flex flex-col gap-2 rounded-2xl border border-slate-100 hover:border-blue-200 hover:shadow-md cursor-pointer transition active:scale-[0.98]"
                                >
                                    <div className="flex justify-between items-start">
                                        <h4 className="font-bold text-slate-800 text-sm pr-4 line-clamp-1">{ticket.subject}</h4>
                                        <span className={`px-2 py-0.5 rounded text-[9px] uppercase font-bold flex-shrink-0 ${ticket.status === 'answered' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-600'}`}>{ticket.status}</span>
                                    </div>
                                    <p className="text-xs font-medium text-slate-500 line-clamp-2">
                                        {ticket.messages && ticket.messages.length > 0 ? ticket.messages[ticket.messages.length - 1].text : ticket.message}
                                    </p>
                                    <p className="text-[10px] text-slate-400 font-medium">{new Date(ticket.createdAt).toLocaleDateString()}</p>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

            </div>
            <BottomNav />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { Play, CheckCircle, Clock } from 'lucide-react';
import api from '../../../services/api';
import Button from '../../../components/ui/Button';
import toast from 'react-hot-toast';

export default function TasksPage() {
    const [tasks, setTasks] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTask, setActiveTask] = useState(null);
    const [timer, setTimer] = useState(0);
    const [claiming, setClaiming] = useState(false);
    const [userStats, setUserStats] = useState(null);

    useEffect(() => {
        fetchTasks();
    }, []);

    const fetchTasks = async () => {
        try {
            const res = await api.get('/tasks/status'); // Detailed status
            setTasks(res.data.taskAds || []);
            setUserStats(res.data);
            setLoading(false);
        } catch (err) {
            console.error(err);
        }
    };

    useEffect(() => {
        let interval;
        if (activeTask && timer > 0) {
            interval = setInterval(() => {
                setTimer((prev) => prev - 1);
            }, 1000);
        } else if (activeTask && timer === 0) {
            // Task Done
            clearInterval(interval);
        }
        return () => clearInterval(interval);
    }, [activeTask, timer]);

    const handleStartTask = async (task) => {
        if (!userStats.canWork && userStats.tasksCompleted >= userStats.dailyLimit) {
            toast.error('Daily limit reached!');
            return;
        }

        try {
            // Start Tracking on Backend
            await api.post('/tasks/start', { taskId: task.id });

            setActiveTask(task);
            setTimer(task.duration || 10);

            // Open Ad in New Tab (simulated)
            if (task.url) window.open(task.url, '_blank');

        } catch (err) {
            toast.error('Failed to start task');
        }
    };

    const handleClaim = async () => {
        setClaiming(true);
        try {
            await api.post('/tasks/submit', { taskId: activeTask.id });
            toast.success('Reward Claimed!');
            setActiveTask(null);
            fetchTasks(); // Refresh stats
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed to claim');
        } finally {
            setClaiming(false);
        }
    };

    if (loading) return <div className="p-8 text-center">Loading Tasks...</div>;

    return (
        <div className="min-h-screen bg-slate-50 pb-20">
            {/* Header */}
            <div className="bg-[#16172B] p-6 pt-8 rounded-b-[2rem] text-white">
                <h1 className="text-2xl font-black mb-1">Task Care</h1>
                <p className="text-slate-400 text-sm mb-4">Watch Ads & Earn Money</p>

                <div className="flex gap-4">
                    <div className="bg-white/10 p-3 rounded-xl flex-1 backdrop-blur-sm">
                        <div className="text-xs text-slate-400 uppercase font-bold">Today's Earnings</div>
                        <div className="text-xl font-bold">{(userStats?.tasksCompleted * parseFloat(userStats?.rewardPerTask)).toFixed(2)} $</div>
                    </div>
                    <div className="bg-white/10 p-3 rounded-xl flex-1 backdrop-blur-sm">
                        <div className="text-xs text-slate-400 uppercase font-bold">Tasks Done</div>
                        <div className="text-xl font-bold">{userStats?.tasksCompleted} / {userStats?.dailyLimit}</div>
                    </div>
                </div>
            </div>

            {/* Active Task Overlay */}
            {activeTask && (
                <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-6 backdrop-blur-sm">
                    <div className="bg-white rounded-3xl p-6 w-full max-w-sm text-center shadow-2xl animate-in zoom-in">
                        <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Clock className="w-8 h-8 text-blue-600 animate-pulse" />
                        </div>
                        <h3 className="text-xl font-bold text-slate-800 mb-2">Watching Ad...</h3>
                        <p className="text-slate-500 mb-6">Please wait {timer} seconds to claim reward.</p>

                        {timer > 0 ? (
                            <div className="text-4xl font-black text-blue-600 font-mono mb-8">
                                00:{timer.toString().padStart(2, '0')}
                            </div>
                        ) : (
                            <Button
                                onClick={handleClaim}
                                disabled={claiming}
                                className="w-full bg-green-500 hover:bg-green-600 text-white shadow-lg shadow-green-200"
                            >
                                {claiming ? 'Claiming...' : 'Claim Reward $'}
                            </Button>
                        )}

                        {timer > 0 && <p className="text-xs text-slate-400 mt-4">Do not close the ad window</p>}
                    </div>
                </div>
            )}

            {/* Task List */}
            <div className="p-6 space-y-4">
                <h3 className="font-bold text-slate-700">Available Tasks</h3>
                {tasks.map((task) => (
                    <div key={task.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="bg-blue-50 p-2.5 rounded-full">
                                <Play className="w-5 h-5 text-blue-600 ml-0.5" />
                            </div>
                            <div>
                                <h4 className="font-bold text-slate-800">{task.title}</h4>
                                <div className="flex items-center gap-2 text-xs text-slate-500 font-medium">
                                    <span className="bg-slate-100 px-1.5 py-0.5 rounded text-slate-600">{task.duration}s</span>
                                    <span>•</span>
                                    <span className="text-green-600 font-bold">+{task.reward} $</span>
                                </div>
                            </div>
                        </div>
                        <button
                            onClick={() => handleStartTask(task)}
                            className="bg-[#16172B] text-white px-4 py-2 rounded-xl text-sm font-bold shadow-lg hover:bg-slate-800 transition-colors"
                        >
                            Start
                        </button>
                    </div>
                ))}

                {tasks.length === 0 && (
                    <div className="text-center py-10 text-slate-400">
                        No tasks available right now.
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';
import { useEffect, useState } from 'react';
import api from '../../../services/api';
import BottomNav from '../../../components/BottomNav';
import Link from 'next/link';
import { ArrowLeft, Clock, ArrowUpRight, ArrowDownLeft, Wallet, Smartphone, Gamepad2, Gift, Send, CheckCircle } from 'lucide-react';

// Helper to group by date
const groupTransactionsByDate = (transactions) => {
    const groups = {};
    transactions.forEach(tx => {
        const date = new Date(tx.createdAt).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' });
        if (!groups[date]) groups[date] = [];
        groups[date].push(tx);
    });
    return groups;
};

// Helper for Icon & Color
const getTransactionMeta = (type) => {
    switch (type) {
        case 'add_money': return { icon: Wallet, color: 'text-emerald-500', bg: 'bg-emerald-50', label: 'Add Money' };
        case 'mobile_recharge': return { icon: Smartphone, color: 'text-violet-500', bg: 'bg-violet-50', label: 'Mobile Recharge' };
        case 'send_money': return { icon: Send, color: 'text-pink-500', bg: 'bg-pink-50', label: 'Send Money' };
        case 'game_win': return { icon: Gamepad2, color: 'text-orange-500', bg: 'bg-orange-50', label: 'Game Win' };
        case 'game_loss': return { icon: Gamepad2, color: 'text-slate-500', bg: 'bg-slate-100', label: 'Game Play' };
        case 'commission': return { icon: Gift, color: 'text-blue-500', bg: 'bg-blue-50', label: 'Commission' };
        case 'wallet_transfer': return { icon: ArrowUpRight, color: 'text-indigo-500', bg: 'bg-indigo-50', label: 'Transfer' };
        case 'referral_bonus': return { icon: Gift, color: 'text-purple-500', bg: 'bg-purple-50', label: 'Referral Bonus' };
        case 'task_reward': return { icon: CheckCircle, color: 'text-yellow-500', bg: 'bg-yellow-50', label: 'Task Reward' };
        default: return { icon: Clock, color: 'text-slate-500', bg: 'bg-slate-100', label: type.replace('_', ' ') };
    }
};

export default function HistoryPage() {
    const [transactions, setTransactions] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchHistory = async () => {
            try {
                const res = await api.get('/transaction/history');
                setTransactions(res.data);
                setLoading(false);
            } catch (err) {
                console.error(err);
                setLoading(false);
            }
        };
        fetchHistory();
    }, []);

    const groupedTransactions = groupTransactionsByDate(transactions);

    return (
        <div className="flex flex-col h-screen bg-slate-50 font-sans">
            {/* Header */}
            <div className="bg-white px-6 py-4 flex items-center gap-4 shadow-sm z-10 sticky top-0">
                <Link href="/dashboard" className="p-2 hover:bg-slate-100 rounded-full transition"><ArrowLeft className="w-6 h-6 text-slate-700" /></Link>
                <h1 className="text-xl font-bold text-slate-800">Transaction History</h1>
            </div>

            <div className="flex-1 overflow-y-auto px-4 pb-24 scrollbar-hide">
                {loading ? (
                    <div className="flex justify-center items-center h-64">
                        <div className="animate-spin rounded-full h-10 w-10 border-4 border-pink-500 border-t-transparent"></div>
                    </div>
                ) : transactions.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-3/4 text-center opacity-50">
                        <div className="w-20 h-20 bg-slate-200 rounded-full flex items-center justify-center mb-4">
                            <Clock className="w-10 h-10 text-slate-400" />
                        </div>
                        <h3 className="text-lg font-bold text-slate-600">No Transactions Yet</h3>
                        <p className="text-slate-400 text-sm max-w-[200px]">Your recent activity will appear here.</p>
                    </div>
                ) : (
                    <div className="space-y-6 pt-4">
                        {Object.keys(groupedTransactions).map((date) => (
                            <div key={date}>
                                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3 pl-2">{date}</h3>
                                <div className="space-y-3">
                                    {groupedTransactions[date].map((tx) => {
                                        const meta = getTransactionMeta(tx.type);
                                        const Icon = meta.icon;
                                        const isCredit = parseFloat(tx.amount) > 0;

                                        return (
                                            <div key={tx.id} className="bg-white p-4 rounded-2xl shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] border border-slate-100 flex items-center justify-between active:scale-[0.98] transition-transform">
                                                <div className="flex items-center gap-4">
                                                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${meta.bg} ${meta.color} shrink-0`}>
                                                        <Icon className="w-6 h-6" />
                                                    </div>
                                                    <div>
                                                        <p className="font-bold text-slate-700 text-sm capitalize">{meta.label}</p>
                                                        <p className="text-[10px] text-slate-400 font-medium max-w-[140px] truncate">
                                                            {tx.description || tx.recipientDetails || 'No details'}
                                                        </p>
                                                        <div className="flex items-center gap-2 mt-0.5">
                                                            <span className={`text-[10px] px-2 py-0.5 rounded-md font-bold uppercase ${tx.status === 'completed' ? 'bg-green-100 text-green-700' :
                                                                tx.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                                                                    'bg-red-100 text-red-700'
                                                                }`}>
                                                                {tx.status}
                                                            </span>
                                                            <span className="text-[10px] text-slate-400 font-mono">#{tx.id}</span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <div className="text-right">
                                                    <p className={`font-bold text-lg ${isCredit ? 'text-green-600' : 'text-slate-800'}`}>
                                                        {isCredit ? '+' : ''}{parseFloat(tx.amount).toFixed(2)}
                                                    </p>
                                                    <p className="text-xs text-slate-400 font-medium">{new Date(tx.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
            <BottomNav />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../../services/api';
import { useRouter } from 'next/navigation';
import { ArrowLeft, ArrowRightLeft, CreditCard } from 'lucide-react';
import Link from 'next/link';

export default function LoadPurchasePage() {
    const [user, setUser] = useState(null);
    const [amount, setAmount] = useState('');
    const [loading, setLoading] = useState(false);
    const [msg, setMsg] = useState('');
    const router = useRouter();

    useEffect(() => {
        fetchUser();
    }, []);

    const fetchUser = async () => {
        try {
            const res = await api.get('/auth/me');
            setUser(res.data);
        } catch (err) {
            console.error(err);
        }
    };

    const handleLoadPurchase = async (e) => {
        e.preventDefault();
        setLoading(true);
        // We reuse the transfer-main logic or create new endpoint? 
        // Currently /wallet/transfer-to-main goes Income -> Purchase (Wait, check name)
        // Previous transferToMain was Income -> Purchase. 
        // We need Main -> Purchase.
        // Let's use a new endpoint or specific payload

        // Actually, let's create a new action endpoint or use a dual-purpose one.
        // For simplicity, I'll mock the endpoint logic here and implement it in backend next step.
        try {
            await api.post('/wallet/load-purchase', { amount });
            setMsg('Transaction Successful: Funds added to Purchase Wallet');
            setTimeout(() => router.push('/dashboard'), 2000);
        } catch (err) {
            setMsg(err.response?.data?.message || 'Transaction Failed');
        } finally {
            setLoading(false);
        }
    };

    if (!user) return <div className="p-10 text-center">Loading...</div>;

    const mainBalance = parseFloat(user.wallet_balance || 0);

    return (
        <div className="flex flex-col h-screen bg-slate-50 font-sans">
            {/* Header */}
            <div className="bg-white px-6 py-4 flex items-center gap-4 shadow-sm z-10 sticky top-0">
                <Link href="/dashboard" className="p-2 hover:bg-slate-100 rounded-full transition">
                    <ArrowLeft className="w-6 h-6 text-slate-700" />
                </Link>
                <h1 className="text-xl font-bold text-slate-800">Load Purchase Wallet</h1>
            </div>

            <div className="p-6 flex-1 overflow-y-auto">
                <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl p-6 text-white text-center mb-8 shadow-lg shadow-indigo-200">
                    <p className="text-indigo-100 text-sm font-medium mb-1">Available Main Balance</p>
                    <h2 className="text-4xl font-bold">${mainBalance.toFixed(2)}</h2>
                </div>

                {msg && (
                    <div className={`p-4 rounded-xl mb-6 text-center font-bold text-sm ${msg.includes('Success') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                        {msg}
                    </div>
                )}

                <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                    <h3 className="font-bold text-slate-700 mb-4 flex items-center gap-2">
                        <ArrowRightLeft className="w-5 h-5 text-indigo-500" /> Transfer to Purchase Wallet
                    </h3>
                    <p className="text-sm text-slate-400 mb-6">Move funds from your Main Wallet to Purchase Wallet for shopping or buying plans.</p>

                    <form onSubmit={handleLoadPurchase}>
                        <div className="mb-6">
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 ml-1">Amount</label>
                            <input
                                type="number"
                                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-lg"
                                placeholder="0.00"
                                value={amount}
                                onChange={(e) => setAmount(e.target.value)}
                                min="1"
                                required
                            />
                        </div>
                        <button
                            type="submit"
                            disabled={loading || mainBalance <= 0}
                            className="w-full bg-slate-800 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-slate-900 active:scale-95 transition-all disabled:opacity-50 disabled:active:scale-100"
                        >
                            {loading ? 'Processing...' : 'Load Funds'}
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../../services/api';
import { useRouter } from 'next/navigation';
import { ArrowLeft, Smartphone, Radio, CheckCircle } from 'lucide-react';
import Link from 'next/link';
import TapToConfirmButton from '../../../components/TapToConfirmButton';
import { authService } from '../../../services/authService';

export default function MobileRechargePage() {
    const [operator, setOperator] = useState(''); // Default empty to force choice
    const [phone, setPhone] = useState('');
    const [amount, setAmount] = useState('');
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const [balance, setBalance] = useState(0);
    const router = useRouter();

    const operators = [
        { name: 'Grameenphone', color: '#10b3e8', bg: 'bg-[#10b3e8]' },
        { name: 'Banglalink', color: '#ff6b00', bg: 'bg-[#ff6b00]' },
        { name: 'Robi', color: '#e40000', bg: 'bg-[#e40000]' },
        { name: 'Airtel', color: '#d6001c', bg: 'bg-[#d6001c]' },
        { name: 'Teletalk', color: '#8cbd00', bg: 'bg-[#8cbd00]' }
    ];

    useEffect(() => {
        // Fetch User Balance
        const fetchBalance = async () => {
            try {
                const user = await authService.getCurrentUser();
                setBalance(user.wallet_balance || 0);
            } catch (err) {
                console.error("Failed to fetch balance", err);
            }
        };
        fetchBalance();
    }, []);

    const handleConfirm = () => {
        setError('');
        setMessage('');

        if (!operator) return setError('Please select an operator');
        if (!phone || phone.length < 11) return setError('Invalid phone number');
        if (!amount || parseFloat(amount) < 10) return setError('Minimum recharge is 10 Tk');
        if (parseFloat(amount) > balance) return setError('Insufficient balance');

        setLoading(true);
        api.post('/transaction/mobile-recharge', {
            recipientPhone: phone,
            amount: parseFloat(amount),
            operator
        })
            .then(() => {
                setMessage('Recharge Successful! ⚡');
                setTimeout(() => router.push('/dashboard'), 2000);
            })
            .catch(err => {
                setError(err.response?.data?.message || 'Request failed');
                setLoading(false);
            });
    };

    return (
        <div className="h-[100dvh] w-full flex flex-col font-sans overflow-hidden bg-gradient-to-b from-[#2e1065] to-[#111827] text-white">

