        text: 'text-cyan-400',
        bg: 'bg-cyan-900/20',
        border: 'border-cyan-500/50',
        shadow: 'shadow-[0_0_30px_rgba(6,182,212,0.3)]',
        pulseBorder: 'border-cyan-400',
