        }, 50);
        return () => clearInterval(interval);
    }, []);

    useEffect(() => {
        const sequence = async () => {
            if (mode === 'connect') {
                addLog("Initializing Quantum Handshake...");
                await new Promise(r => setTimeout(r, 800));
                addLog(`Targeting Node: ${plan?.serverIp || '204.14.XX.XX'}...`);
