import React, { useState, useEffect } from 'react';
import { X, Tv, ShieldCheck, Maximize2, Minimize2 } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { animationManager } from '../utils/AnimationManager';

const TaskTVPlayer = ({ task, onComplete, onClose }) => {
    const [timer, setTimer] = useState(task?.duration || 15); // Default enforced to 15s
    const [isMuted, setIsMuted] = useState(true);
    const [isMaximized, setIsMaximized] = useState(false);
    const [canClose, setCanClose] = useState(false);

    const [claiming, setClaiming] = useState(false);
    const [isSuccess, setIsSuccess] = useState(false);
    const router = useRouter(); // Ensure useRouter is imported

    useEffect(() => {
        if (!task) return;
        setTimer(task.duration || 15);
        setCanClose(false);
        setClaiming(false);
        setIsSuccess(false);

        const interval = setInterval(() => {
            setTimer((prev) => {
                if (prev <= 1) {
                    clearInterval(interval);
                    setCanClose(true);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);

        return () => clearInterval(interval);
    }, [task]);

    const handleClaim = async () => {
        if (!canClose || claiming) return;
        setClaiming(true);

        try {
            // Trigger animation
            animationManager.triggerRewardAnimation();

            // Call API
            if (onComplete) {
                await onComplete(task);
            }

            // Show Success UI
            setIsSuccess(true);

            // Auto Redirect after 2s
            setTimeout(() => {
                router.push('/dashboard');
            }, 2000);

        } catch (error) {
            console.error(error);
            setClaiming(false);
        }
    };

    if (!task) return null;

    return (
        <div className={`relative transition-all duration-500 ease-in-out ${isMaximized ? 'fixed inset-0 z-50 bg-black' : 'w-full max-w-4xl mx-auto'}`}>

            {/* TV FRAME CONTAINER */}
            <div className={`relative bg-gray-900 rounded-2xl overflow-hidden shadow-2xl border-4 border-gray-800 ${isMaximized ? 'h-full' : 'aspect-video'}`}>

                {/* TV BRANDING BAR (TOP) */}
                <div className="absolute top-0 left-0 right-0 h-12 bg-gradient-to-b from-black/80 to-transparent z-20 flex items-center justify-between px-4">
                    <div className="flex items-center gap-2 text-white/50 text-xs font-mono uppercase tracking-widest">
                        <Tv size={14} className="text-emerald-500" />
                        <span>Monetag Secure Stream</span>
                    </div>
                    <div className="flex items-center gap-3">
                        <button
                            onClick={() => setIsMaximized(!isMaximized)}
                            className="text-white/30 hover:text-white transition-colors"
                        >
                            {isMaximized ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
                        </button>
                    </div>
                </div>

                {/* IFRAME CONTENT (SANDBOXED) */}
                <div className="w-full h-full bg-black relative">
                    <iframe
                        src={task.url}
                        title="Ad Content"
                        className="w-full h-full object-cover"
                        sandbox="allow-scripts allow-same-origin allow-forms"
                        referrerPolicy="no-referrer"
                    />
                </div>

                {/* CONTROLS BAR (BOTTOM) */}
                <div className="absolute bottom-0 left-0 right-0 h-16 bg-gradient-to-t from-black via-black/80 to-transparent z-20 flex items-center justify-between px-6">

                    {/* LEFT: TIMER STATUS */}
                    <div className="flex items-center gap-3">
                        <div className={`
                            w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm border-2
                            ${canClose
                                ? 'bg-emerald-500 border-emerald-400 text-white shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-pulse'
                                : 'bg-transparent border-white/20 text-white/50'
                            }
                        `}>
                            {canClose ? <ShieldCheck size={20} /> : timer}
                        </div>
                        <div className="flex flex-col">
                            <span className="text-white text-sm font-medium tracking-wide">
                                {canClose ? 'Task Complete' : 'Viewing Ad...'}
                            </span>
                            <span className="text-white/30 text-[10px] uppercase">
                                {canClose ? 'Reward Ready' : `Wait ${timer}s to claim`}
                            </span>
                        </div>
                    </div>

                    {/* RIGHT: ACTION BUTTON (CLOSE) - HIDDEN UNTIL DONE */}
                    {canClose && !isSuccess && (
                        <button
                            onClick={handleClaim}
                            disabled={claiming}
                            className={`
                                group flex items-center gap-2 px-6 py-2 rounded-full font-bold text-sm transition-all duration-300 transform
                                bg-white text-black hover:bg-emerald-400 hover:scale-105 shadow-lg cursor-pointer
                                ${claiming ? 'opacity-50 cursor-not-allowed' : ''}
                            `}
                        >
                            {claiming ? (
                                <span>CLAIMING...</span>
                            ) : (
                                <>
                                    <span>CLAIM REWARD</span>
                                    <X size={16} className="transition-transform duration-300 group-hover:rotate-90" />
                                </>
                            )}
                        </button>
                    )}

                    {/* SUCCESS STATE UI */}
                    {isSuccess && (
                        <div className="flex items-center gap-3 animate-in fade-in zoom-in duration-300">
                            <div className="bg-emerald-500 text-white px-4 py-2 rounded-full font-bold text-sm shadow-lg flex items-center gap-2">
                                <ShieldCheck size={16} />
                                <span>Reward Claimed!</span>
                            </div>
                            <button onClick={() => window.location.href = '/dashboard'} className="text-white/50 text-xs hover:text-white underline">
                                Return to Dashboard
                            </button>
                        </div>
                    )}

                </div>
            </div>

            {/* TV ALIEN ANTENNA (DECORATIVE) */}
            {!isMaximized && (
                <div className="absolute -top-6 left-1/2 -translate-x-1/2 w-32 h-6 flex justify-center items-end opacity-20">
                    <div className="w-[1px] h-full bg-white rotate-[-30deg] origin-bottom px-[0.5px]"></div>
                    <div className="w-[1px] h-full bg-white rotate-[30deg] origin-bottom px-[0.5px]"></div>
                </div>
            )}
        </div>
    );
};

export default TaskTVPlayer;

import { useState, useEffect } from 'react';
import axios from 'axios';
import ApprovalModal from './admin/ApprovalModal';
import TransactionCard from './admin/TransactionCard';
import api from '../services/api';
import Link from 'next/link';
import { useNotification } from '../context/NotificationContext';
import ConfirmationModal from './ui/ConfirmationModal';

export default function TransactionApproval() {
    const { showSuccess, showError } = useNotification();
    const [transactions, setTransactions] = useState([]);
    const [agents, setAgents] = useState([]);
    const [selectedAgent, setSelectedAgent] = useState({});
    const [loading, setLoading] = useState(true);

    // Modal State
    const [approvalModal, setApprovalModal] = useState({ show: false, transactionId: null, type: null });
    const [bonusAmount, setBonusAmount] = useState('');
    const [adminComment, setAdminComment] = useState('');
    const [receivedAgent, setReceivedAgent] = useState('');
    const [confirmModal, setConfirmModal] = useState({ isOpen: false });

    useEffect(() => {
        fetchTransactions();
        fetchAgents();
    }, []);

    const fetchTransactions = async () => {
        try {
            // Updated Endpoint
            const res = await api.get('/transactions/pending');
            setTransactions(res.data);
        } catch (err) {
            console.error(err);
            showError('Admin Panel Error: ' + (err.response?.data?.message || err.message));
        } finally {
            setLoading(false);
        }
    };

    const fetchAgents = async () => {
        try {
            // Using new agent controller endpoint
            const res = await api.get('/admin/agents');
            setAgents(res.data);
        } catch (err) {
            console.error(err);
            setLoading(false);
        }
    };

    const handleAssign = async (transactionId) => {
        const agentId = selectedAgent[transactionId];
        if (!agentId) return showError('Please select an agent');

        try {
            await api.post('/transactions/assign', { transactionId, agentId });
            showSuccess('Assigned to Agent!');
            fetchTransactions();
        } catch (err) {
            console.error(err);
            showError('Failed to assign');
        }
    };

    const openApprovalModal = (transaction) => {
        setApprovalModal({ show: true, transactionId: transaction._id, type: transaction.recipientDetails?.includes('Method:') ? 'mobile' : 'bank' });
        setBonusAmount('');
        setAdminComment('');
        setReceivedAgent('');
    };

    const submitApproval = async () => {
        try {
            await api.post('/transactions/complete', {
                transactionId: approvalModal.transactionId,
                status: 'completed',
                comment: adminComment || 'Admin Approved',
                bonusAmount,
                receivedByAgentId: receivedAgent
            });
            showSuccess('Transaction Approved!');
            setApprovalModal({ show: false, transactionId: null, type: null });
            fetchTransactions();
        } catch (err) {
            console.error(err);
            showError('Failed to approve: ' + (err.response?.data?.message || err.message));
        }
    };

    const handleAgentSelect = (trxId, agentId) => {
        setSelectedAgent(prev => ({ ...prev, [trxId]: agentId }));
    };

    const handleReject = (transaction) => {
        setConfirmModal({
            isOpen: true,
            title: 'Reject Transaction',
            message: 'Are you sure you want to REJECT this transaction?',
            onConfirm: async () => {
                try {
                    await api.post('/transactions/complete', {
                        transactionId: transaction._id,
                        status: 'rejected',
                        comment: 'Admin Rejected'
                    });
                    showSuccess('Transaction Rejected!');
                    fetchTransactions();
                    setConfirmModal({ isOpen: false });
                } catch (err) {
                    console.error(err);
                    showError('Failed to reject');
                }
            }
        });
    };

    if (loading) return (
        <div className="flex flex-col items-center justify-center py-12">
            <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-indigo-600 mb-4"></div>
            <p className="text-slate-400 font-medium">Loading requests...</p>
        </div>
    );

    return (
        <div className="pb-20 flex justify-center">

            <div className="w-full max-w-2xl space-y-5 px-4 md:px-0">
                {transactions.length === 0 ? (
                    <div className="py-20 text-center bg-white/50 backdrop-blur-xl rounded-[2.5rem] border border-white/50 shadow-sm">
                        <div className="w-20 h-20 bg-gradient-to-tr from-slate-100 to-white rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                            <span className="text-3xl grayscale opacity-50">🎉</span>
                        </div>
                        <h3 className="text-slate-800 font-bold text-lg">All Caught Up!</h3>
                        <p className="text-slate-400 text-sm mt-2">No pending transactions to review.</p>
                    </div>
                ) : (
                    transactions.map(trx => (
                        <TransactionCard
                            key={trx._id}
                            trx={trx}
                            agents={agents}
                            selectedAgentId={selectedAgent[trx._id]}
                            onSelectAgent={handleAgentSelect}
                            onAssign={handleAssign}
                            onApprove={openApprovalModal}
                            onReject={handleReject}
                        />
                    ))
                )}
            </div>

            <ApprovalModal
                show={approvalModal.show}
                onClose={() => setApprovalModal({ show: false, transactionId: null })}
                onConfirm={submitApproval}
                bonusAmount={bonusAmount}
                setBonusAmount={setBonusAmount}
                adminComment={adminComment}
                setAdminComment={setAdminComment}
                receivedAgent={receivedAgent}
                setReceivedAgent={setReceivedAgent}
                agents={agents}
            />

            <div className="fixed bottom-6 right-6 z-20">
                <Link href="/admin/history" className="bg-white text-slate-600 px-6 py-3 rounded-full shadow-lg font-bold border border-slate-200 hover:bg-slate-50 transition flex items-center gap-2">
                    <span>📜 View History</span>
                </Link>
            </div>

            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                onConfirm={confirmModal.onConfirm}
                title={confirmModal.title}
                message={confirmModal.message}
                confirmText="Reject Transaction"
            />
        </div>
    );
}

