import { useState, useEffect } from 'react';
import Link from 'next/link';
import api from '../services/api';
import { KeyRound, LineChart, Search, Wallet, Shield, RefreshCw, MapPin, Monitor, Plus, Minus } from 'lucide-react';
import USCIcon from './ui/USCIcon';
import RoleDropdown from './admin/RoleDropdown';
import UserProfileModal from './admin/UserProfileModal';
import toast from 'react-hot-toast';

export default function UserManagement() {
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [isRefreshing, setIsRefreshing] = useState(false);

    // Modals
    const [balanceModal, setBalanceModal] = useState({ show: false, userId: null, type: 'credit', username: '' });
    const [amount, setAmount] = useState('');
    const [note, setNote] = useState('');
    const [secKeys, setSecKeys] = useState(['', '', '']); // [SECURITY] 3-Layer Keys

    const [resetModal, setResetModal] = useState({ show: false, userId: null, username: '' });
    const [newPassword, setNewPassword] = useState('');

    const [statsModal, setStatsModal] = useState({ show: false, userId: null, username: '' });
    const [profileModal, setProfileModal] = useState({ show: false, userId: null });

    useEffect(() => {
        const delayDebounce = setTimeout(() => {
            fetchUsers();
        }, 500);
        return () => clearTimeout(delayDebounce);
    }, [searchTerm]);

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const res = await api.get(`/admin/users?search=${searchTerm}`);
            // [FIX] Backend returns { users: [], totalPages: ... } now
            if (res.data.users && Array.isArray(res.data.users)) {
                setUsers(res.data.users);
            } else if (Array.isArray(res.data)) {
                setUsers(res.data);
            } else {
                setUsers([]);
            }
            setLoading(false);
        } catch (err) {
            console.error('Fetch error:', err);
            setError('Failed to load users');
            setLoading(false);
        }
    };

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await fetchUsers();
        setIsRefreshing(false);
    };

    const handleBalanceUpdate = async (e) => {
        e.preventDefault();
        try {
            await api.post(`/admin/user/${balanceModal.userId}/balance`, {
                amount,
                type: balanceModal.type,
                comment: note || 'Admin Manual Adjustment',
                secKey1: secKeys[0], // [SECURITY] Include keys
                secKey2: secKeys[1],
                secKey3: secKeys[2]
            });
            toast.success('Balance Updated Successfully');
            setBalanceModal({ show: false, userId: null, type: 'credit', username: '' });
            setAmount('');
            setNote('');
            setSecKeys(['', '', '']); // Reset keys
            fetchUsers();
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed to update balance');
        }
    };

    const handleRoleChange = async (userId, newRole) => {
        // Optimistic update
        setUsers(users.map(u => u.id === userId ? { ...u, role: newRole } : u));
        try {
            await api.put('/admin/user/role', { userId, role: newRole });
        } catch (err) {
            toast.error('Failed to update role');
            fetchUsers(); // Revert on error
        }
    };

    const handleResetPassword = async () => {
        if (!newPassword) return;
        try {
            await api.put('/admin/user/reset-password', { userId: resetModal.userId, newPassword });
            toast.success('Password reset successfully');
            setResetModal({ show: false, userId: null, username: '' });
            setNewPassword('');
        } catch (err) {
            toast.error('Failed to reset password');
        }
    };

    const getRoleLabel = (role) => {
        switch (role) {
            case 'super_admin': return 'Super Admin';
            case 'employee_admin': return 'Employee';
            case 'agent': return 'Agent';
            case 'user': return 'User';
            default: return role;
        }
    };

    const getRoleBadge = (role) => {
        const styles = {
            super_admin: 'bg-purple-100 text-purple-700 border-purple-200',
            employee_admin: 'bg-blue-100 text-blue-700 border-blue-200',
            agent: 'bg-emerald-100 text-emerald-700 border-emerald-200',
            user: 'bg-slate-100 text-slate-700 border-slate-200'
        };
        return styles[role] || styles.user;
    };

    return (
        <div className="max-w-7xl mx-auto pb-20 px-4">
            {/* Search Bar & Refresh */}
            <div className="sticky top-4 z-20 mb-6 flex gap-3">
                <div className="relative flex-1 shadow-2xl rounded-2xl bg-white/80 backdrop-blur-xl border border-white/50">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                        <Search className="h-5 w-5 text-indigo-500" />
                    </div>
                    <input
                        type="text"
                        className="block w-full pl-12 pr-4 py-4 bg-transparent rounded-2xl text-sm font-bold text-slate-800 placeholder:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                        placeholder="Search by Name, Phone, or Email..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <button
                    onClick={handleRefresh}
                    className={`p-4 bg-white/80 backdrop-blur-xl border border-white/50 rounded-2xl shadow-xl hover:bg-white transition flex items-center justify-center text-indigo-600 ${isRefreshing ? 'animate-spin' : ''}`}
                    title="Refresh Data"
                >
                    <RefreshCw className="h-6 w-6" />
                </button>
            </div>

            {/* Error State */}
            {error && <div className="text-center p-4 bg-red-100 text-red-600 rounded-xl mb-4 font-bold animate-pulse">{error}</div>}

            {/* User List */}
            {/* User List */}
            {loading && !users.length ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {[1, 2, 3, 4, 5, 6].map(i => <div key={i} className="h-64 bg-slate-900/50 animate-pulse rounded-3xl border border-white/5" />)}
                </div>
            ) : (
                <div className="grid grid-cols-1 gap-4">
                    {users.map(user => (
                        <div key={user.id} className="bg-[#111] p-6 rounded-3xl shadow-lg border border-white/10 relative group hover:border-indigo-500/30 transition-all duration-300">

                            {/* Decorative Glow */}
                            <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/5 blur-3xl rounded-full -translate-y-1/2 translate-x-1/2 pointer-events-none"></div>

                            <div className="relative z-10 flex flex-col gap-6">

                                {/* 1. TOP ROW: Identity & Badges */}
                                <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between border-b border-white/5 pb-4">
                                    <div className="flex items-center gap-4">
                                        <div className={`w-14 h-14 rounded-2xl flex-shrink-0 flex items-center justify-center text-xl font-black uppercase shadow-lg ${getRoleBadge(user.role)}`}>
                                            {user.fullName ? user.fullName.charAt(0) : '?'}
                                        </div>
                                        <div>
                                            <h3 className="text-lg font-bold text-white leading-tight truncate">{user.fullName || 'Unknown User'}</h3>
                                            <p className="text-sm font-mono text-slate-400 mt-0.5">{user.phone || user.u_ph || 'No Phone'}</p>
                                        </div>
                                    </div>

                                    <div className="flex flex-wrap gap-2">
                                        <span className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase border ${getRoleBadge(user.role)}`}>
                                            {getRoleLabel(user.role)}
                                        </span>
                                        <span className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase border ${user.status === 'banned' ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20'}`}>
                                            {user.status || 'Active'}
                                        </span>
                                        <span className="px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase border bg-indigo-500/10 text-indigo-500 border-indigo-500/20">
                                            {user.taskData?.accountTier || 'Starter'}
                                        </span>
                                        {user.referralCode && (
                                            <span className="text-[10px] bg-slate-800 text-slate-300 px-2.5 py-1 rounded-lg font-mono border border-white/5" title="Referral Code">
                                                REF: {user.referralCode}
                                            </span>
                                        )}
                                    </div>
                                </div>

                                {/* 2. MIDDLE ROW: Financial Stats */}
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="bg-slate-900/40 p-4 rounded-xl border border-white/5">
                                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider mb-1">Main Wallet</p>
                                        <p className="text-base sm:text-xl font-black text-white font-mono tracking-tight">
                                            <span className="flex items-center gap-1"><USCIcon className="w-4 h-4" /> {(user.wallet?.main ?? user.w_dat?.m ?? 0).toFixed(2)}</span>
                                        </p>
                                    </div>
                                    <div className="bg-slate-900/40 p-4 rounded-xl border border-white/5">
                                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider mb-1">Game Wallet</p>
                                        <p className="text-base sm:text-xl font-black text-yellow-500 font-mono tracking-tight">
                                            <span className="flex items-center gap-1"><USCIcon className="w-4 h-4" /> {(user.wallet?.game ?? user.w_dat?.g ?? 0).toFixed(2)}</span>
                                        </p>
                                    </div>
                                </div>

                                {/* 3. BOTTOM ROW: Actions */}
                                <div className="flex flex-col gap-4">
                                    {/* Money Actions */}
                                    <div className="grid grid-cols-2 gap-3">
                                        <button
                                            onClick={() => setBalanceModal({ show: true, userId: user.id, type: 'credit', username: user.fullName })}
                                            className="flex items-center justify-center gap-1.5 bg-emerald-500 hover:bg-emerald-600 text-white py-3 px-1 rounded-xl text-[11px] sm:text-xs font-black uppercase tracking-wide transition shadow-lg shadow-emerald-500/20 active:scale-95"
                                        >
                                            <Plus className="w-4 h-4" /> Add Fund
                                        </button>
                                        <button
                                            onClick={() => setBalanceModal({ show: true, userId: user.id, type: 'debit', username: user.fullName })}
                                            className="flex items-center justify-center gap-1.5 bg-red-500 hover:bg-red-600 text-white py-3 px-1 rounded-xl text-[11px] sm:text-xs font-black uppercase tracking-wide transition shadow-lg shadow-red-500/20 active:scale-95"
                                        >
                                            <Minus className="w-4 h-4" /> Deduct
                                        </button>
                                    </div>

                                    {/* Admin Tools */}
                                    <div className="flex items-center gap-3 bg-white/5 p-2 rounded-xl border border-white/5">
                                        <div className="flex-1 min-w-[100px]">
                                            <RoleDropdown
                                                currentRole={user.role}
                                                onChange={(val) => handleRoleChange(user.id, val)}
                                                direction="up"
                                            />
                                        </div>
                                        <button
                                            onClick={() => setProfileModal({ show: true, userId: user.id })}
                                            className="px-3 py-2 bg-indigo-500/20 text-indigo-400 hover:text-white hover:bg-indigo-500 rounded-lg text-xs font-bold uppercase transition shadow-lg shadow-indigo-500/10"
                                            title="View Full Profile & Status"
                                        >
                                            Profile
                                        </button>
                                        <button
                                            onClick={() => setResetModal({ show: true, userId: user.id, username: user.fullName })}
                                            className="p-2 text-slate-400 hover:text-white hover:bg-white/10 rounded-lg transition"
                                            title="Reset Password"
                                        >
                                            <KeyRound className="w-5 h-5" />
                                        </button>
                                    </div>
                                </div>

                            </div>
                        </div>
                    ))}
                    {!loading && users.length === 0 && (
                        <div className="text-center py-10">
                            <p className="text-slate-400 font-medium">No users found matching "{searchTerm}".</p>
                        </div>
                    )}
                </div>
            )}

            {/* Balance Modal and Other Modals */}
            {balanceModal.show && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white rounded-[2rem] p-6 w-full max-w-sm shadow-2xl scale-100">
                        <h3 className="font-extrabold text-xl text-slate-900 mb-1">
                            {balanceModal.type === 'credit' ? 'Add Balance' : 'Deduct Balance'}
                        </h3>
                        <p className="text-sm text-slate-500 mb-6">Target: <span className="font-bold text-indigo-600">{balanceModal.username}</span></p>

                        <form onSubmit={handleBalanceUpdate} className="space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5 ml-1">Amount (NXS)</label>
                                <input
                                    type="number"
                                    required
                                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-xl text-slate-800 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all placeholder:text-slate-300"
                                    placeholder="0.00"
                                    value={amount}
                                    onChange={e => setAmount(e.target.value)}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5 ml-1">Admin Note</label>
                                <input
                                    type="text"
                                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-400"
                                    placeholder="Reason for adjustment..."
                                    value={note}
                                    onChange={e => setNote(e.target.value)}
                                />
                            </div>

                            {/* 3-LAYER SECURITY INPUTS (Only for Credits) */}
                            {balanceModal.type === 'credit' && (
                                <div className="space-y-2 mt-4 p-4 bg-red-50 border border-red-100 rounded-xl">
                                    <label className="block text-xs font-bold text-red-600 uppercase mb-2 flex items-center gap-1">
                                        <Shield className="w-3 h-3" /> 3-Layer Security Required
                                    </label>
                                    {[0, 1, 2].map((i) => (
                                        <input
                                            key={i}
                                            type="password"
                                            required
                                            placeholder={`Secret Key ${i + 1}`}
                                            className="w-full p-2.5 bg-white border border-red-200 rounded-lg text-sm text-slate-900 text-center tracking-[0.3em] font-mono outline-none focus:border-red-500 focus:ring-1 focus:ring-red-500 transition-all"
                                            value={secKeys[i]}
                                            onChange={(e) => {
                                                const newKeys = [...secKeys];
                                                newKeys[i] = e.target.value;
                                                setSecKeys(newKeys);
                                            }}
                                        />
                                    ))}
                                </div>
                            )}

                            <div className="flex gap-3 pt-4">
                                <button type="button" onClick={() => { setBalanceModal({ show: false }); setSecKeys(['', '', '']); }} className="flex-1 py-3.5 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition">Cancel</button>
                                <button type="submit" className={`flex-1 py-3.5 text-white font-bold rounded-xl transition shadow-lg ${balanceModal.type === 'credit' ? 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-200' : 'bg-rose-500 hover:bg-rose-600 shadow-rose-200'}`}>
                                    Confirm
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Reset Password Modal */}
            {resetModal.show && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white rounded-[2rem] p-6 w-full max-w-sm shadow-2xl">
                        <h3 className="font-extrabold text-xl text-slate-900 mb-6">Reset Password</h3>
                        <input
                            type="text"
                            className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-lg outline-none focus:ring-2 focus:ring-indigo-500 mb-6 transition-all"
                            placeholder="New Password"
                            value={newPassword}
                            onChange={e => setNewPassword(e.target.value)}
                        />
                        <div className="flex gap-3">
                            <button onClick={() => setResetModal({ show: false })} className="flex-1 py-3.5 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition">Cancel</button>
                            <button onClick={handleResetPassword} className="flex-1 py-3.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition">Update</button>
                        </div>
                    </div>
                </div>
            )}

            {/* User Profile Modal */}
            <UserProfileModal
                isOpen={profileModal.show}
                onClose={() => setProfileModal({ show: false, userId: null })}
                userId={profileModal.userId}
                onStatusUpdate={fetchUsers}
            />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Shield, Lock, Globe, Server, Wifi, Cpu, Activity, CheckCircle2 } from 'lucide-react';

export default function VPSConnectModal({ plan, onComplete }) {
    const [phase, setPhase] = useState(0);

    // Sequence Timing: 7 Seconds Total
    useEffect(() => {
        const sequence = async () => {
            // Phase 1: Authentication (0-2.5s)
            setPhase(1);
            await new Promise(r => setTimeout(r, 2500));

            // Phase 2: Tunneling (2.5-5s)
            setPhase(2);
            await new Promise(r => setTimeout(r, 2500));

            // Phase 3: Encryption (5-7s)
            setPhase(3);
            await new Promise(r => setTimeout(r, 2000));

            // Done
            onComplete();
        };
        sequence();
    }, []);

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[9999] bg-[#020617] flex flex-col items-center justify-center overflow-hidden"
        >
            {/* --- Cyber Background Grid --- */}
            <div className="absolute inset-0 bg-[linear-gradient(rgba(30,58,138,0.1)_1px,transparent_1px),linear-gradient(90deg,rgba(30,58,138,0.1)_1px,transparent_1px)] bg-[size:40px_40px] [mask-image:radial-gradient(ellipse_80%_80%_at_50%_50%,#000_10%,transparent_100%)]"></div>

            {/* --- Glowing USA Flag Overlay --- */}
            <div className="absolute inset-0 bg-[url('/bg-flag.png')] bg-cover bg-center opacity-10 mix-blend-overlay"></div>

            {/* --- Central HUD --- */}
            <div className="relative z-10 w-full max-w-lg p-8 flex flex-col items-center">

                {/* 3D Rotating Shield & Emblem */}
                <div className="relative w-48 h-48 mb-10 flex items-center justify-center">
                    {/* Outer Rings */}
                    <motion.div
                        animate={{ rotate: 360 }}
                        transition={{ duration: 8, repeat: Infinity, ease: "linear" }}
                        className="absolute inset-0 rounded-full border border-slate-700/50 border-t-cyan-500 border-r-blue-500"
                    />
                    <motion.div
                        animate={{ rotate: -360 }}
                        transition={{ duration: 12, repeat: Infinity, ease: "linear" }}
                        className="absolute inset-4 rounded-full border border-slate-700/50 border-b-emerald-500 border-l-purple-500 opacity-70"
                    />

                    {/* Pulsing Core */}
                    <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-3xl animate-pulse"></div>

                    {/* Shield Icon */}
                    <motion.div
                        initial={{ scale: 0.8, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        transition={{ type: "spring", stiffness: 100 }}
                        className="relative z-10 bg-slate-900 border border-slate-700 p-6 rounded-2xl shadow-[0_0_50px_rgba(59,130,246,0.3)]"
                    >
                        <Shield size={64} className="text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]" fill="rgba(37,99,235,0.2)" />
                        <div className="absolute -top-1 -right-1">
                            <Activity size={16} className="text-emerald-400 animate-pulse" />
                        </div>
                    </motion.div>
                </div>

                {/* Cyber Text Interface */}
                <div className="w-full space-y-6">

                    {/* Phase 1: Auth */}
                    <PhaseItem
                        active={phase === 1}
                        completed={phase > 1}
                        icon={Globe}
                        label="Authenticating with USA Global Proxy..."
                        detail="Routing via Washington D.C. Node"
                    />

                    {/* Phase 2: Tunneling */}
                    <PhaseItem
                        active={phase === 2}
                        completed={phase > 2}
                        icon={Server}
                        label="Tunneling via VPS: New York City Gateway..."
                        detail={`Target: ${plan.planName} (Latency: <15ms)`}
                    />

                    {/* Phase 3: Encryption */}
                    <PhaseItem
                        active={phase === 3}
                        completed={phase > 3}
                        icon={Lock}
                        label="Encryption Active: AES-256 Tunnel Established."
                        detail="Secure Handshake Verified"
                        isLast
                    />

                </div>

                {/* Progress Bar */}
                <div className="w-full h-1 bg-slate-800 mt-12 overflow-hidden rounded-full">
                    <motion.div
                        initial={{ width: "0%" }}
                        animate={{ width: phase === 1 ? "33%" : phase === 2 ? "66%" : "100%" }}
                        transition={{ duration: 2, ease: "easeInOut" }}
                        className="h-full bg-gradient-to-r from-blue-500 via-cyan-400 to-emerald-400 shadow-[0_0_20px_rgba(6,182,212,0.8)]"
                    />
                </div>

                <p className="mt-4 text-[10px] text-slate-500 font-mono tracking-[0.2em] uppercase">
                    USA SECURE NETWORK • VER: 5.0.2 • ID: {plan.syntheticPhone}
                </p>

            </div>
        </motion.div>
    );
}

function PhaseItem({ active, completed, icon: Icon, label, detail, isLast }) {
    return (
        <div className={`flex items-center gap-4 transition-all duration-500 ${active || completed ? 'opacity-100 translate-x-0' : 'opacity-30 translate-x-4'}`}>
            <div className={`w-10 h-10 rounded-lg flex items-center justify-center border transition-all duration-500
                ${completed ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400' :
                    active ? 'bg-blue-500/10 border-blue-500 text-blue-400 shadow-[0_0_15px_rgba(59,130,246,0.5)]' :
                        'bg-slate-800 border-slate-700 text-slate-600'}
            `}>
                {completed ? <CheckCircle2 size={20} /> : <Icon size={20} className={active ? 'animate-pulse' : ''} />}
            </div>
            <div className="flex-1">
                <h4 className={`text-sm font-bold font-mono transition-colors duration-300 ${active ? 'text-white' : completed ? 'text-emerald-400' : 'text-slate-500'}`}>
                    {label}
                </h4>
                {active && (
                    <motion.p
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="text-[10px] text-cyan-400 font-mono mt-1 tracking-wider"
                    >
                        {'>'} {detail}
                    </motion.p>
                )}
            </div>
        </div>
    );
}

'use client';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Shield, Lock, X, CheckCircle, AlertTriangle } from 'lucide-react';

export default function VerificationModal({ plan, onClose, onSuccess }) {
    const [inputKey, setInputKey] = useState('');
    const [error, setError] = useState('');
    const [verifying, setVerifying] = useState(false);

    const handleVerify = async () => {
        setVerifying(true);
        setError('');

        // Simulate Network Delay for "Security Check"
        setTimeout(() => {
            const normalize = (s) => s ? String(s).replace(/[^0-9]/g, '') : '';
            const cleanInput = normalize(inputKey);
            const cleanTarget = normalize(plan.syntheticPhone);

            if (cleanInput === cleanTarget && cleanTarget.length > 5) {
                setVerifying(false);
                onSuccess(plan);
            } else {
                setVerifying(false);
                setError('Authentication Failed: ID Mismatch. Please copy EXACTLY.');
            }
        }, 1500);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
            <motion.div
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.8, opacity: 0 }}
                className="bg-slate-900 w-full max-w-md rounded-2xl border border-slate-700 shadow-2xl overflow-hidden"
            >
                <div className="bg-slate-800 p-4 border-b border-slate-700 flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <Shield className="w-5 h-5 text-emerald-500" />
                        <span className="font-bold text-white">Security Gateway</span>
                    </div>
                    <button onClick={onClose} className="text-slate-400 hover:text-white"><X size={20} /></button>
                </div>

                <div className="p-6">
                    <div className="mb-6 bg-blue-500/10 border border-blue-500/30 p-4 rounded-lg">
                        <p className="text-blue-200 text-sm flex gap-2">
                            <Lock size={16} className="shrink-0 mt-0.5" />
                            <span>For your security, please verify ownership of the assigned USA Number to activate this server.</span>
                        </p>
                    </div>

                    <div className="space-y-4">
                        <div>
                            <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Assigned Identity</label>
                            <div className="bg-slate-950 p-3 rounded border border-slate-700 font-mono text-emerald-400 text-lg text-center tracking-widest select-all">
                                {plan.syntheticPhone}
                            </div>
                            <p className="text-[10px] text-center text-slate-500 mt-1">(Copy this number)</p>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Verify Identity</label>
                            <input
                                type="text"
                                value={inputKey}
                                onChange={(e) => setInputKey(e.target.value)}
                                placeholder="Paste +1 (XXX) Number Here"
                                className="w-full bg-slate-800 border border-slate-600 rounded-lg p-3 text-white focus:ring-2 focus:ring-emerald-500 outline-none font-mono text-center"
                            />
                        </div>

                        {error && (
                            <motion.div
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="text-red-400 text-sm font-bold flex items-center justify-center gap-2 bg-red-500/10 p-2 rounded"
                            >
                                <AlertTriangle size={16} />
                                {error}
                            </motion.div>
                        )}

                        <button
                            onClick={handleVerify}
                            disabled={verifying || !inputKey}
                            className={`w-full py-3 rounded-lg font-bold text-white transition-all transform active:scale-95 ${verifying ? 'bg-slate-700 cursor-wait' : 'bg-emerald-600 hover:bg-emerald-500 shadow-lg shadow-emerald-500/20'
                                }`}
                        >
                            {verifying ? 'Verifying Credentials...' : 'Authenticate Connection'}
                        </button>
                    </div>
                </div>
            </motion.div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { useSocket } from '../../hooks/useSocket';
import { Activity } from 'lucide-react';

export default function AdminLiveChart({ initialData }) {
    const socket = useSocket('/system');
    const [data, setData] = useState(initialData || [
        { time: '0m', in: 0, out: 0, net: 0 }
    ]);

    useEffect(() => {
        if (!socket) return;

        // Listen for Global Admin Socket Events for Real-time Charting
        const handleUpdate = (tx) => {
            setData(prev => {
                const now = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
                const newPoint = {
                    time: now,
                    in: tx.type.includes('deposit') || tx.type.includes('recharge') ? tx.amount : 0,
                    out: tx.type.includes('withdraw') || tx.type.includes('cash_out') ? tx.amount : 0,
                };
                newPoint.net = newPoint.in - newPoint.out;

                const newData = [...prev, newPoint];
                if (newData.length > 20) newData.shift(); // Keep last 20 points
                return newData;
            });
        };

        // Custom event from backend could be 'admin_live_tx'
        socket.on('admin_live_tx', handleUpdate);

        // Also fallback to generic user updates if we can intercept them (Admin should subscribe to a global room)
        socket.on('wallet:update', (txData) => {
            handleUpdate(txData);
        });

        return () => {
            socket.off('admin_live_tx', handleUpdate);
            socket.off('wallet:update', handleUpdate);
        };
    }, [socket]);

    const CustomTooltip = ({ active, payload, label }) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-slate-900 border border-white/10 p-3 rounded-lg shadow-xl shrink-0 text-xs">
                    <p className="text-slate-400 font-mono mb-2">{label}</p>
                    {payload.map((entry, index) => (
                        <div key={index} className="flex justify-between gap-4 font-bold" style={{ color: entry.color }}>
                            <span className="uppercase">{entry.name}:</span>
                            <span>${entry.value.toLocaleString()}</span>
                        </div>
                    ))}
                </div>
            );
        }
        return null;
    };

    return (
        <div className="w-full h-72 bg-[#0f0f0f] border border-white/5 rounded-2xl p-4 relative overflow-hidden group">
            <div className="flex items-center gap-2 mb-4">
                <Activity className="w-4 h-4 text-emerald-400" />
                <h3 className="text-slate-400 text-xs font-bold uppercase tracking-widest">Live Transaction Activity</h3>
                <span className="flex h-2 w-2 relative ml-auto">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
                </span>
            </div>

            <div className="h-full w-full -ml-4">
                <ResponsiveContainer width="100%" height="90%">
                    <AreaChart data={data} margin={{ top: 5, right: 0, left: 0, bottom: 0 }}>
                        <defs>
                            <linearGradient id="colorIn" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                                <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                            </linearGradient>
                            <linearGradient id="colorOut" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.3} />
                                <stop offset="95%" stopColor="#f43f5e" stopOpacity={0} />
                            </linearGradient>
                        </defs>
                        <XAxis dataKey="time" hide />
                        <YAxis hide />
                        <Tooltip content={<CustomTooltip />} />
                        <Area type="monotone" dataKey="in" name="Inflow" stroke="#10b981" strokeWidth={2} fillOpacity={1} fill="url(#colorIn)" isAnimationActive={true} />
                        <Area type="monotone" dataKey="out" name="Outflow" stroke="#f43f5e" strokeWidth={2} fillOpacity={1} fill="url(#colorOut)" isAnimationActive={true} />
                    </AreaChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
}

