                                                        <span className="inline-flex items-center gap-1.5 px-2 py-1 rounded bg-red-500/10 text-red-400 text-[10px] font-bold uppercase tracking-wider border border-red-500/20">
                                                            <TrendingDown size={12} /> Burn / Debit
                                                        </span>
                                                    )}
