import { X } from 'lucide-react';
import { useState, useEffect } from 'react';

export default function AgentBalanceModal({ isOpen, onClose, onSubmit, initialAgentId }) {
    const [form, setForm] = useState({ agentId: initialAgentId, type: 'credit', amount: '', note: '' });

    useEffect(() => {
        if (initialAgentId) {
            setForm(prev => ({ ...prev, agentId: initialAgentId }));
        }
    }, [initialAgentId]);

    const handleSubmit = (e) => {
        e.preventDefault();
        onSubmit(form);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
            <div className="bg-white rounded-2xl p-6 w-full max-w-md shadow-2xl">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-xl font-bold">Manage Balance</h2>
                    <button onClick={onClose}><X className="w-6 h-6 text-gray-400" /></button>
                </div>
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid grid-cols-2 gap-3 mb-4">
                        <button type="button" onClick={() => setForm({ ...form, type: 'credit' })} className={`p-3 rounded-xl font-bold border ${form.type === 'credit' ? 'bg-green-100 border-green-500 text-green-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}>
                            Send Money (Credit)
                        </button>
                        <button type="button" onClick={() => setForm({ ...form, type: 'debit' })} className={`p-3 rounded-xl font-bold border ${form.type === 'debit' ? 'bg-red-100 border-red-500 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}>
                            Collect Cash (Debit)
                        </button>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Amount</label>
                        <input type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-indigo-500 text-2xl font-bold" value={form.amount} onChange={e => setForm({ ...form, amount: e.target.value })} required />
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Note (Optional)</label>
                        <input type="text" placeholder="Reason for adjustment..." className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-indigo-500" value={form.note} onChange={e => setForm({ ...form, note: e.target.value })} />
                    </div>

                    <button type="submit" className="w-full bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-black transition mt-4 shadow-xl shadow-slate-200">
                        {form.type === 'credit' ? 'Send to Agent' : 'Collect from Agent'}
                    </button>
                </form>
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../services/api';
import { ArrowDownToLine, ArrowUpFromLine, Activity, BarChart3, AlertTriangle, ShieldCheck } from 'lucide-react';

export default function EcosystemTracker() {
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);

    const fetchEconomy = async () => {
        try {
            const { data } = await api.get('/admin/economy-sheet');
            setStats(data);
        } catch (e) {
            console.error("Economy Sync Error", e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchEconomy();
        const interval = setInterval(fetchEconomy, 10000); // 10 Sec Poll
        return () => clearInterval(interval);
    }, []);

    if (loading || !stats) {
        return <div className="w-full h-32 flex items-center justify-center border border-white/5 rounded-2xl bg-slate-900/50 animate-pulse">
            <span className="text-slate-500 font-mono text-sm">Loading Ecosystem Analytics...</span>
        </div>;
    }

    const { today_generation, today_recovery, today_net, chart_data } = stats;

    return (
        <div className="w-full mb-8">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold flex items-center gap-2 text-white">
                    <BarChart3 className="text-purple-500" />
                    Economy Balance Sheet
                    <span className="text-xs bg-purple-500/20 text-purple-400 px-2 py-0.5 rounded-full border border-purple-500/50">
                        TODAY'S METRICS
                    </span>
                </h2>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
                {/* 1. Liability Generated */}
                <div className="bg-[#0f0f0f] border border-red-500/20 p-5 rounded-2xl relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition">
                        <ArrowUpFromLine className="w-24 h-24 text-red-500" />
                    </div>
                    <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-3 relative z-10 flex items-center gap-1">
                        <AlertTriangle size={12} className="text-red-400" /> Today's Liability Generated
                    </h3>
                    <div className="text-3xl font-black text-white tracking-tight relative z-10">
                        <span className="text-sm text-slate-500 font-normal">$</span>
                        {today_generation.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </div>
                    <p className="text-[10px] text-slate-400 mt-2 font-mono relative z-10">
                        Money mined today via Tasks & Referrals
                    </p>
                </div>

                {/* 2. Recovery / Burned */}
                <div className="bg-[#0f0f0f] border border-emerald-500/20 p-5 rounded-2xl relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition">
                        <ArrowDownToLine className="w-24 h-24 text-emerald-500" />
                    </div>
                    <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-3 relative z-10 flex items-center gap-1">
                        <ShieldCheck size={12} className="text-emerald-400" /> Today's Ecosystem Recovery
                    </h3>
                    <div className="text-3xl font-black text-white tracking-tight relative z-10">
                        <span className="text-sm text-slate-500 font-normal">$</span>
                        {today_recovery.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </div>
                    <p className="text-[10px] text-slate-400 mt-2 font-mono relative z-10">
                        Money burned via Lottery & Fees
                    </p>
                </div>

                {/* 3. Net Daily Drain */}
                <div className={`bg-[#0f0f0f] border ${today_net > 0 ? 'border-red-500/30' : 'border-emerald-500/30'} p-5 rounded-2xl relative overflow-hidden group`}>
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition">
                        <Activity className={`w-24 h-24 ${today_net > 0 ? 'text-red-500' : 'text-emerald-500'}`} />
                    </div>
                    <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-3 relative z-10">
                        Net Daily Ecosystem Drain
                    </h3>
                    <div className="text-3xl font-black text-white tracking-tight relative z-10 flex items-baseline gap-2">
                        <span className={`text-xl ${today_net > 0 ? 'text-red-500' : 'text-emerald-500'}`}>
                            {today_net > 0 ? '+' : ''}
                        </span>
                        <span className="text-sm text-slate-500 font-normal">$</span>
                        {today_net.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </div>
                    <div className="mt-3 relative z-10">
                        {today_net > 0 ? (
                            <span className="px-2 py-1 bg-red-500/10 text-red-400 text-[10px] font-bold uppercase rounded border border-red-500/20">
                                Inflation: Recovery is Too Low
                            </span>
                        ) : (
                            <span className="px-2 py-1 bg-emerald-500/10 text-emerald-400 text-[10px] font-bold uppercase rounded border border-emerald-500/20">
                                Deflation: Recovery is Healthy
                            </span>
                        )}
                    </div>
                </div>
            </div>

            {/* 7-Day Chart Representation (Simple Bar) */}
            <div className="mt-4 p-5 bg-[#0f0f0f] border border-white/5 rounded-2xl">
                <h3 className="text-slate-500 text-xs font-bold uppercase tracking-widest mb-4">7-Day Analysis (Generation vs Burn)</h3>
                <div className="grid grid-cols-7 gap-2 h-40 items-end">
                    {chart_data.map((day, idx) => {
                        const maxVal = Math.max(...chart_data.map(d => Math.max(d.generated, d.burned)), 1);
                        const genHeight = Math.max((day.generated / maxVal) * 100, 2);
                        const burnHeight = Math.max((day.burned / maxVal) * 100, 2);

                        return (
                            <div key={idx} className="flex flex-col items-center justify-end h-full gap-1 group relative">
                                <div className="absolute bottom-full mb-2 bg-slate-800 text-white text-[10px] p-2 rounded opacity-0 group-hover:opacity-100 transition whitespace-nowrap z-20 pointer-events-none">
                                    <div className="text-red-400">Generated: ${day.generated}</div>
                                    <div className="text-emerald-400">Burned: ${day.burned}</div>
                                </div>
                                <div className="flex gap-1 w-full justify-center items-end flex-1">
                                    {/* Generated Bar */}
                                    <div className="w-1/3 bg-red-500/50 rounded-t-sm transition-all" style={{ height: `${genHeight}%` }}></div>
                                    {/* Burned Bar */}
                                    <div className="w-1/3 bg-emerald-500/50 rounded-t-sm transition-all" style={{ height: `${burnHeight}%` }}></div>
                                </div>
                                <div className="text-[9px] text-slate-500 mt-2 font-mono truncate w-full text-center">
                                    {day.date.split('-').slice(1).join('/')}
                                </div>
                            </div>
                        )
                    })}
                </div>
                <div className="flex items-center gap-4 mt-4 pt-4 border-t border-white/5">
                    <div className="flex items-center gap-1.5 text-[10px] text-slate-400 uppercase font-bold tracking-wider">
                        <div className="w-3 h-3 bg-red-500/50 rounded-sm"></div> New Liability Created
                    </div>
                    <div className="flex items-center gap-1.5 text-[10px] text-slate-400 uppercase font-bold tracking-wider">
                        <div className="w-3 h-3 bg-emerald-500/50 rounded-sm"></div> Ecosystem Recovery (Burned)
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../services/api';
import { RefreshCcw, TrendingUp, Shield, Users, Wallet, Flame, HardDrive, ScrollText } from 'lucide-react';
import AdminMintLogsModal from './AdminMintLogsModal';

export default function LiveVaultTracker() {
    const [vaults, setVaults] = useState({
        total_minted: 0,
        total_revoked: 0,
        net_created: 0,
        global_pool: 0, // system liability
        admin_profit: 0
    });
    const [loading, setLoading] = useState(true);
    const [lastUpdate, setLastUpdate] = useState(null);
    const [showLogs, setShowLogs] = useState(false);

    const fetchVaults = async () => {
        try {
            const { data } = await api.get('/admin/live-vaults');
            if (data.status === 'LIVE') {
                setVaults(data.vaults);
                setLastUpdate(Date.now());
            }
        } catch (e) {
            console.error("Vault Sync Error", e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchVaults();
        const interval = setInterval(fetchVaults, 5000); // 5 Seconds Polling
        return () => clearInterval(interval);
    }, []);

    const VaultCard = ({ title, amount, subtitle, icon: Icon, color }) => (
        <div className={`flex flex-col p-4 rounded-xl border ${color} bg-slate-900/50 backdrop-blur-sm shadow-lg`}>
            <div className="flex justify-between items-start mb-2">
                <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-wider">
                    <Icon size={16} />
                    {title}
                </div>
                {subtitle && (
                    <div className="text-[10px] font-black px-2 py-0.5 rounded bg-slate-800 text-slate-300">
                        {subtitle}
                    </div>
                )}
            </div>
            <div className="text-2xl font-black text-white tracking-tight flex items-baseline gap-1">
                <span className="text-sm text-slate-500">$</span>
                {amount.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
            </div>
            <div className="w-full h-1 bg-slate-800 mt-3 rounded-full overflow-hidden">
                <div className="h-full bg-current opacity-50 w-full animate-pulse" style={{ color: color.split('-')[1] }} />
            </div>
        </div>
    );

    return (
        <div className="w-full mb-6">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold flex items-center gap-2 text-white">
                    <HardDrive className="text-blue-500" />
                    System Ledger & Minting
                    <span className="text-xs bg-green-500/20 text-green-400 px-2 py-0.5 rounded-full border border-green-500/50 animate-pulse">
                        LIVE SYNC
                    </span>
                </h2>

                <div className="flex items-center gap-4">
                    <button
                        onClick={() => setShowLogs(true)}
                        className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold rounded-lg transition border border-blue-400"
                    >
                        <ScrollText size={14} /> Minting Logs
                    </button>
                    <div className="text-xs text-slate-500 flex items-center gap-2 hidden sm:flex">
                        <RefreshCcw size={12} className={loading ? 'animate-spin' : ''} />
                        Updated: <span suppressHydrationWarning>{lastUpdate ? new Date(lastUpdate).toLocaleTimeString() : 'Syncing...'}</span>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                <VaultCard
                    title="Gross Minted"
                    amount={vaults.total_minted}
                    subtitle="ADMIN CREATED"
                    icon={TrendingUp}
                    color="border-blue-500/50 shadow-blue-500/10"
                />
                <VaultCard
                    title="System Liability"
                    amount={vaults.global_pool}
                    subtitle="USER WALLETS"
                    icon={Users}
                    color="border-yellow-500/50 shadow-yellow-500/10"
                />
                <VaultCard
                    title="Money Burned"
                    amount={vaults.total_revoked}
                    subtitle="ADMIN REVOKED"
                    icon={Flame}
                    color="border-red-500/50 shadow-red-500/10"
                />
                <VaultCard
                    title="Admin Profit"
                    amount={vaults.admin_profit}
                    subtitle="COMMISSION"
                    icon={Wallet}
                    color="border-green-500/50 shadow-green-500/10"
                />
            </div>

            {showLogs && <AdminMintLogsModal onClose={() => setShowLogs(false)} />}
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../services/api';
import { Trophy, Plus, Wallet, Target, Zap } from 'lucide-react';
import { useCurrency } from '../../context/CurrencyContext';
import ConfirmationModal from '../ui/ConfirmationModal';
import toast from 'react-hot-toast';

export default function LotteryManager() {
    // 5x Profit Model State
    const [activeSlot, setActiveSlot] = useState(null);
    const [history, setHistory] = useState([]);
    const [modal, setModal] = useState({ isOpen: false, title: '', message: '', onConfirm: null });

    // Create Form
    const [prizeAmount, setPrizeAmount] = useState('');
    const [multiplier, setMultiplier] = useState(5);
    const [loading, setLoading] = useState(false);

    const { formatMoney } = useCurrency(); // Assuming this hook exists or we format manually

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            const [statusRes, historyRes] = await Promise.all([
                api.get('/lottery/active'),
                api.get('/lottery/history')
            ]);

            if (statusRes.data.status !== 'INACTIVE') {
                setActiveSlot(statusRes.data);
            } else {
                setActiveSlot(null);
            }
            setHistory(historyRes.data);

        } catch (e) { console.error(e); }
    };

    const createSlot = async () => {
        if (!prizeAmount) return toast.error('Enter Prize Amount');
        setLoading(true);
        try {
            await api.post('/lottery/admin/create', {
                prize: prizeAmount,
                multiplier: multiplier
            });
            toast.success('5x Profit Slot Launched!');
            setPrizeAmount('');
            loadData();
        } catch (e) { toast.error(e.response?.data?.message || 'Error'); }
        finally { setLoading(false); }
    };

    const forceDraw = async () => {
        setModal({
            isOpen: true,
            title: 'Force Draw?',
            message: 'This will bypass the sales target and pick a winner immediately.',
            onConfirm: async () => {
                try {
                    await api.post('/lottery/admin/draw');
                    toast.success('Draw Initiated!');
                    loadData();
                } catch (e) { toast.error(e.response?.data?.message || 'Error'); }
            }
        });
    };

    return (
        <div className="p-6 bg-slate-900 text-white rounded-xl space-y-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
                <Trophy className="text-yellow-400" /> V2 Lottery Manager (5x Profit)
            </h2>

            {/* CREATION PANEL */}
            {!activeSlot ? (
                <div className="bg-slate-800 p-6 rounded-xl border border-white/5 space-y-4">
                    <h3 className="font-bold text-lg text-emerald-400 flex items-center gap-2">
                        <Zap className="w-5 h-5" /> Launch New 5x Slot
                    </h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-xs text-slate-400">Prize Amount (USD)</label>
                            <input className="bg-slate-900 border border-slate-700 p-3 rounded-lg w-full focus:border-emerald-500 outline-none"
                                type="number" placeholder="e.g. 10000"
                                value={prizeAmount}
                                onChange={e => setPrizeAmount(e.target.value)} />
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs text-slate-400">Profit Multiplier (Default 5x)</label>
                            <input className="bg-slate-900 border border-slate-700 p-3 rounded-lg w-full focus:border-emerald-500 outline-none"
                                type="number"
                                value={multiplier}
                                onChange={e => setMultiplier(e.target.value)} />
                        </div>
                    </div>

                    <div className="bg-slate-900/50 p-3 rounded text-xs text-slate-400 flex justify-between">
                        <span>Target Sales: ${prizeAmount ? prizeAmount * multiplier : 0}</span>
                        <span>Profit: ${prizeAmount ? (prizeAmount * multiplier) - prizeAmount : 0}</span>
                    </div>

                    <button
                        onClick={createSlot}
                        disabled={loading}
                        className="bg-emerald-500 hover:bg-emerald-600 px-6 py-3 rounded-lg font-bold flex items-center gap-2 transition disabled:opacity-50 w-full justify-center"
                    >
                        <Plus className="w-5 h-5" /> {loading ? 'Launching...' : 'LAUNCH SLOT'}
                    </button>
                </div>
            ) : (
                <div className="bg-slate-800 p-6 rounded-xl border border-yellow-500/30 relative overflow-hidden">
                    <div className="absolute top-0 right-0 bg-yellow-500 text-black text-[10px] font-bold px-3 py-1 rounded-bl-xl">
                        ACTIVE
                    </div>

                    <div className="flex flex-col md:flex-row justify-between items-center gap-6">
                        <div>
                            <h4 className="text-slate-400 text-xs uppercase tracking-widest">Current Jackpot</h4>
                            <div className="text-4xl font-black text-yellow-400">${activeSlot.jackpot}</div>
                            <div className="text-xs text-slate-500 mt-1">Target Sales: ${activeSlot.targetSales}</div>
                        </div>

                        <div className="flex-1 w-full">
                            <div className="flex justify-between text-xs text-slate-300 mb-1">
                                <span>Progress</span>
                                <span>{activeSlot.progress.toFixed(1)}%</span>
                            </div>
                            <div className="h-4 bg-slate-900 rounded-full overflow-hidden border border-white/5 relative">
                                <div className="absolute inset-0 bg-gradient-to-r from-yellow-600 to-yellow-400 transition-all duration-500" style={{ width: `${activeSlot.progress}%` }}></div>
                            </div>
                            <div className="text-center text-[10px] text-slate-500 mt-1">
                                Current Sales: ${activeSlot.currentSales}
                            </div>
                        </div>

                        <button
                            onClick={forceDraw}
                            className="bg-red-900/50 hover:bg-red-900/80 border border-red-500/50 text-red-200 px-4 py-2 rounded-lg text-xs font-bold"
                        >
                            FORCE DRAW
                        </button>
                    </div>
                </div>
            )}

            {/* History List */}
            <div className="space-y-4">
                <h3 className="font-bold text-lg text-slate-300">Recent Draws</h3>
                {history.map((lot, idx) => (
                    <div key={idx} className="bg-slate-800 p-4 rounded-xl flex justify-between items-center border border-white/5 opacity-75">
                        <div>
                            <p className="text-white font-bold">Winner: {lot.winner}</p>
                            <p className="text-xs text-slate-500">{new Date(lot.date).toLocaleString()}</p>
                        </div>
                        <div className="text-emerald-400 font-mono font-bold">
                            +${lot.amount}
                        </div>
                    </div>
                ))}
            </div>
            </div>

            <ConfirmationModal
                isOpen={modal.isOpen}
                onClose={() => setModal({ ...modal, isOpen: false })}
                onConfirm={modal.onConfirm}
                title={modal.title}
                message={modal.message}
                confirmText="Proceed"
            />
        </div >
    );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import api from '../../services/api';
import { useSocket } from '../../hooks/useSocket';
import { RefreshCw, CheckCircle, XCircle, AlertTriangle, Eye, FileText, Ban, Shield, MessageSquare, Bell } from 'lucide-react';
import USCIcon from '../ui/USCIcon';
import toast from 'react-hot-toast';
import ConfirmationModal from '../ui/ConfirmationModal';

export default function P2PCommandCenter() {
    const socket = useSocket();
    const [trades, setTrades] = useState([]);
    const [selectedTrade, setSelectedTrade] = useState(null);
    const [chatHistory, setChatHistory] = useState([]);
    const [loadingChat, setLoadingChat] = useState(false);
    const [confirmModal, setConfirmModal] = useState({ isOpen: false });

    // Audio Ref
    const audioRef = useRef(null);

    useEffect(() => {
        fetchMarket();
    }, []);

    useEffect(() => {
        if (!socket) return;

        // Join Admin Room
        socket.emit('join_admin_room', 'ADMIN_SECRET');

        socket.on('p2p_alert', (data) => {
            toast(data.message, { icon: '🚨', duration: 5000 });
            playAlertSound();
            fetchMarket();
        });

        return () => {
            socket.off('p2p_alert');
        };
    }, [socket]);

    const playAlertSound = () => {
        if (audioRef.current) {
            audioRef.current.play().catch(e => console.log("Audio play blocked"));
        }
    };

    const fetchMarket = async () => {
        try {
            const tradeRes = await api.get('/p2p/admin/trades');
            setTrades(tradeRes.data);

            // Auto-select first awaiting trade if none selected
            if (!selectedTrade) {
                const pending = tradeRes.data.find(t => ['AWAITING_ADMIN', 'DISPUTED'].includes(t.status));
                if (pending) selectTrade(pending);
            }
        } catch (e) { console.error(e); }
    };

    const selectTrade = async (trade) => {
        setSelectedTrade(trade);
        setLoadingChat(true);
        try {
            const res = await api.get(`/p2p/trade/${trade._id}/chat`);
            setChatHistory(res.data);
        } catch (e) {
            console.error("Chat fetch fail", e);
        } finally {
            setLoadingChat(false);
        }
    };

    const approve = (tradeId) => {
        setConfirmModal({
            isOpen: true,
            title: 'FORCE RELEASE FUNDS',
            message: 'Tribunal action: Release locked funds to the BUYER? This is irreversible.',
            confirmText: 'Release to Buyer',
            onConfirm: async () => {
                try {
                    await api.post('/p2p/admin/resolve', { tradeId, resolution: 'RELEASE_TO_BUYER' });
                    toast.success("FUNDS RELEASED TO BUYER");
                    fetchMarket();
                    setSelectedTrade(null);
                    setConfirmModal({ isOpen: false });
                } catch (e) {
                    toast.error(e.response?.data?.message || "Failed");
                }
            }
        });
    };

    const reject = (tradeId) => {
        setConfirmModal({
            isOpen: true,
            title: 'FORCE REFUND TO SELLER',
            message: 'Tribunal action: Cancel the trade and return locked funds to the SELLER?',
            confirmText: 'Refund Seller',
            onConfirm: async () => {
                try {
                    await api.post('/p2p/admin/resolve', { tradeId, resolution: 'REFUND_TO_SELLER' });
                    toast.success("FUNDS REFUNDED TO SELLER");
                    fetchMarket();
                    setSelectedTrade(null);
                    setConfirmModal({ isOpen: false });
                } catch (e) {
                    toast.error(e.response?.data?.message || "Failed");
                }
            }
        });
    };

    const [isMobileView, setIsMobileView] = useState(false);

    // Responsive check (basic)
    useEffect(() => {
        const checkMobile = () => setIsMobileView(window.innerWidth < 768);
        checkMobile();
        window.addEventListener('resize', checkMobile);
        return () => window.removeEventListener('resize', checkMobile);
    }, []);

    const pendingTrades = trades.filter(t => ['AWAITING_ADMIN', 'DISPUTED'].includes(t.status));

    return (
        <div className="h-[calc(100vh-100px)] flex flex-col md:flex-row gap-6 text-white font-sans">
            <audio ref={audioRef} src="/sounds/alert.mp3" preload="auto" />

            {/* LEFT: INBOX */}
            <div className={`w-full md:w-1/3 bg-[#111] border border-white/10 rounded-2xl flex flex-col overflow-hidden ${selectedTrade && isMobileView ? 'hidden' : 'flex'}`}>
                <div className="p-4 border-b border-white/10 bg-slate-900/50 flex justify-between items-center">
                    <h2 className="font-bold flex items-center gap-2">
                        <AlertTriangle className="w-4 h-4 text-red-500 animate-pulse" /> Disputes ({pendingTrades.length})
                    </h2>
                    <button onClick={fetchMarket}><RefreshCw className="w-4 h-4" /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-2 space-y-2">
                    {pendingTrades.length === 0 && <div className="p-4 text-center text-slate-500 text-sm">All clear, Commander.</div>}
                    {pendingTrades.map(t => (
                        <div
                            key={t._id}
                            onClick={() => selectTrade(t)}
                            className={`p-4 rounded-xl cursor-pointer border transition-all ${selectedTrade?._id === t._id ? 'bg-indigo-600/20 border-indigo-500' : 'bg-white/5 border-transparent hover:bg-white/10'}`}
                        >
                            <div className="flex justify-between mb-1">
                                <span className="font-bold text-sm text-slate-300">Order #{t._id.substr(-4)}</span>
                                <span className="text-[10px] font-black tracking-widest px-2 py-0.5 rounded bg-red-500/20 text-red-400 border border-red-500/20">{t.status}</span>
                            </div>
                            <div className="flex justify-between items-end">
                                <div>
                                    <div className="text-xs text-slate-400">{t.sellerId?.username} → {t.buyerId?.username}</div>
                                </div>
                                <div className="font-black font-mono flex items-center gap-1">
                                    <USCIcon className="w-4 h-4" /> {t.amount}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* RIGHT: INSPECTOR */}
            <div className={`w-full md:w-2/3 flex flex-col gap-6 ${!selectedTrade && isMobileView ? 'hidden' : 'flex'}`}>
                {selectedTrade ? (
                    <>
                        {/* 1. TOP: DECISION PANEL */}
                        <div className="bg-[#1a1b2e] border border-indigo-500/30 rounded-2xl p-6 shadow-2xl relative overflow-hidden">
                            {/* Mobile Back Button */}
                            {isMobileView && (
                                <button onClick={() => setSelectedTrade(null)} className="mb-4 text-xs text-slate-400 flex items-center gap-1">
                                    ← Back to List
                                </button>
                            )}

                            <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 blur-3xl rounded-full translate-x-1/2 -translate-y-1/2 pointer-events-none"></div>

                            <div className="flex flex-col md:flex-row justify-between items-start relative z-10 gap-4">
                                <div>
                                    <h3 className="text-2xl font-black mb-1 flex items-center gap-2">
                                        <Shield className="w-6 h-6 text-emerald-400" /> Tribunal Audit
                                    </h3>
                                    <p className="text-slate-400 text-sm mb-4">Investigate evidence, force resolution.</p>

                                    {selectedTrade.status === 'DISPUTED' && selectedTrade.disputeReason && (
                                        <div className="mb-4 bg-red-950/40 border border-red-500/30 p-3 rounded-xl max-w-sm">
                                            <div className="text-[10px] uppercase font-bold text-red-400 mb-1 flex justify-between">
                                                <span>Dispute Reason</span>
                                                <span>Reported By: {selectedTrade.disputeRaisedBy === selectedTrade.buyerId?._id ? 'BUYER' : 'SELLER'}</span>
                                            </div>
                                            <div className="text-sm text-red-100">{selectedTrade.disputeReason}</div>
                                        </div>
                                    )}

                                    <div className="grid grid-cols-2 gap-8 text-sm">
                                        <div>
                                            <div className="text-xs uppercase text-slate-500 font-bold">Trading Amount</div>
                                            <div className="text-xl font-mono font-bold flex items-center gap-2">
                                                <USCIcon className="w-5 h-5" /> {selectedTrade.amount}
                                            </div>
                                        </div>
                                        <div>
                                            <div className="text-xs uppercase text-slate-500 font-bold">Admin Fee (2%)</div>
                                            <div className="text-xl font-mono font-bold text-emerald-400 flex items-center gap-2">
                                                <USCIcon className="w-5 h-5" /> {(selectedTrade.amount * 0.02).toFixed(2)}
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex flex-col gap-3">
                                    <button onClick={() => approve(selectedTrade._id)} className="w-full md:w-48 py-4 bg-emerald-500 hover:bg-emerald-400 text-black font-black uppercase tracking-wider rounded-xl shadow-lg shadow-emerald-500/20 transition-all active:scale-95 flex flex-col items-center leading-none gap-1 border border-emerald-400/50">
                                        <span className="text-[10px] opacity-70">Force Action</span>
                                        <span>Release to Buyer</span>
                                    </button>
                                    <button onClick={() => reject(selectedTrade._id)} className="w-full md:w-48 py-4 bg-red-900/60 border border-red-500/50 hover:bg-red-500 hover:text-white text-red-500 font-bold uppercase tracking-wider rounded-xl transition-all flex flex-col items-center justify-center gap-1 shadow-lg shadow-red-900/20">
                                        <span className="text-[10px] opacity-80">Force Action</span>
                                        <span className="flex items-center gap-1"><Ban className="w-3 h-3" /> Refund Seller</span>
                                    </button>

                                    {/* Fail-Safe */}
                                    <button onClick={() => {
                                        setConfirmModal({
                                            isOpen: true,
                                            title: 'EMERGENCY UNLOCK',
                                            message: 'EMERGENCY: Force unlock stuck funds back to seller? This action is irreversible.',
                                            confirmText: 'FORCE UNLOCK',
                                            onConfirm: () => {
                                                setConfirmModal(prev => ({ ...prev, isOpen: false })); // Close first to run logic? or Just run logic
                                                // Actually logic is same as reject(refund)
                                                // We can re-use logic but bypassing the wrapper
                                                // Let's just call the api directly inside logic
                                                api.post('/p2p/admin/resolve', { tradeId: selectedTrade._id, resolution: 'REFUND_TO_SELLER' })
                                                    .then(() => { toast.success("FORCED UNLOCK"); fetchMarket(); setSelectedTrade(null); })
                                                    .catch(e => toast.error(e.response?.data?.message || "Failed"));
                                            }
                                        });
                                    }} className="text-[10px] text-slate-500 hover:text-red-400 underline mt-2">
                                        Manual Unlock (Emergency)
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* 2. SPLIT: PROOF & CHAT */}
                        <div className="flex-1 flex gap-6 min-h-0">
                            {/* PROOF */}
                            <div className="w-1/2 bg-black border border-white/10 rounded-2xl p-4 flex flex-col">
                                <h4 className="font-bold text-sm text-slate-400 mb-2 flex items-center gap-2"><Eye className="w-4 h-4" /> Payment Proof</h4>
                                <div className="flex-1 bg-slate-900 rounded-xl border border-white/5 flex items-center justify-center overflow-hidden relative">
                                    {selectedTrade.paymentProofUrl ? (
                                        <a href={selectedTrade.paymentProofUrl} target="_blank" rel="noreferrer" className="block w-full h-full relative group">
                                            <img src={selectedTrade.paymentProofUrl} className="w-full h-full object-contain" alt="Proof" />
                                            <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                                                <span className="bg-white text-black px-4 py-2 rounded-full font-bold text-xs">Click to Zoom</span>
                                            </div>
                                        </a>
                                    ) : (
                                        <div className="text-center text-slate-500">
                                            <Ban className="w-8 h-8 mx-auto mb-2 opacity-50" />
                                            No Proof Uploaded
                                        </div>
                                    )}
                                </div>
                            </div>

                            {/* CHAT LOGS */}
                            <div className="w-1/2 bg-[#0a0f1e] border border-white/10 rounded-2xl flex flex-col p-4">
                                <h4 className="font-bold text-sm text-slate-400 mb-2 flex items-center gap-2"><MessageSquare className="w-4 h-4" /> Live Chat Log</h4>
                                <div className="flex-1 overflow-y-auto space-y-3 pr-2">
                                    {loadingChat && <div className="text-center text-xs animate-pulse text-indigo-400"> decrypting logs...</div>}
                                    {chatHistory.map((msg, i) => (
                                        <div key={i} className={`text-xs p-2 rounded-lg ${msg.senderId === selectedTrade.buyerId._id ? 'bg-blue-900/20 text-blue-200 border border-blue-500/10 ml-0 mr-8' : 'bg-emerald-900/20 text-emerald-200 border border-emerald-500/10 ml-8 mr-0'}`}>
                                            <div className="font-bold text-[10px] opacity-50 mb-1">{msg.senderId === selectedTrade.buyerId._id ? 'BUYER' : 'SELLER'}</div>
                                            {msg.text}
                                            {msg.imageUrl && <div className="mt-1 text-[10px] text-indigo-400">[Image Attachment]</div>}
                                        </div>
                                    ))}
                                    {chatHistory.length === 0 && !loadingChat && <div className="text-center text-[10px] text-slate-600 mt-10">No messages exchanged.</div>}
                                </div>
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 bg-[#111] border border-white/5 border-dashed rounded-3xl flex items-center justify-center flex-col gap-4 text-slate-500">
                        <div className="w-20 h-20 rounded-full bg-slate-900 flex items-center justify-center">
                            <Shield className="w-10 h-10 opacity-20" />
                        </div>
                        <p>Select a trade to commence security audit.</p>
                    </div>
                )}
            </div>
            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                onConfirm={confirmModal.onConfirm}
                title={confirmModal.title}
                message={confirmModal.message}
                confirmText={confirmModal.confirmText || 'Confirm'}
            />
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import api from '../../services/api';
import { RefreshCw, Trash2, ArrowUpDown, Filter, ShieldAlert } from 'lucide-react';
import toast from 'react-hot-toast';
import ConfirmationModal from '../ui/ConfirmationModal';

export default function P2PMarketControl() {
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [confirmModal, setConfirmModal] = useState({ isOpen: false });

    // Filters
    const [typeFilter, setTypeFilter] = useState(''); // '' = All, 'BUY', 'SELL'
    const [sortFilter, setSortFilter] = useState(''); // '' = Newest, 'highest', 'lowest'

    useEffect(() => {
        fetchOrders();
    }, [typeFilter, sortFilter]);

    const fetchOrders = async () => {
        setLoading(true);
        try {
            let query = '/p2p/admin/orders?';
            if (typeFilter) query += `type=${typeFilter}&`;
            if (sortFilter) query += `sort=${sortFilter}`;

            const res = await api.get(query);
            setOrders(res.data);
        } catch (e) {
            toast.error("Failed to load active orders");
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = (orderId) => {
        setConfirmModal({
            isOpen: true,
            title: 'FORCE DELETE POST',
            message: 'Are you sure you want to forcibly delete this P2P advertisement? If it is a SELL ad, the reserved NXS amount will not be locked, it will just drop the listing.',
            confirmText: 'Delete Listing',
            onConfirm: async () => {
                try {
                    await api.delete(`/p2p/admin/orders/${orderId}`);
                    toast.success("Post successfully deleted and removed from market.");
                    fetchOrders();
                    setConfirmModal({ isOpen: false });
                } catch (e) {
                    toast.error(e.response?.data?.message || "Deletion failed");
                }
            }
        });
    };

    return (
        <div className="flex flex-col h-full bg-[#111] border border-white/10 rounded-2xl overflow-hidden font-sans">
            {/* Header / Actions */}
            <div className="p-4 border-b border-white/10 bg-slate-900/50 flex flex-col sm:flex-row justify-between items-center gap-4">
                <div className="flex items-center gap-2 text-red-500 font-bold">
                    <ShieldAlert className="w-5 h-5" /> Live Market Scanner ({orders.length})
                </div>

                <div className="flex flex-wrap items-center gap-3">
                    <select
                        value={typeFilter}
                        onChange={(e) => setTypeFilter(e.target.value)}
                        className="bg-black border border-white/20 text-white text-xs rounded-lg px-3 py-2 outline-none"
                    >
                        <option value="">All Types (Buy & Sell)</option>
                        <option value="SELL">SELL Ads (NXS to BDT)</option>
                        <option value="BUY">BUY Ads (BDT to NXS)</option>
                    </select>

                    <select
                        value={sortFilter}
                        onChange={(e) => setSortFilter(e.target.value)}
                        className="bg-black border border-white/20 text-white text-xs rounded-lg px-3 py-2 outline-none"
                    >
                        <option value="">Sort: Newest First</option>
                        <option value="highest">Sort: Highest Rate</option>
                        <option value="lowest">Sort: Lowest Rate</option>
                    </select>

                    <button onClick={fetchOrders} className="p-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg transition">
                        <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            {/* List */}
            <div className="flex-1 overflow-y-auto p-4 space-y-3">
                {orders.length === 0 && !loading && (
                    <div className="h-full flex items-center justify-center text-slate-500 text-sm">No active orders found.</div>
                )}
                {orders.map(o => (
                    <div key={o._id} className="p-4 rounded-xl bg-white/5 border border-white/5 flex flex-col sm:flex-row justify-between items-center gap-4 hover:bg-white/10 transition">
                        <div className="flex items-center gap-4 w-full sm:w-auto">
                            <div className={`text-[10px] sm:text-xs font-black px-2 py-1 rounded w-14 text-center ${o.type === 'SELL' ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400'}`}>
                                {o.type}
                            </div>
                            <div>
                                <div className="text-sm font-bold text-white mb-0.5">{o.userId?.username || 'Unknown'} <span className="text-[10px] text-slate-500 font-normal ml-1">({o.userId?.country || 'BD'})</span></div>
                                <div className="text-[10px] text-slate-400 font-mono">Limit: {o.amount} NXS via {o.paymentMethod}</div>
                            </div>
                        </div>

                        <div className="flex w-full sm:w-auto items-center justify-between sm:justify-end gap-6 border-t border-white/10 sm:border-0 pt-3 sm:pt-0">
                            <div className="text-right">
                                <div className="text-[10px] text-slate-500 uppercase font-bold tracking-wider mb-0.5">Exchange Rate</div>
                                <div className={`text-lg font-black font-mono flex items-center gap-1 ${(o.rate > 135 || o.rate < 110) ? 'text-red-500' : 'text-fuchsia-400'}`}>
                                    {o.rate} <span className="text-[10px] font-sans">BDT</span>
                                </div>
                            </div>

                            <button onClick={() => handleDelete(o._id)} className="p-3 bg-red-900/40 text-red-500 hover:bg-red-500 hover:text-white rounded-xl transition border border-red-500/30">
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                onConfirm={confirmModal.onConfirm}
                title={confirmModal.title}
                message={confirmModal.message}
                confirmText={confirmModal.confirmText || 'Confirm'}
            />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import { Terminal, RefreshCw, AlertTriangle, ShieldCheck } from 'lucide-react';

export default function SystemLogs() {
    const [logs, setLogs] = useState([]);
    const [loading, setLoading] = useState(false);

    const fetchLogs = async () => {
        setLoading(true);
        try {
            // Ensure backend has GET /api/admin/logs (It does in adminRoutes.js -> adminController.getAuditLogs)
            const { data } = await api.get('/admin/logs');
            setLogs(data);
        } catch (err) {
            console.error("Failed to fetch logs", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchLogs();
    }, []);

    return (
        <div className="bg-black/40 border border-white/10 rounded-xl overflow-hidden shadow-xl">
            {/* Header */}
            <div className="bg-gray-900/80 p-4 flex justify-between items-center border-b border-white/5">
                <h3 className="text-white font-bold flex items-center gap-2">
                    <Terminal size={18} className="text-yellow-500" />
                    System Logs & Security Audit
                </h3>
                <button
                    onClick={fetchLogs}
                    className={`p-2 rounded-lg bg-white/5 hover:bg-white/10 text-slate-300 transition ${loading ? 'animate-spin' : ''}`}
                >
                    <RefreshCw size={16} />
                </button>
            </div>

            {/* Console View */}
            <div className="p-4 h-[400px] overflow-y-auto font-mono text-xs space-y-2 bg-black/90">
                {logs.length > 0 ? logs.map((log, i) => (
                    <div key={i} className="flex gap-3 border-b border-white/5 pb-2 last:border-0 hover:bg-white/5 p-1 rounded transition">
                        <span className="text-slate-500 min-w-[130px]">{new Date(log.timestamp).toLocaleString()}</span>
                        <span className={`uppercase font-bold ${log.level === 'error' ? 'text-red-500' : (log.level === 'warn' ? 'text-orange-400' : 'text-emerald-400')}`}>
                            [{log.level || 'INFO'}]
                        </span>
                        <span className="text-slate-300 break-all">
                            {typeof log.message === 'object' ? JSON.stringify(log.message) : log.message}
                            {log.meta && <span className="text-slate-500 ml-2">{JSON.stringify(log.meta)}</span>}
                        </span>
                    </div>
                )) : (
                    <div className="text-center text-slate-500 py-20 flex flex-col items-center">
                        <ShieldCheck size={48} className="mb-4 opacity-50" />
                        <p>No verified security incidents or logs found.</p>
                        <p className="text-[10px] mt-2 opacity-50">Run internal tests to generate traffic.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import { Search, Edit, Ban, Key, RefreshCcw, Briefcase, MoreVertical, CheckCircle, XCircle, ArrowUpRight, ArrowDownLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const UserManagement = () => {
    const [users, setUsers] = useState([]);
    const [search, setSearch] = useState('');
    const [loading, setLoading] = useState(false);
    const [actionUser, setActionUser] = useState(null);
    const [password, setPassword] = useState('');
    const [filterVerified, setFilterVerified] = useState(false);
    const [filterAdminDeposit, setFilterAdminDeposit] = useState(false);

    // Quick Action Menu State
    const [openMenuId, setOpenMenuId] = useState(null);

    useEffect(() => {
        const delayDebounceFn = setTimeout(() => {
            fetchUsers();
        }, 500);
        return () => clearTimeout(delayDebounceFn);
    }, [search, filterVerified, filterAdminDeposit]);

    const fetchUsers = async () => {
        setLoading(true);
        try {
            let queryParams = [];
            if (search) queryParams.push(`search=${search}`);
            if (filterVerified) queryParams.push(`isVerified=true`);
            if (filterAdminDeposit) queryParams.push(`hasAdminDeposit=true`);

            const queryString = queryParams.length > 0 ? `?${queryParams.join('&')}` : '';
            const { data } = await api.get(`/admin/users${queryString}`);
            if (data.users) setUsers(data.users);
            else if (Array.isArray(data)) setUsers(data);
        } catch (err) {
            console.error("Failed to fetch users");
        } finally {
            setLoading(false);
        }
    };

    const handleAction = async (type, payload = {}) => {
        if (!actionUser) return;
        try {
            if (type === 'password') {
                await api.put(`/admin/users/${actionUser._id}/reset-password`, { newPassword: password });
                toast.success('Password Reset Successfully');
            } else if (type === 'status') {
                await api.put(`/admin/users/${actionUser._id}/status`, { status: payload.status });
                fetchUsers();
            } else if (type === 'promote') {
                await api.put(`/admin/users/${actionUser._id}/promote`, { tier: payload.tier });
                fetchUsers();
            } else if (type === 'toggle_verification') {
                await api.put(`/admin/user/verify-badge`, { userId: actionUser._id, isVerified: !actionUser.isVerifiedMerchant });
                toast.success('Verification Badge Updated');
                fetchUsers();
            }
            setActionUser(null);
        } catch (err) {
            toast.error('Action Failed: ' + (err.response?.data?.message || err.message));
        }
    };

    // Close menus when clicking outside
    useEffect(() => {
        const handleClickOutside = () => setOpenMenuId(null);
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, []);

    return (
        <div className="bg-[#0D0D0D] p-6 rounded-2xl border border-[#D4AF37]/20 shadow-2xl relative overflow-hidden">
            {/* Royal Glow Effect */}
            <div className="absolute top-0 right-0 w-96 h-96 bg-[#D4AF37]/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/3 pointer-events-none"></div>

            <div className="flex flex-col md:flex-row justify-between items-center mb-6 relative z-10 gap-4">
                <h2 className="text-2xl font-black text-[#D4AF37] tracking-wider uppercase flex items-center gap-2">
                    <Briefcase className="w-6 h-6" /> User Management
                </h2>

                <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
                    {/* Filters */}
                    <div className="flex items-center gap-4 text-xs font-bold text-slate-400">
                        <label className="flex items-center gap-2 cursor-pointer hover:text-[#D4AF37]">
                            <input type="checkbox" checked={filterVerified} onChange={() => setFilterVerified(!filterVerified)} className="accent-[#D4AF37] w-4 h-4 cursor-pointer" />
                            Verified Only
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer hover:text-[#D4AF37]">
                            <input type="checkbox" checked={filterAdminDeposit} onChange={() => setFilterAdminDeposit(!filterAdminDeposit)} className="accent-[#D4AF37] w-4 h-4 cursor-pointer" />
                            Admin Deposit
                        </label>
                    </div>

                    {/* Search Bar */}
                    <div className="relative w-full md:w-80 group">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-[#D4AF37] transition-colors" size={20} />
                        <input
                            type="text"
                            placeholder="Search users..."
                            className="w-full bg-[#1A1A1A] border border-white/10 rounded-full py-3 pl-12 pr-4 text-white placeholder-slate-600 focus:outline-none focus:border-[#D4AF37] focus:ring-1 focus:ring-[#D4AF37] transition-all"
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            {/* Premium Table */}
            <div className="overflow-x-auto rounded-xl border border-white/5 bg-[#0a0a0a]">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-[#151515] text-[#D4AF37] text-xs uppercase tracking-wider border-b border-white/5">
                            <th className="p-4 font-bold">User</th>
                            <th className="p-4 font-bold text-right text-emerald-400">Main Wallet</th>
                            <th className="p-4 font-bold text-right text-yellow-400">Game Wallet</th>
                            <th className="p-4 font-bold text-right text-purple-400">Income</th>
                            <th className="p-4 font-bold text-center">Status</th>
                            <th className="p-4 font-bold text-center">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/5">
                        {loading && (
                            <tr><td colSpan="6" className="p-8 text-center text-slate-500 animate-pulse">Loading Royal Database...</td></tr>
                        )}
                        {!loading && users.map(user => (
                            <tr key={user._id} className="hover:bg-white/[0.02] transition-colors text-sm group">
                                <td className="p-4">
                                    <div className="flex flex-col">
                                        <span className="font-bold text-white text-base flex items-center gap-2">
                                            {user.fullName}
                                            {user.isVerifiedMerchant && <CheckCircle size={14} className="text-blue-500 fill-blue-500/20" />}
                                        </span>
                                        <span className="text-xs text-slate-500 font-mono">@{user.username}</span>
                                        <span className="text-[10px] text-slate-600">{user.primary_phone}</span>
                                    </div>
                                </td>

                                {/* 3-Wallet Columns */}
                                <td className="p-4 text-right font-mono text-emerald-400 font-bold bg-emerald-500/5">
                                    ${(user.wallet?.main || 0).toLocaleString()}
                                </td>
                                <td className="p-4 text-right font-mono text-yellow-500 font-bold bg-yellow-500/5">
                                    ${(user.wallet?.game || 0).toLocaleString()}
                                </td>
                                <td className="p-4 text-right font-mono text-purple-400 font-bold bg-purple-500/5">
                                    ${(user.wallet?.income || 0).toLocaleString()}
                                </td>

                                <td className="p-4 text-center">
                                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase border ${user.status === 'active' ? 'border-emerald-500/30 text-emerald-400 bg-emerald-500/10' : 'border-red-500/30 text-red-400 bg-red-500/10'}`}>
                                        {user.status}
                                    </span>
                                </td>

                                <td className="p-4 text-center relative">
                                    <div className="relative inline-block" onClick={e => e.stopPropagation()}>
                                        <button
                                            onClick={() => setOpenMenuId(openMenuId === user._id ? null : user._id)}
                                            className="p-2 hover:bg-white/10 rounded-full transition text-slate-400 hover:text-white"
                                        >
                                            <MoreVertical size={16} />
                                        </button>

                                        {/* Dropdown Menu */}
                                        {openMenuId === user._id && (
                                            <div className="absolute right-0 top-full mt-2 w-48 bg-[#1A1A1A] border border-[#D4AF37]/20 rounded-xl shadow-2xl z-50 overflow-hidden flex flex-col">
                                                <button
                                                    onClick={() => { setActionUser({ ...user, action: 'adjust' }); setOpenMenuId(null); }}
                                                    className="px-4 py-3 text-left hover:bg-white/5 flex items-center gap-2 text-xs font-bold text-white transition"
                                                >
                                                    <Briefcase size={14} className="text-emerald-400" /> Adjust Balance
                                                </button>
                                                <button
                                                    onClick={() => { handleAction('status', { status: user.status === 'active' ? 'blocked' : 'active' }); setOpenMenuId(null); }}
                                                    className="px-4 py-3 text-left hover:bg-white/5 flex items-center gap-2 text-xs font-bold text-white transition"
                                                >
                                                    {user.status === 'active' ? <Ban size={14} className="text-red-400" /> : <CheckCircle size={14} className="text-green-400" />}
                                                    {user.status === 'active' ? 'Block User' : 'Activate User'}
                                                </button>
                                                <button
                                                    onClick={() => { setActionUser({ ...user, action: 'password' }); setOpenMenuId(null); }}
                                                    className="px-4 py-3 text-left hover:bg-white/5 flex items-center gap-2 text-xs font-bold text-white transition"
                                                >
                                                    <Key size={14} className="text-yellow-400" /> Reset Password
                                                </button>
                                                <button
                                                    onClick={() => { setActionUser({ ...user, action: 'promote' }); setOpenMenuId(null); }}
                                                    className="px-4 py-3 text-left hover:bg-white/5 flex items-center gap-2 text-xs font-bold text-white transition"
                                                >
                                                    <ArrowUpRight size={14} className="text-purple-400" /> Manage Tier
                                                </button>
                                                <button
                                                    onClick={() => { setActionUser(user); handleAction('toggle_verification'); setOpenMenuId(null); }}
                                                    className="px-4 py-3 text-left hover:bg-white/5 flex items-center gap-2 text-xs font-bold text-blue-400 transition border-t border-white/10"
                                                >
                                                    <CheckCircle size={14} /> {user.isVerifiedMerchant ? 'Remove Verification' : 'Verify Merchant'}
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Modals reused from original structure but restyled */}
            {actionUser && actionUser.action === 'adjust' && (
                <AdjustBalanceModal
                    user={actionUser}
                    onClose={() => setActionUser(null)}
                    onSuccess={() => { setActionUser(null); fetchUsers(); }}
                />
            )}

            {actionUser && actionUser.action === 'password' && (
                <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <div className="bg-[#151515] p-6 rounded-2xl border border-[#D4AF37]/30 w-full max-w-sm shadow-[0_0_50px_rgba(212,175,55,0.2)]">
                        <h3 className="text-lg font-bold text-[#D4AF37] mb-4 uppercase tracking-widest">Reset Password</h3>
                        <input
                            type="text"
                            placeholder="New Password"
                            className="w-full bg-black border border-white/10 p-3 rounded-xl mb-4 text-white focus:border-[#D4AF37] outline-none"
                            onChange={(e) => setPassword(e.target.value)}
                        />
                        <div className="flex justify-end gap-2">
                            <button onClick={() => setActionUser(null)} className="px-4 py-2 text-slate-400 hover:text-white transition">Cancel</button>
                            <button onClick={() => handleAction('password')} className="px-6 py-2 bg-[#D4AF37] hover:bg-[#b08d26] text-black font-black rounded-xl transition">RESET</button>
                        </div>
                    </div>
                </div>
            )}

            {actionUser && actionUser.action === 'promote' && (
                <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <div className="bg-[#151515] p-6 rounded-2xl border border-[#D4AF37]/30 w-full max-w-sm shadow-[0_0_50px_rgba(212,175,55,0.2)]">
                        <h3 className="text-lg font-bold text-[#D4AF37] mb-4 uppercase tracking-widest">Change Tier</h3>
                        <div className="grid grid-cols-1 gap-2 mb-4">
                            {['Standard', 'Premium', 'Platinum'].map(tier => (
                                <button
                                    key={tier}
                                    onClick={() => handleAction('promote', { tier })}
                                    className="p-4 bg-white/5 hover:bg-[#D4AF37] hover:text-black rounded-xl border border-white/10 text-left text-white transition font-bold"
                                >
                                    {tier}
                                </button>
                            ))}
                        </div>
                        <button onClick={() => setActionUser(null)} className="w-full py-2 text-slate-400 hover:text-white transition">Cancel</button>
                    </div>
                </div>
            )}
        </div>
    );
};

const AdjustBalanceModal = ({ user, onClose, onSuccess }) => {
    const [amount, setAmount] = useState('');
    const [type, setType] = useState('credit');
    const [walletType, setWalletType] = useState('main');
    const [comment, setComment] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async () => {
        if (!amount || parseFloat(amount) <= 0) return toast.error('Invalid Amount');
        setLoading(true);
        try {
            await api.post(`/admin/user/${user._id}/balance`, {
                amount: parseFloat(amount),
                type,
                walletType,
                comment
            });
            toast.success('Balance Updated Successfully');
            onSuccess();
        } catch (err) {
            toast.error('Error: ' + (err.response?.data?.message || err.message));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-[#151515] p-6 rounded-2xl border border-[#D4AF37]/30 w-full max-w-md shadow-[0_0_50px_rgba(212,175,55,0.2)]">
                <h3 className="text-lg font-bold text-[#D4AF37] mb-6 uppercase tracking-widest border-b border-white/10 pb-4">
                    Adjust Balance <span className="text-white block text-sm normal-case mt-1 opacity-50">{user.fullName} (@{user.username})</span>
                </h3>

                {/* Wallet Select */}
                <div className="mb-6">
                    <label className="text-[10px] text-slate-400 font-bold uppercase block mb-2 tracking-wider">Target Wallet</label>
                    <div className="grid grid-cols-3 gap-2">
                        {['main', 'game', 'income'].map(w => (
                            <button
                                key={w}
                                onClick={() => setWalletType(w)}
                                className={`py-3 text-xs uppercase font-black rounded-xl border transition-all ${walletType === w
                                    ? 'bg-[#D4AF37] text-black border-[#D4AF37]'
                                    : 'bg-black border-white/10 text-slate-500 hover:border-white/30'
                                    }`}
                            >
                                {w}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Amount */}
                <div className="mb-6 relative">
                    <label className="text-[10px] text-slate-400 font-bold uppercase block mb-2 tracking-wider">Amount</label>
                    <input
                        type="number"
                        placeholder="0.00"
                        className="w-full bg-black border border-white/10 p-4 rounded-xl text-white font-black text-2xl focus:border-[#D4AF37] outline-none"
                        value={amount}
                        onChange={(e) => setAmount(e.target.value)}
                    />
                </div>

                {/* Action Type */}
                <div className="grid grid-cols-2 gap-3 mb-6">
                    <button onClick={() => setType('credit')} className={`p-4 rounded-xl border font-black flex flex-col items-center gap-1 transition-all ${type === 'credit' ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' : 'bg-black border-white/10 text-slate-500'}`}>
                        <ArrowUpRight size={20} /> ADD FUNDS
                    </button>
                    <button onClick={() => setType('debit')} className={`p-4 rounded-xl border font-black flex flex-col items-center gap-1 transition-all ${type === 'debit' ? 'bg-red-500/20 border-red-500 text-red-400' : 'bg-black border-white/10 text-slate-500'}`}>
                        <ArrowDownLeft size={20} /> DEDUCT FUNDS
                    </button>
                </div>

                {/* Comment */}
                <input
                    type="text"
                    placeholder="Reason for adjustment..."
                    className="w-full bg-black border border-white/10 p-3 rounded-xl mb-6 text-white text-sm focus:border-[#D4AF37] outline-none"
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                />

                <div className="flex justify-end gap-3 pt-4 border-t border-white/10">
                    <button onClick={onClose} className="px-6 py-3 text-slate-400 font-bold hover:text-white transition" disabled={loading}>Cancel</button>
                    <button onClick={handleSubmit} disabled={loading} className="px-8 py-3 bg-[#D4AF37] hover:bg-[#b08d26] text-black font-black rounded-xl transition shadow-lg shadow-[#D4AF37]/20">
                        {loading ? 'Processing...' : 'CONFIRM ADJUSTMENT'}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default UserManagement;

