            <p className="text-xs text-slate-600 mt-2">Check back later or auto-create in Admin.</p>
        </div>
    );

    return (
        <div className="relative w-full shadow-2xl mx-auto perspective-1000">
            {/* Same styles ... */}
            <style jsx>{`
                @keyframes smoke {
