                                                >
                                                    {t}
                                                </button>
                                            ))}
                                        </div>
                                    )}

                                    <div className="space-y-1">
                                        <input
                                            type="text"
                                            required
                                            value={takerPaymentDetails}
                                            onChange={(e) => setTakerPaymentDetails(e.target.value)}
