'use client';
import { useState, useEffect } from 'react';
import api from '../../services/api';
import { RefreshCw, Plus, Search, Filter, DollarSign, ArrowRight, ArrowLeft, User, ShieldCheck, Clock, Globe2, ArrowDownCircle, ArrowUpCircle, Zap, TrendingUp, BarChart2 } from 'lucide-react';
import OrderCreationModal from './OrderCreationModal';
import BuyOrderModal from './BuyOrderModal';
import P2PChatRoom from './P2PChatRoom';
import { useRouter, useSearchParams } from 'next/navigation';
import { useSocket } from '../../hooks/useSocket';
import { useAuth } from '../../hooks/useAuth';
import { useNotification } from '../../hooks/useNotification';
import RatingModal from './RatingModal';
import ConfirmationModal from '../ui/ConfirmationModal';
import toast from 'react-hot-toast';
import { P2PSkeleton } from '../ui/SkeletonLoader';
import { ResponsiveContainer, AreaChart, Area, XAxis, YAxis, Tooltip } from 'recharts';


export default function P2PDashboard({ initialMode, onClose }) {
    const { user } = useAuth();
    const userCountry = user?.country?.toUpperCase() || 'BD';
    const [mode, setMode] = useState(initialMode || 'buy'); // 'buy', 'sell', 'history', 'my_ads'

    // [NEW] Global Advanced Filters
    const [filters, setFilters] = useState({
        sort: '', // 'lowest', 'highest'
        country: 'all',
        paymentMethod: 'all'
    });

    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(1);
    const [hasMore, setHasMore] = useState(true);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [activeTradeId, setActiveTradeId] = useState(null);
    const [ratingTradeId, setRatingTradeId] = useState(null);
    const [buyModalConfig, setBuyModalConfig] = useState({ isOpen: false, order: null });
    const [modal, setModal] = useState({ isOpen: false, title: '', message: '', onConfirm: null });
    const router = useRouter(); // [FIX] Initialize hook here
    const searchParams = useSearchParams();
    const tradeQueryId = searchParams ? searchParams.get('tradeId') : null;
    const { permission, requestPermission, notify, playSound } = useNotification();
    
    // [NEW] Global Running Trades Count for Smart Banner
    const [runningCount, setRunningCount] = useState(0);


    const [marketStats, setMarketStats] = useState({ price: 0, high: 0, low: 0, vol: 0, change: 0 });

    // [FIX] Use System Namespace to match Backend
    const socket = useSocket('/system');

    const checkRunningTrades = async () => {
        try {
            if (!user) return;
            const res = await api.get('/p2p/my-trades');
            const active = res.data.filter(t => ['CREATED', 'PAID', 'AWAITING_ADMIN', 'DISPUTED'].includes(t.status));
            setRunningCount(active.length);
        } catch(e){}
    };

    useEffect(() => {
        fetchOrders();
        fetchStats();
        checkRunningTrades();

        if (socket) {
            const handleAlert = () => fetchOrders();
            const handleCompleted = (trade) => {
                console.log("P2P Completed Event Received - Refreshing Orders");
                setOrders(prev => prev.map(o => o._id === trade._id ? { ...o, ...trade } : o));
                if (mode === 'buy' || mode === 'sell') fetchOrders();
                setRatingTradeId(trade._id);
                checkRunningTrades();
            };
            const handleMarkPaid = (trade) => {
                setOrders(prev => prev.map(o => o._id === trade._id ? { ...o, ...trade } : o));
            };
            const handleDispute = (trade) => {
                setOrders(prev => prev.map(o => o._id === trade._id ? { ...o, ...trade } : o));
            };
            const handleTradeStart = (trade) => {
                checkRunningTrades();
                if (trade.sellerId === user?._id || trade.buyerId === user?._id) {
                    setActiveTradeId(trade._id);
                    localStorage.setItem('active_p2p_trade', trade._id);
                } else if (mode === 'buy' || mode === 'sell') {
                    fetchOrders();
                }
            };

            socket.on('p2p_alert', handleAlert);
            socket.on('p2p_completed', handleCompleted);
            socket.on('p2p_mark_paid', handleMarkPaid);
            socket.on('p2p_trade_dispute', handleDispute);
            socket.on('p2p_trade_start', handleTradeStart);

            return () => {
                socket.off('p2p_alert', handleAlert);
                socket.off('p2p_completed', handleCompleted);
                socket.off('p2p_mark_paid', handleMarkPaid);
                socket.off('p2p_trade_dispute', handleDispute);
                socket.off('p2p_trade_start', handleTradeStart);
            };
        }

        return () => {}; // fallback if no socket
    }, [mode, filters, socket, user]);

    async function fetchStats() {
        try {
            const res = await api.get('/p2p/summary');
            if (res.data) setMarketStats(res.data);
        } catch (e) { console.error("Stats API failed", e); }
    }

    async function fetchOrders(isLoadMore = false) {
        const fetchPage = isLoadMore ? page + 1 : 1;
        if (!isLoadMore) {
            setLoading(true);
            setHasMore(true);
        }

        try {
            if (mode === 'buy' || mode === 'sell') {
                const targetAdType = mode === 'buy' ? 'SELL' : 'BUY';
                const query = new URLSearchParams({
                    type: targetAdType,
                    page: fetchPage,
                    limit: 10,
                    ...(filters.sort && { sort: filters.sort }),
                    ...(filters.country !== 'all' && { country: filters.country }),
                    ...(filters.paymentMethod !== 'all' && { paymentMethod: filters.paymentMethod })
                }).toString();

                const res = await api.get(`/p2p/market?${query}`);

                if (isLoadMore) {
                    setOrders(prev => [...prev, ...res.data]);
                    setPage(fetchPage);
                } else {
                    setOrders(res.data);
                    setPage(1);
                }

                if (res.data.length < 10) setHasMore(false);

            } else if (mode === 'my_ads') {
                const res = await api.get('/p2p/my-orders');
                setOrders(res.data);
                setHasMore(false);
            } else if (mode === 'active' || mode === 'history') {
                const res = await api.get('/p2p/my-trades');
                if (mode === 'active') {
                    setOrders(res.data.filter(t => ['CREATED', 'PAID', 'AWAITING_ADMIN', 'DISPUTED'].includes(t.status)));
                } else {
                    setOrders(res.data.filter(t => ['COMPLETED', 'CANCELLED', 'RESOLVED_BUYER', 'RESOLVED_SELLER'].includes(t.status)));
                }
                setHasMore(false);
            }
        } catch (e) {
            console.error(e);
            if (!isLoadMore) setOrders([]);
        }
        setLoading(false);
    }

    const handleTradeAction = (order) => {
        // [LIVE BALANCE CHECK] For SELL ads only (We are buying)
        if (order.type === 'SELL') {
            const liveAvailable = order.userId?.wallet?.main || 0;
            const maxLimit = Math.min(order.amount, liveAvailable);
            if (maxLimit <= 0) return toast.error("Seller has no balance available right now.");
        }

        // [LIVE BALANCE CHECK] For BUY ads only (We are selling)
        if (order.type === 'BUY') {
            const myBalance = user?.wallet?.main || 0;
            if (myBalance <= 0) return toast.error("Your balance is zero. You cannot sell NXS.");
        }

        setBuyModalConfig({ isOpen: true, order });
    };

    const confirmTrade = (requestedAmount, takerPaymentDetails, transactionType) => {
        const order = buyModalConfig.order;
        const actionWord = order.type === 'SELL' ? 'buy' : 'sell';

        setBuyModalConfig({ isOpen: false, order: null });

        setModal({
            isOpen: true,
            title: `Confirm ${actionWord.toUpperCase()}`,
            message: `You are about to ${actionWord} ${requestedAmount} NXS. Proceed?`,
            confirmText: 'Confirm Trade',
            onConfirm: async () => {
                try {
                    const res = await api.post(`/p2p/buy/${order._id}`, { requestedAmount, takerPaymentDetails, transactionType });
                    if (res.data.success) {
                        toast.success("Trade Started Successfully!");
                        router.push(`/p2p?tradeId=${res.data.trade._id}`); // [FIX] Auto-Jump securely via URL
                    }
                } catch (e) {
                    toast.error(e.response?.data?.message || "Failed to start trade");
                }
            }
        });
    };

    const handleCancelOrder = async (orderId) => {
        if (!confirm("Are you sure you want to cancel this listing?")) return;
        try {
            const res = await api.post(`/p2p/sell/${orderId}/cancel`);
            if (res.data.success) {
                toast.success("Order Cancelled Successfully");
                fetchOrders();
            }
        } catch (e) {
            toast.error(e.response?.data?.message || "Failed to cancel order");
        }
    };

    useEffect(() => {
        if (tradeQueryId) {
            setActiveTradeId(tradeQueryId);
            localStorage.setItem('active_p2p_trade', tradeQueryId);
        } else {
            const savedTrade = localStorage.getItem('active_p2p_trade');
            if (savedTrade) setActiveTradeId(savedTrade);
        }
    }, [tradeQueryId]);

    // Clear on exit
    const exitTrade = () => {
        setActiveTradeId(null);
        localStorage.removeItem('active_p2p_trade');
        router.replace('/p2p'); // Clear URL query so it doesn't auto-reopen
    };

    const getMethodStyle = (method) => {
        const m = method.toLowerCase();
        if (m === 'bkash') return 'bg-pink-500/10 text-pink-400 border-pink-500/20';
        if (m === 'nagad') return 'bg-orange-500/10 text-orange-400 border-orange-500/20';
        if (m === 'binance' || m === 'binance pay') return 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20';
        if (m === 'gpay' || m === 'google pay') return 'bg-blue-500/10 text-blue-400 border-blue-500/20';
        return 'bg-[#1a2c3d] text-cyan-400 border-cyan-500/20';
    };

    const displayOrders = orders;

    // If active trade, show Chat Room
    if (activeTradeId) {
        return <P2PChatRoom tradeId={activeTradeId} onBack={exitTrade} />;
    }

    // [NEW/PSYCHOLOGICAL] Calculate VIP Fee Tier
    const getFeeTier = (count) => {
        if (count >= 500) return { name: 'WHALE', fee: '0.07%', color: 'text-purple-400 bg-purple-500/10 border-purple-500/30 shadow-[0_0_10px_rgba(168,85,247,0.2)]' };
        if (count >= 250) return { name: 'EXPERT', fee: '0.25%', color: 'text-blue-400 bg-blue-500/10 border-blue-500/30 shadow-[0_0_10px_rgba(59,130,246,0.2)]' };
        if (count >= 100) return { name: 'PRO', fee: '0.50%', color: 'text-[#fcd535] bg-[#fcd535]/10 border-[#fcd535]/30' };
        if (count >= 20) return { name: 'TRADER', fee: '0.80%', color: 'text-[#0ecb81] bg-[#0ecb81]/10 border-[#0ecb81]/30' };
        return { name: 'NEWBIE', fee: '1.00%', color: 'text-[#848e9c] bg-[#2b3139]' };
    };
    const userTier = getFeeTier(user?.completedTrades || 0);

    return (
        <div className="min-h-screen bg-[#0b0e11] text-[#eaeaec] font-sans pb-24 overflow-x-hidden">

            {/* Notification Permission Banner */}
            {permission === 'default' && (
                <div className="bg-[#fcd535] text-black px-4 py-2 flex justify-between items-center text-xs font-bold w-full top-0 left-0 z-50">
                    <span>Enable Push Notifications for Trade Alerts!</span>
                    <button onClick={requestPermission} className="bg-black text-white px-3 py-1 rounded">Enable</button>
                </div>
            )}

            {/* Smart Running Banner */}
            {runningCount > 0 && mode !== 'active' && !activeTradeId && (
                <div 
                    onClick={() => setMode('active')}
                    className="bg-[#fcd535]/10 text-[#fcd535] border-b border-[#fcd535]/20 px-4 py-3 flex justify-between items-center cursor-pointer hover:bg-[#fcd535]/20 transition"
                >
                    <div className="flex items-center gap-2">
                        <Clock className="w-5 h-5 animate-spin-slow" style={{ animationDuration: '3s' }} />
                        <span className="text-xs font-bold font-mono tracking-wide">You have {runningCount} Running Trade{runningCount > 1 ? 's' : ''}!</span>
                    </div>
                    <button className="text-[10px] bg-[#fcd535] text-black px-4 py-1.5 rounded font-black uppercase tracking-wider shadow-[0_0_10px_rgba(252,213,53,0.3)] animate-pulse hover:scale-105 transition">
                        View Now
                    </button>
                </div>
            )}

            {/* Header */}
            <div className="flex justify-between items-center p-4 bg-[#181a20] border-b border-[#2b3139]">
                <div className="flex items-center gap-3">
                    <button onClick={onClose || (() => router.back())} className="text-[#848e9c] hover:text-[#eaeaec] transition">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-xl font-black text-[#eaeaec] flex items-center gap-2">
                            P2P Market
                        </h1>
                        <p className="text-[10px] text-[#848e9c] font-bold uppercase tracking-widest flex items-center gap-1">
                            <ShieldCheck className="w-3 h-3 text-[#0ecb81]" /> Escrow Active
                        </p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <button onClick={fetchOrders} className="text-[#848e9c] hover:text-[#eaeaec] transition">
                        <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin text-[#fcd535]' : ''}`} />
                    </button>
                </div>
            </div>

            {/* Trading View / Market Stats Header */}
            <div className="p-4 bg-[#181a20] border-b border-[#2b3139]">
                <div className="flex items-end justify-between">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <h2 className="text-2xl font-black text-[#eaeaec]">NXS / USD</h2>
                            <span className="text-[10px] bg-[#2b3139] text-[#848e9c] px-2 py-0.5 rounded font-bold">P2P</span>
                        </div>
                        <div className="flex items-center gap-2 mt-1">
                            <span className="text-lg font-bold text-[#0ecb81]">{marketStats.price ? marketStats.price.toFixed(2) : '---'}</span>
                            <div className={`text-[10px] font-black px-2 py-0.5 rounded flex items-center gap-1 border ${userTier.color}`}>
                                <Zap className="w-3 h-3" /> {userTier.name} FEE: {userTier.fee}
                            </div>
                        </div>
                    </div>
                    <div className="flex gap-4 text-right">
                        <div>
                            <div className="text-[9px] text-[#848e9c] uppercase font-bold tracking-widest mb-0.5">24h High</div>
                            <div className="text-[11px] font-mono text-[#eaeaec]">{marketStats.high ? marketStats.high.toFixed(2) : '---'}</div>
                        </div>
                        <div>
                            <div className="text-[9px] text-[#848e9c] uppercase font-bold tracking-widest mb-0.5">24h Low</div>
                            <div className="text-[11px] font-mono text-[#eaeaec]">{marketStats.low ? marketStats.low.toFixed(2) : '---'}</div>
                        </div>
                        <div className="hidden sm:block">
                            <div className="text-[9px] text-[#848e9c] uppercase font-bold tracking-widest mb-0.5">24h Vol</div>
                            <div className="text-[11px] font-mono text-[#eaeaec]">{marketStats.vol ? (marketStats.vol > 1000 ? (marketStats.vol / 1000).toFixed(1) + 'K' : marketStats.vol) : '---'}</div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Price Chart */}
            {(mode === 'buy' || mode === 'sell' || mode === 'active' || mode === 'history') && marketStats?.chartData && marketStats.chartData.length > 0 && (
                <div className="bg-[#181a20] border-b border-[#2b3139] px-2 py-4 h-[140px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={marketStats.chartData}>
                            <defs>
                                <linearGradient id="colorPrice" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#0ecb81" stopOpacity={0.4} />
                                    <stop offset="95%" stopColor="#0ecb81" stopOpacity={0} />
                                </linearGradient>
                            </defs>
                            <YAxis
                                domain={[marketStats.minBoundary || 'dataMin', marketStats.maxBoundary || 'dataMax']}
                                hide
                            />
                            <Tooltip
                                contentStyle={{ backgroundColor: '#1e2329', border: '1px solid #2b3139', borderRadius: '8px', fontSize: '10px', color: '#848e9c' }}
                                itemStyle={{ color: '#0ecb81', fontWeight: 'bold' }}
                                labelStyle={{ color: '#eaeaec', marginBottom: '4px' }}
                                formatter={(value) => [`${value} $`, 'Price']}
                            />
                            <Area
                                type="monotone"
                                dataKey="price"
                                stroke="#0ecb81"
                                strokeWidth={2}
                                fillOpacity={1}
                                fill="url(#colorPrice)"
                                isAnimationActive={true}
                                animationDuration={1500}
                                animationEasing="ease-in-out"
                            />
                        </AreaChart>
                    </ResponsiveContainer>
                </div>
            )}

            {/* Sleek Tabs */}
            <div className="flex bg-[#181a20] px-3 overflow-x-auto scrollbar-none border-b border-[#2b3139]">
                {['buy', 'sell', 'active', 'history', 'my_ads'].map(t => (
                    <button
                        key={t}
                        onClick={() => setMode(t)}
                        className={`px-4 py-3 text-sm font-black tracking-wide transition relative whitespace-nowrap ${mode === t ? (t === 'active' ? 'text-[#fcd535] animate-pulse' : t === 'buy' ? 'text-[#0ecb81]' : t === 'sell' ? 'text-[#f6465d]' : 'text-white') : 'text-[#848e9c] hover:text-[#eaeaec]'}`}
                    >
                        {t === 'active' ? '⏳ RUNNING' : t === 'history' ? '📜 HISTORY' : t.replace('_', ' ').toUpperCase()}
                        {mode === t && (
                            <div className={`absolute bottom-0 left-0 w-full h-[3px] rounded-t-full ${t === 'buy' ? 'bg-[#0ecb81]' : t === 'sell' ? 'bg-[#f6465d]' : 'bg-[#fcd535]'}`} />
                        )}
                    </button>
                ))}
            </div>

            {/* 4. Stable "Post Ad" Button (Right below Tabs/"Function") */}
            <div className="px-4 py-3 bg-[#0b0e11] border-b border-[#2b3139]/30">
                <button
                    onClick={() => setShowCreateModal(true)}
                    className="w-full py-3 bg-[#fcd535] hover:bg-[#e6c130] text-black rounded-xl font-black flex items-center justify-center gap-2 transition-all shadow-[0_4px_15px_rgba(252,213,53,0.15)] active:scale-[0.98]"
                >
                    <Plus className="w-5 h-5" /> POST NEW AD
                </button>
            </div>

            {/* Advanced Filters */}
            {(mode === 'buy' || mode === 'sell') && (
                <div className="p-3 bg-[#0b0e11]">
                    <div className="flex bg-[#181a20] rounded-lg p-1 border border-[#2b3139]">
                        <select
                            value={filters.country}
                            onChange={(e) => setFilters(f => ({ ...f, country: e.target.value }))}
                            className="flex-1 bg-transparent text-[#eaeaec] text-xs font-bold px-2 py-2 outline-none border-r border-[#2b3139] appearance-none"
                        >
                            <option value="all">🌐 Any Country</option>
                            <option value="BD">🇧🇩 Bangladesh</option>
                            <option value="IN">🇮🇳 India</option>
                            <option value="GLOBAL">🌍 Global</option>
                        </select>
                        <select
                            value={filters.paymentMethod}
                            onChange={(e) => setFilters(f => ({ ...f, paymentMethod: e.target.value }))}
                            className="flex-1 bg-transparent text-[#eaeaec] text-xs font-bold px-2 py-2 outline-none border-r border-[#2b3139] appearance-none"
                        >
                            <option value="all">All Payments</option>
                            <option value="bkash">bKash</option>
                            <option value="nagad">Nagad</option>
                            <option value="binance">Binance</option>
                        </select>
                        <select
                            value={filters.sort}
                            onChange={(e) => setFilters(f => ({ ...f, sort: e.target.value }))}
                            className="flex-1 bg-transparent text-[#eaeaec] text-xs font-bold px-2 py-2 outline-none appearance-none"
                        >
                            <option value="">Sort: Best Rate</option>
                            <option value="lowest">Lowest Price</option>
                            <option value="highest">Highest Price</option>
                        </select>
                    </div>
                </div>
            )}

            {/* Order List */}
            <div className="pb-32 px-1">
                {mode === 'active' || mode === 'history' ? (
                    loading ? <P2PSkeleton /> :
                        orders.length === 0 ? <div className="text-center py-10 text-[#848e9c]">No Trades Found</div> :
                            orders.map(trade => (
                                <div key={trade._id} className="bg-[#181a20] mb-2 p-3 flex flex-col hover:bg-[#1e2329] transition group cursor-pointer" onClick={() => { setActiveTradeId(trade._id); localStorage.setItem('active_p2p_trade', trade._id); }}>
                                    <div className="flex justify-between items-center mb-2">
                                        <div className="flex items-center gap-2">
                                            <span className={`text-[9px] px-1.5 py-0.5 rounded font-bold uppercase ${trade.status === 'COMPLETED' ? 'bg-[#0ecb81]/10 text-[#0ecb81]' : trade.status === 'CANCELLED' ? 'bg-[#2b3139] text-[#848e9c]' : trade.status === 'DISPUTED' ? 'bg-[#f6465d]/10 text-[#f6465d]' : 'bg-[#fcd535]/10 text-[#fcd535]'}`}>
                                                {trade.status}
                                            </span>
                                            <span className="text-[10px] text-[#848e9c] font-mono">#{trade._id.substr(-6)}</span>
                                        </div>
                                        <div className="text-[10px] text-[#848e9c]">
                                            {new Date(trade.createdAt).toLocaleDateString()}
                                        </div>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <div>
                                            <div className="text-sm font-bold text-[#eaeaec] flex items-center gap-1">
                                                {trade.amount} NXS
                                            </div>
                                            <div className="text-[10px] text-[#848e9c] mt-0.5">
                                                Total: {((trade.amount / 50) * (trade.orderId?.rate || 1.3)).toLocaleString('en-IN', { maximumFractionDigits: 2 })} {trade.orderId?.fiatCurrency || 'BDT'}
                                            </div>
                                        </div>
                                        <div className="text-right flex items-center gap-2 text-[#848e9c] group-hover:text-[#eaeaec] transition">
                                            <span className="text-[10px] uppercase font-bold">{trade.orderId?.type === 'SELL' ? 'Bought' : 'Sold'}</span>
                                            <ArrowRight className="w-4 h-4" />
                                        </div>
                                    </div>
                                </div>
                            ))
                ) : (
                    /* Exchange Style Order Book View */
                    loading ? <P2PSkeleton /> :
                        orders.length === 0 ? <div className="text-center py-10 text-[#848e9c]">No Ads Match criteria</div> :
                            displayOrders.map(order => (
                                <div key={order._id} className="bg-[#181a20] mb-2 p-3 hover:bg-[#1e2329] transition relative">
                                    {/* Top Row: User Info */}
                                    <div className="flex items-center gap-2 mb-3">
                                        <div className="w-6 h-6 rounded-full bg-[#2b3139] flex items-center justify-center text-[10px] font-bold text-[#848e9c]">
                                            {order.userId?.username?.charAt(0) || 'U'}
                                        </div>
                                        <span className="font-bold text-sm text-[#eaeaec] truncate max-w-[120px]">
                                            {order.userId?.username || `User`}
                                        </span>
                                        {order.userId?.isVerifiedMerchant && (
                                            <div className="flex items-center justify-center bg-[#fcd535]/10 p-1 rounded">
                                                <ShieldCheck className="w-3.5 h-3.5 text-[#fcd535]" />
                                            </div>
                                        )}
                                        <div className="flex gap-2 text-[10px] text-[#848e9c] ml-auto">
                                            <span>{order.userId?.completedTrades || 0} trades</span>
                                            <span>{order.userId?.trustScore || 100}%</span>
                                        </div>
                                    </div>

                                    {/* Middle Row: Price, Limits and Action */}
                                    <div className="flex justify-between items-start mb-3">
                                        <div className="flex flex-col gap-1.5">
                                            <div className="text-lg font-black font-mono text-[#eaeaec] leading-none">
                                                {order.rate || 1.3} <span className="text-[10px] text-[#848e9c] ml-0.5">{order.fiatCurrency || 'BDT'} / 50 NXS</span>
                                            </div>
                                            <div className="flex items-center gap-2 text-[10px]">
                                                <span className="text-[#848e9c] w-12 border-b border-dashed border-[#2b3139]">Amount</span>
                                                <span className="text-[#eaeaec] font-mono">{order.amount.toLocaleString()} NXS</span>
                                            </div>
                                            <div className="flex items-center gap-2 text-[10px]">
                                                <span className="text-[#848e9c] w-12 border-b border-dashed border-[#2b3139]">Fiat Vol</span>
                                                <span className="text-[#eaeaec] font-mono">{((order.amount / 50) * (order.rate || 1.3)).toLocaleString('en-IN', { maximumFractionDigits: 2 })} {order.fiatCurrency || 'BDT'}</span>
                                            </div>
                                        </div>

                                        <div className="flex flex-col items-end justify-between h-full gap-2">
                                            {mode === 'my_ads' ? (
                                                <div className="text-right">
                                                    <div className={`text-[9px] font-black uppercase tracking-widest mb-1.5 ${order.status === 'OPEN' ? (order.type === 'BUY' ? 'text-[#0ecb81]' : 'text-[#f6465d]') : 'text-[#848e9c]'}`}>
                                                        {order.type} • {order.status}
                                                    </div>
                                                    {order.status === 'OPEN' && (
                                                        <button
                                                            onClick={(e) => { e.stopPropagation(); handleCancelOrder(order._id); }}
                                                            className="text-[10px] text-[#f6465d] bg-[#f6465d]/10 hover:bg-[#f6465d]/20 font-bold px-4 py-1.5 rounded transition"
                                                        >
                                                            CANCEL
                                                        </button>
                                                    )}
                                                </div>
                                            ) : (
                                                <button
                                                    onClick={() => handleTradeAction(order)}
                                                    disabled={order.status !== 'OPEN'}
                                                    className={`px-6 py-2 rounded font-bold text-xs uppercase transition-all ${order.status !== 'OPEN' ? 'bg-[#2b3139] text-[#848e9c]' : (order.type === 'SELL' ? 'bg-[#0ecb81] hover:bg-[#0b9e65] text-black' : 'bg-[#f6465d] hover:bg-[#c93046] text-white')}`}
                                                >
                                                    {order.status !== 'OPEN' ? 'Taken' : (order.type === 'SELL' ? 'Buy' : 'Sell')}
                                                </button>
                                            )}
                                        </div>
                                    </div>

                                    {/* Bottom Row: Payments */}
                                    <div className="flex gap-1.5 items-center">
                                        <div className="w-1 h-3 rounded-full bg-[#fcd535]"></div>
                                        <span className="text-[10px] uppercase font-bold text-[#eaeaec]">{order.paymentMethod}</span>
                                    </div>
                                </div>
                            ))
                )}

                {/* Pagination Trigger */}
                {(mode === 'buy' || mode === 'sell') && hasMore && (
                    <div className="flex justify-center p-4">
                        <button
                            onClick={() => fetchOrders(true)}
                            className="px-6 py-2 bg-[#2b3139] hover:bg-[#fcd535] hover:text-black rounded text-sm font-bold transition text-[#848e9c]"
                        >
                            Load More
                        </button>
                    </div>
                )}

                {!loading && displayOrders.length === 0 && (
                    <div className="text-center text-[#848e9c] py-20 flex flex-col items-center gap-3">
                        <div className="w-16 h-16 rounded-full bg-[#181a20] flex items-center justify-center">
                            <Search className="w-6 h-6" />
                        </div>
                        <p className="font-bold">No Ads Match criteria</p>
                    </div>
                )}
            </div>

            {/* Modals */}
            <OrderCreationModal
                isOpen={showCreateModal}
                onClose={() => setShowCreateModal(false)}
                onSuccess={(adMode) => {
                    setShowCreateModal(false);
                    // If they posted a BUY ad (they want NXS, payer will send Fiat), they might want to see Sellers
                    // If they posted a SELL ad (they want Fiat, buyer will send Fiat), they might want to see Buyers
                    // Default to 'buy' (Marketplace list) so they aren't stuck on 'my_ads'
                    setMode('buy');
                    fetchOrders();
                }}
            />
            <BuyOrderModal
                isOpen={buyModalConfig.isOpen}
                onClose={() => setBuyModalConfig({ isOpen: false, order: null })}
                order={buyModalConfig.order}
                onConfirm={confirmTrade}
                currentUserBalance={user?.wallet?.main || 0}
            />
            {ratingTradeId && <RatingModal tradeId={ratingTradeId} onClose={() => setRatingTradeId(null)} onSuccess={() => setRatingTradeId(null)} />}
            <ConfirmationModal isOpen={modal.isOpen} onClose={() => setModal({ ...modal, isOpen: false })} onConfirm={modal.onConfirm} title={modal.title} message={modal.message} confirmText={modal.confirmText || 'Confirm'} />
        </div>
    );
}

'use client';
import { useState, useCallback } from 'react';
import Cropper from 'react-easy-crop';
import { Slider } from 'lucide-react'; // Using Lucide icon as placeholder or UI element is fine
import { getCroppedImg } from './cropUtils'; // Helper function we will create
import { X, Check } from 'lucide-react';

export default function ImageCropper({ imageSrc, onCropComplete, onCancel }) {
    const [crop, setCrop] = useState({ x: 0, y: 0 });
    const [zoom, setZoom] = useState(1);
    const [croppedAreaPixels, setCroppedAreaPixels] = useState(null);

    const onCropChange = (crop) => {
        setCrop(crop);
    };

    const onZoomChange = (zoom) => {
        setZoom(zoom);
    };

    const onCropCompleteHandler = useCallback((croppedArea, croppedAreaPixels) => {
        setCroppedAreaPixels(croppedAreaPixels);
    }, []);

    const showCroppedImage = async () => {
        try {
            const croppedImage = await getCroppedImg(imageSrc, croppedAreaPixels);
            onCropComplete(croppedImage);
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <div className="fixed inset-0 z-50 bg-black flex flex-col items-center justify-center">

            <div className="relative w-full h-[70vh] bg-black">
                <Cropper
                    image={imageSrc}
                    crop={crop}
                    zoom={zoom}
                    aspect={1}
                    onCropChange={onCropChange}
                    onCropComplete={onCropCompleteHandler}
                    onZoomChange={onZoomChange}
                    cropShape="round"
                    showGrid={false}
                />
            </div>

            <div className="w-full max-w-md px-6 py-8 bg-[#0A2540] rounded-t-3xl -mt-6 z-10 border-t border-white/10">
                <p className="text-center text-slate-400 text-xs uppercase font-bold mb-4">Zoom & Position</p>
                <input
                    type="range"
                    value={zoom}
                    min={1}
                    max={3}
                    step={0.1}
                    aria-labelledby="Zoom"
                    onChange={(e) => setZoom(e.target.value)}
                    className="w-full accent-cyan-400 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer mb-8"
                />

                <div className="flex gap-4">
                    <button onClick={onCancel} className="flex-1 py-4 bg-slate-800 border border-slate-600 text-slate-300 rounded-xl font-bold uppercase tracking-widest text-sm hover:bg-slate-700 transition">
                        Cancel
                    </button>
                    <button onClick={showCroppedImage} className="flex-1 py-4 bg-gradient-to-r from-cyan-500 to-blue-500 text-white rounded-xl font-black uppercase tracking-widest text-sm shadow-[0_0_20px_rgba(6,182,212,0.4)] hover:scale-[1.02] active:scale-[0.98] transition">
                        Select Picture
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';

const MOCK_EVENTS = [
    "L2 member earned $500 commission! 🚀",
    "L5 just recruited a new agent! 👥",
    "L10 activity detected! Empire expanding... 🌍",
    "L1 member hit 'Recruiter' badge! 🎖️"
];

export default function EmpireTicker() {
    const [offset, setOffset] = useState(0);

    // Simple CSS animation via transform is smoother, 
    // but React state works for basic ticker too.
    // Let's use a pure CSS marquee approach for performance.

    return (
        <div className="bg-black/40 border-t border-white/5 py-2 overflow-hidden relative">
            <div className="animate-marquee whitespace-nowrap flex gap-8 text-xs font-mono text-emerald-400">
                {MOCK_EVENTS.map((evt, i) => (
                    <span key={i} className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                        {evt}
                    </span>
                ))}
                {/* Duplicate for seamless loop */}
                {MOCK_EVENTS.map((evt, i) => (
                    <span key={`dup-${i}`} className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                        {evt}
                    </span>
                ))}
            </div>

            <style jsx>{`
                .animate-marquee {
                    animation: marquee 15s linear infinite;
                }
                @keyframes marquee {
                    0% { transform: translateX(0); }
                    100% { transform: translateX(-50%); }
                }
            `}</style>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Users, Activity, TrendingUp, ChevronRight, Layers } from 'lucide-react';
import api from '../../services/api';
import EmpireTicker from './EmpireTicker';

export default function NetworkEmpire({ isOpen, onClose }) {
    const [stats, setStats] = useState([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        if (isOpen) fetchStats();
    }, [isOpen]);

    const fetchStats = async () => {
        setLoading(true);
        try {
            const { data } = await api.get('/referral/network-empire');
            setStats(data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    // Helper for Heatmap Color
    const getHeatmapColor = (active, total, earnings, lastActivity) => {
        // [NEW] Inactivity Check (7 Days)
        if (lastActivity) {
            const daysSince = (new Date() - new Date(lastActivity)) / (1000 * 60 * 60 * 24);
            if (daysSince > 7) return 'border-red-900/30 bg-red-950/20 shadow-none grayscale-[0.5]';
        }

        if (active === 0) return 'border-white/5 bg-slate-800/50';

        const ratio = active / (total || 1);
        // High Earnings or High Activity = Premium Colors
        if (earnings > 5000) return 'border-yellow-400/50 bg-yellow-900/20 shadow-[0_0_15px_rgba(250,204,21,0.2)]';
        if (ratio > 0.5) return 'border-emerald-400/50 bg-emerald-900/20 shadow-[0_0_15px_rgba(52,211,153,0.2)]';
        return 'border-blue-400/30 bg-blue-900/20';
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40"
                    />

                    {/* Slide Panel */}
                    <motion.div
                        initial={{ x: '100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '100%' }}
                        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                        className="fixed top-0 right-0 h-full w-full md:w-[450px] bg-[#0f172a] border-l border-white/10 z-50 shadow-2xl overflow-hidden flex flex-col"
                    >
                        {/* Header */}
                        <div className="p-6 border-b border-white/5 flex justify-between items-center bg-slate-900/50">
                            <div>
                                <h2 className="text-2xl font-black text-transparent bg-clip-text bg-gradient-to-r from-amber-400 to-yellow-600 flex items-center gap-2">
                                    <Layers className="w-6 h-6 text-yellow-500" />
                                    NETWORK EMPIRE
                                </h2>
                                <p className="text-slate-400 text-xs font-medium">10-Level Deep Analysis</p>
                            </div>
                            <button onClick={onClose} className="p-2 rounded-full hover:bg-white/10 text-white transition-colors">
                                <X className="w-6 h-6" />
                            </button>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
                            {loading ? (
                                <div className="text-center py-20 text-slate-500 animate-pulse">Scanning Network...</div>
                            ) : (
                                stats.map((level, idx) => {
                                    const activeRatio = level.total ? Math.round((level.active / level.total) * 100) : 0;
                                    const themeClass = getHeatmapColor(level.active, level.total, level.earnings, level.lastActivity);

                                    return (
                                        <motion.div
                                            key={level.level}
                                            initial={{ opacity: 0, x: 20 }}
                                            animate={{ opacity: 1, x: 0 }}
                                            transition={{ delay: idx * 0.05 }}
                                            className={`relative p-4 rounded-2xl border backdrop-blur-md flex items-center justify-between group cursor-pointer overflow-hidden ${themeClass}`}
                                        >
                                            {/* Left: Level Info */}
                                            <div className="flex items-center gap-4 z-10">
                                                <div className="w-12 h-12 rounded-full bg-black/40 flex items-center justify-center font-black text-lg text-slate-300 border border-white/5">
                                                    L{level.level}
                                                </div>
                                                <div>
                                                    <div className="flex items-center gap-2">
                                                        <span className="text-white font-bold text-lg">{level.total}</span>
                                                        <span className="text-xs text-slate-400 uppercase tracking-wider">Members</span>
                                                    </div>
                                                    <div className="flex items-center gap-1 text-xs text-emerald-400">
                                                        <Activity className="w-3 h-3" />
                                                        {level.active} Active
                                                    </div>
                                                </div>
                                            </div>

                                            {/* Right: Earnings & Meter */}
                                            <div className="flex items-center gap-4 z-10">
                                                <div className="text-right">
                                                    <p className="text-xs text-slate-400 font-medium">Earnings</p>
                                                    <p className="text-yellow-400 font-mono font-bold">${level.earnings?.toFixed(0)}</p>
                                                </div>

                                                {/* Circular Meter (Mini) */}
                                                <div className="relative w-10 h-10 flex items-center justify-center">
                                                    <svg className="w-full h-full -rotate-90" viewBox="0 0 36 36">
                                                        <path className="text-slate-700" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="4" />
                                                        <path className="text-blue-500" strokeDasharray={`${activeRatio}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="4" />
                                                    </svg>
                                                    <span className="text-[8px] absolute font-bold text-white">{activeRatio}%</span>
                                                </div>
                                            </div>

                                            {/* Deco BG */}
                                            <div className="absolute -right-4 -bottom-4 opacity-10 rotate-12">
                                                <TrendingUp className="w-24 h-24 text-white" />
                                            </div>
