import { useAuth } from '../../hooks/useAuth';

export default function ChatWidget() {
    const { user } = useAuth();
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState([
        { role: 'model', content: "Hi there! I'm your USA Affiliate support assistant. How can I help you today? 👋" }
    ]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef(null);

    // Auto-scroll
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages, isOpen]);

    // [NEW] Hide on Auth Routes for clean experience
    const pathname = typeof window !== 'undefined' ? window.location.pathname : '';
    const isAuthRoute = ['/login', '/register', '/'].includes(pathname);
    if (isAuthRoute) return null;

    const handleSend = async (e) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg = input.trim();
        setInput('');
        const newMessages = [...messages, { role: 'user', content: userMsg }];
        setMessages(newMessages);
        setLoading(true);

        try {
            // Gemini API strict rule: History cannot start with a model response unless preceded by a user prompt.
            // We strip out the initial hardcoded greeting if it's the only thing there.
            const safeHistory = messages.filter((msg, idx) => !(idx === 0 && msg.role === 'model'));

            const res = await api.post('/chat', {
                message: userMsg,
                history: safeHistory
            });

            if (res.data?.reply) {
                setMessages([...newMessages, { role: 'model', content: res.data.reply }]);
            } else {
                setMessages([...newMessages, { role: 'model', content: "System error, wait a moment." }]);
            }
        } catch (err) {
            setMessages([...newMessages, { role: 'model', content: "Our network is busy right now, please try again." }]);
        } finally {
            setLoading(false);
        }
    };

    return (
        <motion.div
            drag
            dragConstraints={{ top: -600, left: -300, right: 0, bottom: 0 }}
            dragElastic={0.1}
            whileDrag={{ scale: 1.02 }}
            className="fixed bottom-20 right-4 z-[9999] touch-none"
        >
            {/* Floating Action Button */}
            {!isOpen && (
                <button
                    onClick={() => setIsOpen(true)}
