'use client';
import { useState, useEffect } from 'react';
import { Upload, ChevronDown } from 'lucide-react';
import TapToConfirmButton from '../TapToConfirmButton';
import toast from 'react-hot-toast';

export default function RechargeForm({ settings, onSubmit, loading, activeTab }) {
    const [amount, setAmount] = useState('');
    const [paymentMode, setPaymentMode] = useState('mobile_banking');
    const [method, setMethod] = useState('bkash');
    const [trxId, setTrxId] = useState('');
    const [selectedDepositAgent, setSelectedDepositAgent] = useState(null);

    // Sync payment mode with parent tab
    useEffect(() => {
        setPaymentMode(activeTab === 'bank' ? 'bank_transfer' : 'mobile_banking');
    }, [activeTab]);

    // Auto-select first agent
    useEffect(() => {
        if (settings.deposit_agents?.length > 0) {
            setSelectedDepositAgent(settings.deposit_agents[0]);
        }
    }, [settings.deposit_agents]);

    const handleSubmit = () => {
        // Validation for TrxID
        if (!trxId || trxId.length < 8) {
            toast.error("Please enter a valid Transaction ID.");
            return;
        }

        const formData = new FormData();
        formData.append('amount', amount);
        formData.append('method', paymentMode === 'bank_transfer' ? 'Bank Transfer' : method);
        formData.append('transactionId', trxId);

        if (paymentMode === 'mobile_banking' && selectedDepositAgent) {
            formData.append('receivedByAgentId', selectedDepositAgent.agentId);
            formData.append('recipientDetails', `Sent to: ${selectedDepositAgent.number} (${selectedDepositAgent.agentName})`);
        } else {
            formData.append('recipientDetails', `Sent to: ${settings.bkash_number}`);
        }

        onSubmit(formData);
    };

    return (
        <div className="flex flex-col h-full">

            {/* Main Card Container */}
            <div className="rounded-3xl p-6 space-y-6 glass-panel">

                {/* Top Section: Payment Tiles (Colorful High Contrast) */}
                {paymentMode === 'mobile_banking' && (
                    <div className="mb-6">
                        <label className="text-[11px] font-bold text-slate-400 mb-2 block uppercase tracking-wide">Select Method</label>
                        <div className="grid grid-cols-3 gap-2">
                            {['bkash', 'nagad', 'rocket'].map(m => (
                                <button
                                    key={m}
                                    type="button"
                                    onClick={() => setMethod(m)}
                                    className={`py-2 rounded-lg text-xs font-black capitalize transition-all border ${method === m
                                        ? m === 'bkash' ? 'bg-[#e2136e] border-[#e2136e] text-white shadow-[0_0_15px_rgba(226,19,110,0.4)]' // Bkash Brand Color
                                            : m === 'nagad' ? 'bg-[#f6921e] border-[#f6921e] text-white shadow-[0_0_15px_rgba(246,146,30,0.4)]' // Nagad Brand Color
                                                : 'bg-[#8c3494] border-[#8c3494] text-white shadow-[0_0_15px_rgba(140,52,148,0.4)]' // Rocket Brand Color
                                        : 'bg-[#0f172a]/60 border-white/5 text-slate-400 hover:bg-[#1e293b]'
                                        }`}
                                >
                                    {m}
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                {/* Send Money To (Agent) */}
                <div className="mb-4">
                    <label className="text-[11px] font-bold text-slate-400 mb-1.5 block uppercase tracking-wide">Mobile Number (Send Money To)</label>
                    <div className="input-premium rounded-xl p-3 flex items-center justify-between group cursor-pointer border border-white/10 bg-[#0f172a]/80">
                        <div className="flex-1">
                            {settings.deposit_agents && settings.deposit_agents.length > 0 ? (
                                <select
                                    className="w-full bg-transparent text-sm font-bold text-white outline-none cursor-pointer appearance-none [&>option]:bg-[#0f172a]"
                                    onChange={(e) => {
                                        const agent = settings.deposit_agents.find(a => a.number === e.target.value);
                                        setSelectedDepositAgent(agent);
                                    }}
                                    value={selectedDepositAgent?.number || ''}
                                >
                                    {settings.deposit_agents.map((agent, idx) => (
                                        <option key={idx} value={agent.number} className="text-white">
                                            {agent.number} ({agent.agentName})
                                        </option>
                                    ))}
                                </select>
                            ) : (
                                <span className="text-sm font-bold text-white">{settings.bkash_number || 'Loading...'}</span>
                            )}
                            <div className="text-[10px] text-slate-500 mt-0.5">Personal • Click to Copy</div>
                        </div>
                        <ChevronDown className="w-4 h-4 text-slate-500" />
                    </div>
                </div>

                {/* Sender / TrxID */}
                <div className="mb-4">
                    <label className="text-[11px] font-bold text-slate-400 mb-1.5 block uppercase tracking-wide">TrxID (Required)</label>
                    <input
                        type="text"
                        className="w-full input-premium rounded-xl py-3 px-4 text-sm font-bold placeholder:text-slate-600 bg-[#0f172a]/80 border-white/10"
                        placeholder="Enter your 10-character TrxID"
                        value={trxId}
                        onChange={(e) => setTrxId(e.target.value)}
                    />
                </div>

                {/* Amount */}
                <div className="mb-4">
                    <label className="text-[11px] font-bold text-slate-400 mb-1.5 block uppercase tracking-wide">Amount</label>
                    <div className="relative">
                        <input
                            type="number"
                            className="w-full input-premium rounded-xl py-3 px-4 text-sm font-bold placeholder:text-slate-600 pl-8 bg-[#0f172a]/80 border-white/10"
                            placeholder="0"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                        />
                        <span className="absolute left-3 top-3 text-slate-500 font-bold">$</span>
                    </div>
                </div>

            </div>

            {/* Confirm Button */}
            <TapToConfirmButton
                onConfirm={handleSubmit}
                isLoading={loading}
                color="blue"
                initialLabel="Buy NXS 🇺🇸"
                confirmingLabel="Verifying..."
                className="w-full py-4 rounded-xl bg-gradient-to-r from-blue-600 to-red-600 text-white font-black text-lg uppercase tracking-wider shadow-[0_0_20px_rgba(59,130,246,0.5)] active:scale-95 transition-all hover:brightness-110 border border-white/20"
            />
        </div>
    );
}

'use client';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle, Receipt, X, ArrowRight, ShieldCheck, Cpu } from 'lucide-react';

export default function TransactionReceiptModal({ isOpen, onClose, data }) {
    if (!isOpen || !data) return null;

    const { amount, netAmount, fees, txId, timestamp } = data;

    return (
        <AnimatePresence>
            <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/90 backdrop-blur-sm p-4"
            >
                {/* Printing Animation Effect Container */}
                <motion.div
                    initial={{ y: -50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    className="bg-white w-full max-w-sm relative shadow-2xl overflow-hidden"
                    style={{
                        backgroundImage: 'radial-gradient(#f0f0f0 1px, transparent 1px)',
                        backgroundSize: '10px 10px'
                    }}
                >
                    {/* Jaggered Top Edge (Receipt style) */}
                    <div className="absolute top-0 left-0 right-0 h-4 bg-slate-900" style={{ clipPath: 'polygon(0% 0%, 5% 100%, 10% 0%, 15% 100%, 20% 0%, 25% 100%, 30% 0%, 35% 100%, 40% 0%, 45% 100%, 50% 0%, 55% 100%, 60% 0%, 65% 100%, 70% 0%, 75% 100%, 80% 0%, 85% 100%, 90% 0%, 95% 100%, 100% 0%)' }}></div>

                    {/* Content */}
                    <div className="pt-8 pb-6 px-6">

                        <div className="flex justify-center mb-4">
                            <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center border-4 border-emerald-50">
                                <CheckCircle size={32} className="text-emerald-600" />
                            </div>
                        </div>

                        <h2 className="text-center text-slate-800 font-black text-xl mb-1 uppercase tracking-wider">Transaction Approved</h2>
                        <p className="text-center text-slate-400 text-xs font-mono mb-6">{timestamp || new Date().toLocaleString()}</p>

                        <div className="space-y-3 mb-6">
                            <div className="flex justify-between items-center text-sm border-b border-slate-100 pb-2">
                                <span className="text-slate-500 font-medium">Requested Amount</span>
                                <span className="font-bold text-slate-800 font-mono">${amount?.toFixed(2)}</span>
                            </div>

                            {/* Itemized Fees */}
                            <div className="bg-slate-50 p-3 rounded-lg space-y-2">
                                <Row label="Exchange Fee (2%)" value={`-$${fees?.exchange?.toFixed(2)}`} isDeduct />
                                <Row label="Sys. Maintenance Tax" value={`-$${fees?.maintenance?.toFixed(2)}`} isDeduct />
                                <Row label="USA Gateway Charge" value={`-$${fees?.gateway?.toFixed(2)}`} isDeduct />
                            </div>

                            {/* Conversion Section */}
                            {fees?.conversionRate && (
                                <div className="py-2 border-t border-slate-200 mt-2">
                                    <div className="flex justify-between items-center text-xs text-slate-500 mb-1">
                                        <span>Net USD</span>
                                        <span className="font-mono text-slate-700 font-bold">${(amount - fees.totalFee).toFixed(2)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-xs text-slate-500">
                                        <span>Rate (USD→USD)</span>
                                        <span className="font-mono text-slate-700">x {fees.conversionRate}</span>
                                    </div>
                                </div>
                            )}

                            <div className="flex justify-between items-center pt-2 border-t-2 border-slate-800 border-dashed">
                                <span className="text-slate-900 font-black uppercase text-sm">Amount Credited</span>
                                <span className="font-black text-emerald-600 text-xl font-mono">
                                    {fees?.conversionRate ? '$' : '$'}{netAmount?.toFixed(2)}
                                </span>
                            </div>
                        </div>

                        {/* Footer Info */}
                        <div className="bg-slate-100 p-3 rounded text-[10px] text-slate-400 font-mono break-all text-center mb-4">
                            TX ID: {txId || 'TXN-UNKNOWN-NULL'}
                        </div>

                        <button
                            onClick={onClose}
                            className="w-full bg-slate-900 text-white font-bold py-3 rounded-lg shadow-lg hover:bg-slate-800 transition active:scale-95 flex items-center justify-center gap-2"
                        >
                            <Receipt size={16} /> Close Receipt
                        </button>
                    </div>

                    {/* Jaggered Bottom Edge */}
                    <div className="absolute bottom-0 left-0 right-0 h-4 bg-slate-900" style={{ clipPath: 'polygon(0% 100%, 5% 0%, 10% 100%, 15% 0%, 20% 100%, 25% 0%, 30% 100%, 35% 0%, 40% 100%, 45% 0%, 50% 100%, 55% 0%, 60% 100%, 65% 0%, 70% 100%, 75% 0%, 80% 100%, 85% 0%, 90% 100%, 95% 0%, 100% 100%)' }}></div>
                </motion.div>
            </motion.div>
        </AnimatePresence>
    );
}

function Row({ label, value, isDeduct }) {
    return (
        <div className="flex justify-between items-center text-xs">
            <span className="text-slate-500">{label}</span>
            <span className={`font-mono font-medium ${isDeduct ? 'text-red-500' : 'text-slate-700'}`}>{value}</span>
        </div>
    );
}

import React, { useState } from 'react';
import { ArrowRight, Loader2, Wallet } from 'lucide-react';
import api from '../../services/api';
import { useCurrency } from '../../context/CurrencyContext';
import TransactionReceiptModal from './TransactionReceiptModal';
import toast from 'react-hot-toast';

export default function WalletSwap({ user, onSuccess }) {
    const { formatMoney } = useCurrency();
    const [loading, setLoading] = useState(false);
    const [amount, setAmount] = useState('');
    const [receipt, setReceipt] = useState(null);

    const handleSwap = async () => {
        if (!amount || parseFloat(amount) < 5) return;
        setLoading(true);
        try {
            // [v6.5] Convert USD input to NXS for the backend (1 USD = 50 NXS)
            const nxsAmount = parseFloat(amount) * 50;
            const response = await api.post('/wallet/transfer/main', { amount: nxsAmount });

            onSuccess(); // Refresh user data
            setAmount('');

            if (response.data.receipt) {
                setReceipt(response.data.receipt);
            } else {
                toast.success('Transfer Successful');
            }

        } catch (err) {
            console.error(err);
            toast.error(err.response?.data?.message || 'Transfer Failed');
        } finally {
            setLoading(false);
        }
    };

    const incomeBalance = user?.wallet?.income || user?.income_balance || 0;

    return (
        <div className="w-full px-6 mb-3">
            <div className="bg-gradient-to-br from-slate-900 to-slate-800 rounded-xl p-3 border border-white/10 shadow-xl backdrop-blur-md">
                <div className="flex items-center justify-between mb-3">
                    <h3 className="text-sm font-bold text-white flex items-center gap-2">
                        <Wallet className="w-4 h-4 text-cyan-400" /> Fund Transfer
                    </h3>
                    <span className="text-[10px] font-bold text-cyan-400 uppercase bg-cyan-900/30 px-2 py-1 rounded">
                        Income → Main
                    </span>
                </div>

                <div className="flex items-center gap-2 mb-3 relative">
                    {/* From */}
                    <div className="flex-1 p-2 rounded-xl border border-green-500/30 bg-green-500/5 transition-all">
                        <div className="text-[9px] text-slate-400 uppercase font-bold flex items-center gap-1 mb-0.5">
                            From: Income Wallet
                        </div>
                        <div className="text-xs font-bold text-white leading-none">
                            ${(Number(incomeBalance) * 0.02).toFixed(2)} USD
                        </div>
                    </div>

                    {/* Arrow */}
                    <div className="bg-slate-700 rounded-full p-1 border border-slate-600 z-10 flex-shrink-0">
                        <ArrowRight className="w-3 h-3 text-slate-300" />
                    </div>

                    {/* To */}
                    <div className="flex-1 p-2 rounded-xl border border-yellow-500/30 bg-yellow-500/5 transition-all text-right">
                        <div className="text-[9px] text-slate-400 uppercase font-bold flex items-center justify-end gap-1 mb-0.5">
                            To: Main Wallet
                        </div>
                        <div className="text-xs font-bold text-white leading-none mt-1 uppercase text-slate-500">
                            Ready
                        </div>
                    </div>
                </div>

                <div className="flex gap-2">
                    <div className="relative flex-1">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 font-bold font-mono text-[10px] tracking-widest mt-[0.5px]">
                            USD Amount:
                        </span>
                        <input
                            type="number"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                            placeholder="Min: 5.00"
                            className={`w-full h-full bg-slate-950/50 border ${amount && Number(amount) < 5 ? 'border-red-500/50' : 'border-slate-700'} rounded-xl pl-[80px] pr-3 py-2 text-xs text-white placeholder-slate-500 focus:outline-none focus:border-cyan-500 transition-colors font-mono`}
                        />
                    </div>
                    {/* Action Button */}
                    <button
                        onClick={handleSwap}
                        disabled={loading || !amount || Number(amount) < 5}
                        className="w-1/3 py-2 rounded-xl bg-gradient-to-r from-amber-200 to-yellow-400 text-black font-bold text-xs shadow-lg hover:shadow-xl hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
                    >
                        {loading ? 'Wait...' : 'Transfer'}
                    </button>
                </div>

                {/* Status/Fee Warning */}
                <div className="mt-3 text-center space-y-1">
                    {amount && Number(amount) < 5 ? (
                        <p className="text-[10px] text-red-400 font-bold animate-pulse">
                            ❌ Min. Transfer: $5.00 USD
                        </p>
                    ) : (
                        <p className="text-[10px] text-amber-500/80 font-medium tracking-wide">
                            ⚠️ A 3% Exchange Fee applies to Fund Transfers.
                        </p>
                    )}
                </div>
            </div>

            <TransactionReceiptModal
                isOpen={!!receipt}
                onClose={() => setReceipt(null)}
                data={receipt}
            />
        </div>
    );
}

'use client';
import { useState } from 'react';
import { ChevronRight, ArrowRight } from 'lucide-react';
import { useCurrency } from '../../context/CurrencyContext';

// Minimalist Chips for Methods
const MethodChip = ({ id, selected, onClick, label }) => (
    <button
        type="button"
        onClick={onClick}
        className={`
            px-5 py-2.5 rounded-full text-xs font-medium tracking-wide transition-all duration-300 border
            ${selected
                ? 'bg-white text-black border-white shadow-lg shadow-white/10 scale-105'
                : 'bg-zinc-900 text-zinc-500 border-zinc-800 hover:border-zinc-700 hover:text-zinc-300'
            }
        `}
    >
        {label}
    </button>
);

export default function WithdrawForm({ balance, onSubmit, loading }) {
    const { formatMoney } = useCurrency(); // Helper if needed
    const [form, setForm] = useState({
        amount: '',
        method: 'Bkash', // Default
        tier: 'standard',
        accountDetails: '',
        deliveryTime: '24h' // Default
    });

    // Determine Receive Amount (Approx conversion logic if needed, or just 1:1 for USD)
    // Assuming Input is USD for this "Elegant" view? Or USD?
    // User asked: "Display USD balance... Input amount... Receive Amount (USD)..."
    // Implies Input is in USD.
    // Input is now directly in USD as per user request

    // Main Wallet Balance Only
    // Assuming 'balance' prop is the Main Wallet Balance in USD.
    // We can display it as USD for the "Elegant" look if needed, or USD.

    const receiveAmount = form.amount ? parseFloat(form.amount).toLocaleString() : '0';

    const handleSubmit = (e) => {
        e.preventDefault();

        const idempotencyKey = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

        // Input is already in USD, convert to NXS for backend
        const usdValue = parseFloat(form.amount);
        const nxsAmount = usdValue * 50;

        onSubmit({
            ...form,
            amount: nxsAmount,
            idempotencyKey
        });
    };

    return (
        <form onSubmit={handleSubmit} className="w-full max-w-sm mx-auto flex flex-col items-center mt-8 space-y-12 animate-in fade-in duration-700">

            {/* 1. Method Selection (Pills) */}
            <div className="flex flex-wrap justify-center gap-3">
                {['Bkash', 'Nagad', 'Rocket', 'Bank'].map(m => (
                    <MethodChip
                        key={m}
                        id={m}
                        label={m}
                        selected={form.method === m}
                        onClick={() => setForm({ ...form, method: m })}
                    />
                ))}
            </div>

            {/* 2. Delivery Time Selection (New) */}
            <div className="flex justify-center gap-4 mt-6">
                {['1h', '24h', '48h', '72h'].map((time) => (
                    <button
                        key={time}
                        type="button"
                        onClick={() => setForm({ ...form, deliveryTime: time })}
                        className={`px-4 py-1.5 rounded-lg text-[10px] font-bold tracking-widest uppercase transition-all
                            ${form.deliveryTime === time
                                ? 'bg-zinc-800 text-white border border-zinc-600'
                                : 'text-zinc-600 border border-transparent hover:text-zinc-400'
                            }
                        `}
                    >
                        {time}
                    </button>
                ))}
            </div>

            {/* 2. Minimal Input */}
            <div className="w-full relative group text-center">
                <div className="relative inline-block">
                    <span className="absolute left-0 top-1/2 -translate-x-full -translate-y-1/2 pr-4 text-3xl font-thin text-zinc-600">$</span>
                    <input
                        type="number"
                        value={form.amount}
                        onChange={e => setForm({ ...form, amount: e.target.value })}
                        placeholder="0.00"
                        className="w-48 bg-transparent text-5xl font-thin text-white text-center placeholder-zinc-800 outline-none border-b border-zinc-800 focus:border-zinc-500 transition-colors pb-2"
                        autoFocus
                    />
                </div>

                {/* Receive Preview (No Fee on Withdraw) */}
                <div className="mt-6 flex flex-col items-center gap-1">
                    <div className="text-sm font-medium text-zinc-500 flex items-center justify-center gap-2">
                        <span>Receive approx</span>
                        <span className="text-emerald-400/80">$ {receiveAmount}</span>
                    </div>
                    {/* Fee Label */}
                    <span className="text-[10px] text-zinc-700 font-mono tracking-wide">
                        Fee: 0% (Standard) • Deducted from Main Wallet
                    </span>
                </div>
            </div>

            {/* 3. Account Input (Ghost) */}
            <div className="w-full">
                <input
                    type="text"
                    value={form.accountDetails}
                    onChange={e => setForm({ ...form, accountDetails: e.target.value })}
                    placeholder="Enter Account Number"
                    className="w-full bg-[#0F0F0F] text-center py-4 rounded-xl text-zinc-400 placeholder-zinc-700 outline-none border border-transparent focus:border-zinc-800 focus:bg-[#141414] transition-all text-sm tracking-wide"
                />
            </div>

            {/* 4. Action Button */}
            <button
                type="submit"
                disabled={loading || !form.amount || !form.accountDetails}
                className="group relative px-8 py-4 bg-zinc-100 text-black rounded-full font-bold text-sm tracking-widest uppercase hover:px-10 hover:shadow-[0_0_40px_-10px_rgba(255,255,255,0.3)] transition-all disabled:opacity-20 disabled:hover:px-8 disabled:cursor-not-allowed"
            >
                {loading ? 'Processing...' : 'Sell NXS'}
            </button>

        </form>
    );
}

'use client';
import { useState } from 'react';
import { Zap, Clock, ShieldCheck } from 'lucide-react';

export default function WithdrawalTierUI({ selectedTier, onSelect }) {

    const tiers = [
        {
            id: 'express',
            name: 'Express',
            fee: '5%',
            time: 'Instant - 1 Hour',
            icon: <Zap className="w-5 h-5 text-yellow-400" />,
            color: 'border-yellow-400/50 bg-yellow-400/10',
            desc: 'Priority Processing'
        },
        {
            id: 'standard',
            name: 'Standard',
            fee: '2%',
            time: '24 - 48 Hours',
            icon: <Clock className="w-5 h-5 text-slate-400" />,
            color: 'border-white/10 bg-white/5',
            desc: 'Regular Processing'
        }
    ];

    return (
        <div className="grid grid-cols-2 gap-3 mb-6">
            {tiers.map((tier) => (
                <div
                    key={tier.id}
                    onClick={() => onSelect(tier.id)}
                    className={`
                        relative p-3 rounded-xl border cursor-pointer transition-all duration-300
                        ${selectedTier === tier.id ? tier.color + ' shadow-lg scale-[1.02]' : 'border-white/5 bg-slate-900/50 hover:bg-white/5'}
                    `}
                >
                    {selectedTier === tier.id && (
                        <div className="absolute top-2 right-2">
                            <ShieldCheck className="w-4 h-4 text-emerald-400" />
                        </div>
                    )}

                    <div className="mb-2">{tier.icon}</div>
                    <h3 className="font-bold text-sm text-white">{tier.name}</h3>
                    <p className="text-[10px] text-slate-400 mb-2">{tier.desc}</p>

                    <div className="flex items-center justify-between text-[10px] font-mono border-t border-white/10 pt-2">
                        <span className="text-slate-500">Fee: {tier.fee}</span>
                        <span className="text-slate-300">{tier.time}</span>
                    </div>
                </div>
            ))}
        </div>
    );
}

