        if (typeof window !== 'undefined') {
            audioRef.current = new Audio('/sounds/notification.mp3');
            audioRef.current.volume = 0.8;

            if ('Notification' in window) {
                setPermission(Notification.permission);
            }
        }
    }, []);

    // Request native browser permission
    const requestPermission = useCallback(async () => {
        if (!('Notification' in window)) return false;
        if (Notification.permission === 'granted') return true;

        try {
            const result = await Notification.requestPermission();
            setPermission(result);
            return result === 'granted';
        } catch (error) {
            console.error('Error requesting notification permission:', error);
            return false;
        }
    }, []);

    const lastPlayTime = useRef(0);
    const playSound = useCallback((soundPath = null) => {
        const now = Date.now();
        if (now - lastPlayTime.current < 500) return; // Don't play too frequently
        lastPlayTime.current = now;

        try {
            const audioToPlay = soundPath ? new Audio(soundPath) : audioRef.current;
            if (audioToPlay) {
                audioToPlay.currentTime = 0;
                audioToPlay.volume = 0.8;
                const playPromise = audioToPlay.play();
                if (playPromise !== undefined) {
                    playPromise.catch(error => {
                        console.log('Audio autoplay blocked by browser policy.');
                    });
                }
            }
        } catch (e) { }
    }, []);

    // Show native push notification
    const showPush = useCallback((title, options = {}) => {
        if (!('Notification' in window) || Notification.permission !== 'granted') {
            return;
        }

        try {
            const notification = new Notification(title, {
                icon: '/icon.png', // Add your app icon path if you have one
                badge: '/icon.png',
                vibrate: [200, 100, 200],
                ...options
            });

            // Optional: Close after 5 seconds
            setTimeout(() => notification.close(), 5000);

            // Optional: Focus window on click
            notification.onclick = function () {
                window.focus();
                if (this.data && this.data.url) {
                    window.location.href = this.data.url;
                }
                this.close();
            };
        } catch (error) {
            console.error("Push notification failed", error);
        }
    }, []);

    // Utility: Trigger both (the best practice hybrid approach)
    const notify = useCallback((title, body = '', url = null, soundPath = null) => {
        playSound(soundPath);
        showPush(title, { body, ...(url && { data: { url } }) });
    }, [playSound, showPush]);

    return {
        permission,
        requestPermission,
        playSound,
        showPush,
        notify
    };
}

import { useEffect, useState } from 'react';
import getSocket from '../services/socket';

export const useSocket = (namespace = '/system') => {
    const [socketInstance, setSocketInstance] = useState(null);

    useEffect(() => {
        // Get the singleton for this namespace
        const socket = getSocket(namespace);
        setSocketInstance(socket);

        // We DO NOT disconnect here. The service manages persistence.
        // This prevents the "Connect/Disconnect" loop on every re-render.

        // Optional: If we wanted to clean up UNUSED namespaces, we'd need ref counting in the service.
        // For now, keeping a few sockets open (system, game) is fine and stable.
    }, [namespace]);

    return socketInstance;
};

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useNotification } from '../context/NotificationContext';
import taskService from '../services/taskService';

export function useTaskWorker(adId) {
    const { showSuccess, showError } = useNotification();
    const router = useRouter();

    const [adData, setAdData] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (adId) fetchAdData();
    }, [adId]);

    const fetchAdData = async () => {
        try {
            const data = await taskService.getTaskStatus();

            if (data.canWork === false) {
                showError(data.message || 'Please upgrade your plan.');
                router.push('/tasks');
                return;
            }

            const ads = data.taskAds || [];
            const found = ads.find(a => a.id == adId);

            if (found) {
                setAdData({ ...found, duration: found.duration || 10 });
            } else {
                showError('Task not found');
                router.push('/tasks');
            }
        } catch (err) {
            console.error(err);
            showError('Failed to load task');
        } finally {
            setLoading(false);
        }
    };

    const handleTaskComplete = async (task) => {
        try {
            const data = await taskService.submitTask(task.id);
            // Success message is handled by Player or here.
            // Player shows "Reward Claimed". 
            // We can show a toast here too if needed, but Player UI is primary.
            return data;
        } catch (err) {
            showError(err.response?.data?.message || 'Verification failed');
            throw err; // Propatage error to Player so it stops "Claiming..."
        }
    };

    return {
        adData,
        loading,
        handleTaskComplete,
        closeTask: () => router.push('/tasks')
    };
}

import { useState, useCallback } from 'react';
import api from '../services/api';

export const useWalletActions = () => {
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    // Fetch Payment Settings
    const usePaymentSettings = () => {
        const [settings, setSettings] = useState({ bkash_number: '', bank_details: '', deposit_agents: [] });
        const [loadingSettings, setLoadingSettings] = useState(true);

        const fetchSettings = useCallback(async () => {
            try {
                const res = await api.get('/transactions/settings/payment');
                setSettings(res.data);
            } catch (err) {
                console.error('Failed to fetch settings');
            } finally {
                setLoadingSettings(false);
            }
        }, []);

        return { settings, loadingSettings, fetchSettings };
    };

    // Submit Recharge
    const submitRecharge = async (formData) => {
        setLoading(true);
        setError('');
        setSuccess('');
        try {
            await api.post('/transaction/add-money', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            setSuccess('Request submitted! 🚀');
            return true;
        } catch (err) {
            setError(err.response?.data?.message || 'Error submitting request.');
            return false;
        } finally {
            setLoading(false);
        }
    };

    // Submit Withdrawal
    const submitWithdrawal = async (data) => {
        setLoading(true);
        setError('');
        setSuccess('');
        try {
            // Map frontend form to backend expectation
            const payload = {
                amount: data.amount,
                method: data.method,
                details: data.accountDetails,
                tier: data.tier,
                idempotencyKey: data.idempotencyKey
            };

            await api.post('/wallet/withdraw', payload);
            setSuccess('Withdrawal request submitted successfully!');
            return true;
        } catch (err) {
            setError(err.response?.data?.message || err.message || 'Withdrawal failed');
            return false;
        } finally {
            setLoading(false);
        }
    };

    return {
        loading,
        error,
        success,
        submitRecharge,
        submitWithdrawal,
        usePaymentSettings,
        setError,
        setSuccess
    };
};

